	private Rect ConvertRect(OVRPlugin.Rectf openXrRect)
	{
		Vector2 size = openXrRect.Size.FromSizef();
		Vector2 position = openXrRect.Pos.FromFlippedXVector2f();
		position.x -= size.x;
		return new Rect(position, size);
	}

