[HelpURL("https://developer.oculus.com/reference/unity/latest/class_o_v_r_debug_head_controller")]
public class OVRDebugHeadController : MonoBehaviour
{
	[SerializeField]
	public bool AllowPitchLook;

	[SerializeField]
	public bool AllowYawLook = true;

	[SerializeField]
	public bool InvertPitch;

	[SerializeField]
	public float GamePad_PitchDegreesPerSec = 90f;

	[SerializeField]
	public float GamePad_YawDegreesPerSec = 90f;

	[SerializeField]
	public bool AllowMovement;

	[SerializeField]
	public float ForwardSpeed = 2f;

	[SerializeField]
	public float StrafeSpeed = 2f;

	protected OVRCameraRig CameraRig;

	private void Awake()
	{
		OVRCameraRig[] componentsInChildren = base.gameObject.GetComponentsInChildren<OVRCameraRig>();
		if (componentsInChildren.Length == 0)
		{
			UnityEngine.Debug.LogWarning("OVRCamParent: No OVRCameraRig attached.");
		}
		else if (componentsInChildren.Length > 1)
		{
			UnityEngine.Debug.LogWarning("OVRCamParent: More then 1 OVRCameraRig attached.");
		}
		else
		{
			CameraRig = componentsInChildren[0];
		}
	}

	private void Start()
	{
	}

	private void Update()
	{
		if (AllowMovement)
		{
			float y = OVRInput.Get(OVRInput.RawAxis2D.LThumbstick).y;
			float x = OVRInput.Get(OVRInput.RawAxis2D.LThumbstick).x;
			Vector3 vector = CameraRig.centerEyeAnchor.rotation * Vector3.forward * y * Time.deltaTime * ForwardSpeed;
			Vector3 vector2 = CameraRig.centerEyeAnchor.rotation * Vector3.right * x * Time.deltaTime * StrafeSpeed;
			base.transform.position += vector + vector2;
		}
		bool flag = false;
		XRDisplaySubsystem currentDisplaySubsystem = OVRManager.GetCurrentDisplaySubsystem();
		if (currentDisplaySubsystem != null)
		{
			flag = currentDisplaySubsystem.running;
		}
		if (flag || (!AllowYawLook && !AllowPitchLook))
		{
			return;
		}
		Quaternion quaternion = base.transform.rotation;
		if (AllowYawLook)
		{
			quaternion = Quaternion.AngleAxis(OVRInput.Get(OVRInput.RawAxis2D.RThumbstick).x * Time.deltaTime * GamePad_YawDegreesPerSec, Vector3.up) * quaternion;
		}
		if (AllowPitchLook)
		{
			float num = OVRInput.Get(OVRInput.RawAxis2D.RThumbstick).y;
			if (Mathf.Abs(num) > 0.0001f)
			{
				if (InvertPitch)
				{
					num *= -1f;
				}
				Quaternion quaternion2 = Quaternion.AngleAxis(num * Time.deltaTime * GamePad_PitchDegreesPerSec, Vector3.left);
				quaternion *= quaternion2;
			}
		}
		base.transform.rotation = quaternion;
	}
}
[HelpURL("https://developer.oculus.com/reference/unity/v67/class_o_v_r_display")]
public class OVRDisplay
{
	public struct EyeFov
	{
		public float UpFov;

		public float DownFov;

		public float LeftFov;

		public float RightFov;
	}

	public struct EyeRenderDesc
	{
		public Vector2 resolution;

		public Vector2 fov;

		public EyeFov fullFov;
	}

	public struct LatencyData
	{
		public float render;

		public float timeWarp;

		public float postPresent;

		public float renderError;

		public float timeWarpError;
	}

	protected bool needsConfigureTexture;

	protected EyeRenderDesc[] eyeDescs = new EyeRenderDesc[2];

	protected bool recenterRequested;

	protected int recenterRequestedFrameCount = int.MaxValue;

	protected int localTrackingSpaceRecenterCount;

	[Obsolete("Deprecated. Acceleration is not supported in OpenXR", false)]
	public Vector3 acceleration
	{
		get
		{
			if (!OVRManager.isHmdPresent)
			{
				return Vector3.zero;
			}
			Vector3 retVec = Vector3.zero;
			if (OVRNodeStateProperties.GetNodeStatePropertyVector3(XRNode.Head, NodeStatePropertyType.Acceleration, OVRPlugin.Node.Head, OVRPlugin.Step.Render, out retVec))
			{
				return retVec;
			}
			return Vector3.zero;
		}
	}

	[Obsolete("Deprecated. Acceleration is not supported in OpenXR", false)]
	public Vector3 angularAcceleration
	{
		get
		{
			if (!OVRManager.isHmdPresent)
			{
				return Vector3.zero;
			}
			Vector3 retVec = Vector3.zero;
			if (OVRNodeStateProperties.GetNodeStatePropertyVector3(XRNode.Head, NodeStatePropertyType.AngularAcceleration, OVRPlugin.Node.Head, OVRPlugin.Step.Render, out retVec))
			{
				return retVec;
			}
			return Vector3.zero;
		}
	}

	public Vector3 velocity
	{
		get
		{
			if (!OVRManager.isHmdPresent)
			{
				return Vector3.zero;
			}
			Vector3 retVec = Vector3.zero;
			if (OVRNodeStateProperties.GetNodeStatePropertyVector3(XRNode.Head, NodeStatePropertyType.Velocity, OVRPlugin.Node.Head, OVRPlugin.Step.Render, out retVec))
			{
				return retVec;
			}
			return Vector3.zero;
		}
	}

	public Vector3 angularVelocity
	{
		get
		{
			if (!OVRManager.isHmdPresent)
			{
				return Vector3.zero;
			}
			Vector3 retVec = Vector3.zero;
			if (OVRNodeStateProperties.GetNodeStatePropertyVector3(XRNode.Head, NodeStatePropertyType.AngularVelocity, OVRPlugin.Node.Head, OVRPlugin.Step.Render, out retVec))
			{
				return retVec;
			}
			return Vector3.zero;
		}
	}

	public LatencyData latency
	{
		get
		{
			if (!OVRManager.isHmdPresent)
			{
				return default(LatencyData);
			}
			string input = OVRPlugin.latency;
			Regex regex = new Regex("Render: ([0-9]+[.][0-9]+)ms, TimeWarp: ([0-9]+[.][0-9]+)ms, PostPresent: ([0-9]+[.][0-9]+)ms", RegexOptions.None);
			LatencyData result = default(LatencyData);
			Match match = regex.Match(input);
			if (match.Success)
			{
				result.render = float.Parse(match.Groups[1].Value);
				result.timeWarp = float.Parse(match.Groups[2].Value);
				result.postPresent = float.Parse(match.Groups[3].Value);
			}
			return result;
		}
	}

	public float appFramerate
	{
		get
		{
			if (!OVRManager.isHmdPresent)
			{
				return 0f;
			}
			return OVRPlugin.GetAppFramerate();
		}
	}

	public float[] displayFrequenciesAvailable => OVRPlugin.systemDisplayFrequenciesAvailable;

	public float displayFrequency
	{
		get
		{
			return OVRPlugin.systemDisplayFrequency;
		}
		set
		{
			OVRPlugin.systemDisplayFrequency = value;
		}
	}

	public event Action RecenteredPose;

	public OVRDisplay()
	{
		UpdateTextures();
	}

	public void Update()
	{
		UpdateTextures();
		if (recenterRequested && Time.frameCount > recenterRequestedFrameCount)
		{
			UnityEngine.Debug.Log("Recenter event detected");
			if (this.RecenteredPose != null)
			{
				this.RecenteredPose();
			}
			recenterRequested = false;
			recenterRequestedFrameCount = int.MaxValue;
		}
		if (OVRPlugin.GetSystemHeadsetType() < OVRPlugin.SystemHeadset.Oculus_Quest || OVRPlugin.GetSystemHeadsetType() >= OVRPlugin.SystemHeadset.Rift_DK1)
		{
			return;
		}
		int num = OVRPlugin.GetLocalTrackingSpaceRecenterCount();
		if (localTrackingSpaceRecenterCount != num)
		{
			UnityEngine.Debug.Log("Recenter event detected");
			if (this.RecenteredPose != null)
			{
				this.RecenteredPose();
			}
			localTrackingSpaceRecenterCount = num;
		}
	}

	public void RecenterPose()
	{
		OVRManager.GetCurrentInputSubsystem()?.TryRecenter();
		recenterRequested = true;
		recenterRequestedFrameCount = Time.frameCount;
		OVRMixedReality.RecenterPose();
	}

	public EyeRenderDesc GetEyeRenderDesc(XRNode eye)
	{
		return eyeDescs[(int)eye];
	}

	protected void UpdateTextures()
	{
		ConfigureEyeDesc(XRNode.LeftEye);
		ConfigureEyeDesc(XRNode.RightEye);
	}

	protected void ConfigureEyeDesc(XRNode eye)
	{
		if (OVRManager.isHmdPresent)
		{
			int eyeTextureWidth = XRSettings.eyeTextureWidth;
			int eyeTextureHeight = XRSettings.eyeTextureHeight;
			eyeDescs[(int)eye] = default(EyeRenderDesc);
			eyeDescs[(int)eye].resolution = new Vector2(eyeTextureWidth, eyeTextureHeight);
			if (OVRPlugin.GetNodeFrustum2((OVRPlugin.Node)eye, out var frustum))
			{
				eyeDescs[(int)eye].fullFov.LeftFov = 57.29578f * Mathf.Atan(frustum.Fov.LeftTan);
				eyeDescs[(int)eye].fullFov.RightFov = 57.29578f * Mathf.Atan(frustum.Fov.RightTan);
				eyeDescs[(int)eye].fullFov.UpFov = 57.29578f * Mathf.Atan(frustum.Fov.UpTan);
				eyeDescs[(int)eye].fullFov.DownFov = 57.29578f * Mathf.Atan(frustum.Fov.DownTan);
			}
			else
			{
				OVRPlugin.Frustumf eyeFrustum = OVRPlugin.GetEyeFrustum((OVRPlugin.Eye)eye);
				eyeDescs[(int)eye].fullFov.LeftFov = 57.29578f * eyeFrustum.fovX * 0.5f;
				eyeDescs[(int)eye].fullFov.RightFov = 57.29578f * eyeFrustum.fovX * 0.5f;
				eyeDescs[(int)eye].fullFov.UpFov = 57.29578f * eyeFrustum.fovY * 0.5f;
				eyeDescs[(int)eye].fullFov.DownFov = 57.29578f * eyeFrustum.fovY * 0.5f;
			}
			float num = Mathf.Max(eyeDescs[(int)eye].fullFov.LeftFov, eyeDescs[(int)eye].fullFov.RightFov);
			float num2 = Mathf.Max(eyeDescs[(int)eye].fullFov.UpFov, eyeDescs[(int)eye].fullFov.DownFov);
			eyeDescs[(int)eye].fov.x = num * 2f;
			eyeDescs[(int)eye].fov.y = num2 * 2f;
			if (!OVRPlugin.AsymmetricFovEnabled)
			{
				eyeDescs[(int)eye].fullFov.LeftFov = num;
				eyeDescs[(int)eye].fullFov.RightFov = num;
				eyeDescs[(int)eye].fullFov.UpFov = num2;
				eyeDescs[(int)eye].fullFov.DownFov = num2;
			}
		}
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/move-face-tracking/")]
[Feature(Feature.FaceTracking)]
public class OVRFaceExpressions : MonoBehaviour, IReadOnlyCollection<float>, IEnumerable<float>, IEnumerable, OVRFaceExpressions.WeightProvider
{
	public interface WeightProvider
	{
		float GetWeight(FaceExpression expression);
	}

	public enum FaceRegionConfidence
	{
		Lower,
		Upper,
		Max
	}

	public enum FaceTrackingDataSource
	{
		Visual,
		Audio,
		[InspectorName(null)]
		Count
	}

	public enum FaceExpression
	{
		[InspectorName("None")]
		Invalid = -1,
		BrowLowererL,
		BrowLowererR,
		CheekPuffL,
		CheekPuffR,
		CheekRaiserL,
		CheekRaiserR,
		CheekSuckL,
		CheekSuckR,
		ChinRaiserB,
		ChinRaiserT,
		DimplerL,
		DimplerR,
		EyesClosedL,
		EyesClosedR,
		EyesLookDownL,
		EyesLookDownR,
		EyesLookLeftL,
		EyesLookLeftR,
		EyesLookRightL,
		EyesLookRightR,
		EyesLookUpL,
		EyesLookUpR,
		InnerBrowRaiserL,
		InnerBrowRaiserR,
		JawDrop,
		JawSidewaysLeft,
		JawSidewaysRight,
		JawThrust,
		LidTightenerL,
		LidTightenerR,
		LipCornerDepressorL,
		LipCornerDepressorR,
		LipCornerPullerL,
		LipCornerPullerR,
		LipFunnelerLB,
		LipFunnelerLT,
		LipFunnelerRB,
		LipFunnelerRT,
		LipPressorL,
		LipPressorR,
		LipPuckerL,
		LipPuckerR,
		LipStretcherL,
		LipStretcherR,
		LipSuckLB,
		LipSuckLT,
		LipSuckRB,
		LipSuckRT,
		LipTightenerL,
		LipTightenerR,
		LipsToward,
		LowerLipDepressorL,
		LowerLipDepressorR,
		MouthLeft,
		MouthRight,
		NoseWrinklerL,
		NoseWrinklerR,
		OuterBrowRaiserL,
		OuterBrowRaiserR,
		UpperLidRaiserL,
		UpperLidRaiserR,
		UpperLipRaiserL,
		UpperLipRaiserR,
		TongueTipInterdental,
		TongueTipAlveolar,
		TongueFrontDorsalPalate,
		TongueMidDorsalPalate,
		TongueBackDorsalVelar,
		TongueOut,
		TongueRetreat,
		[InspectorName(null)]
		Max
	}

	public struct FaceExpressionsEnumerator : IEnumerator<float>, IEnumerator, IDisposable
	{
		private float[] _faceExpressions;

		private int _index;

		private int _count;

		public float Current => _faceExpressions[_index];

		object IEnumerator.Current => Current;

		internal FaceExpressionsEnumerator(float[] array)
		{
			_faceExpressions = array;
			_index = -1;
			float[] faceExpressions = _faceExpressions;
			_count = ((faceExpressions != null) ? faceExpressions.Length : 0);
		}

		public bool MoveNext()
		{
			return ++_index < _count;
		}

		public void Reset()
		{
			_index = -1;
		}

		public void Dispose()
		{
		}
	}

	public enum FaceViseme
	{
		[InspectorName("None")]
		Invalid = -1,
		SIL,
		PP,
		FF,
		TH,
		DD,
		KK,
		CH,
		SS,
		NN,
		RR,
		AA,
		E,
		IH,
		OH,
		OU,
		[InspectorName(null)]
		Count
	}

	private OVRPlugin.FaceState _currentFaceState;

	private OVRPlugin.FaceVisemesState _currentFaceVisemesState;

	private const OVRPermissionsRequester.Permission FaceTrackingPermission = OVRPermissionsRequester.Permission.FaceTracking;

	private const OVRPermissionsRequester.Permission RecordAudioPermission = OVRPermissionsRequester.Permission.RecordAudio;

	private Action<string> _onPermissionGranted;

	private static int _trackingInstanceCount;

	public bool FaceTrackingEnabled => OVRPlugin.faceTracking2Enabled;

	public bool ValidExpressions { get; private set; }

	public bool EyeFollowingBlendshapesValid { get; private set; }

	public bool AreVisemesValid { get; private set; }

	public float this[FaceExpression expression]
	{
		get
		{
			CheckValidity();
			if (expression < FaceExpression.BrowLowererL || expression >= FaceExpression.Max)
			{
				throw new ArgumentOutOfRangeException("expression", expression, $"Value must be between 0 to {70}");
			}
			return _currentFaceState.ExpressionWeights[(int)expression];
		}
	}

	public int Count
	{
		get
		{
			float[] expressionWeights = _currentFaceState.ExpressionWeights;
			if (expressionWeights == null)
			{
				return 0;
			}
			return expressionWeights.Length;
		}
	}

	private void Awake()
	{
		_onPermissionGranted = OnPermissionGranted;
	}

	private void OnEnable()
	{
		_trackingInstanceCount++;
		if (!StartFaceTracking())
		{
			base.enabled = false;
		}
	}

	private void OnPermissionGranted(string permissionId)
	{
		if (permissionId == OVRPermissionsRequester.GetPermissionId(OVRPermissionsRequester.Permission.FaceTracking) || permissionId == OVRPermissionsRequester.GetPermissionId(OVRPermissionsRequester.Permission.RecordAudio))
		{
			OVRPermissionsRequester.PermissionGranted -= _onPermissionGranted;
			base.enabled = true;
		}
	}

	private OVRPlugin.FaceTrackingDataSource[] GetRequestedFaceTrackingDataSources()
	{
		OVRRuntimeSettings runtimeSettings = OVRRuntimeSettings.GetRuntimeSettings();
		if (runtimeSettings.RequestsAudioFaceTracking && runtimeSettings.RequestsVisualFaceTracking)
		{
			return new OVRPlugin.FaceTrackingDataSource[2]
			{
				OVRPlugin.FaceTrackingDataSource.Visual,
				OVRPlugin.FaceTrackingDataSource.Audio
			};
		}
		if (runtimeSettings.RequestsVisualFaceTracking)
		{
			return new OVRPlugin.FaceTrackingDataSource[1];
		}
		if (runtimeSettings.RequestsAudioFaceTracking)
		{
			return new OVRPlugin.FaceTrackingDataSource[1] { OVRPlugin.FaceTrackingDataSource.Audio };
		}
		return new OVRPlugin.FaceTrackingDataSource[0];
	}

	private bool StartFaceTracking()
	{
		if (!OVRPermissionsRequester.IsPermissionGranted(OVRPermissionsRequester.Permission.FaceTracking) && !OVRPermissionsRequester.IsPermissionGranted(OVRPermissionsRequester.Permission.RecordAudio))
		{
			OVRPermissionsRequester.PermissionGranted -= _onPermissionGranted;
			OVRPermissionsRequester.PermissionGranted += _onPermissionGranted;
			return false;
		}
		if (!OVRPlugin.StartFaceTracking2(GetRequestedFaceTrackingDataSources()))
		{
			UnityEngine.Debug.LogWarning("[OVRFaceExpressions] Failed to start face tracking.");
			return false;
		}
		OVRPlugin.SetFaceTrackingVisemesEnabled(OVRRuntimeSettings.GetRuntimeSettings().EnableFaceTrackingVisemesOutput);
		return true;
	}

	private void OnDisable()
	{
		if (--_trackingInstanceCount == 0)
		{
			OVRPlugin.StopFaceTracking2();
		}
	}

	private void OnDestroy()
	{
		OVRPermissionsRequester.PermissionGranted -= _onPermissionGranted;
	}

	private void Update()
	{
		ValidExpressions = OVRPlugin.GetFaceState2(OVRPlugin.Step.Render, -1, ref _currentFaceState) && _currentFaceState.Status.IsValid;
		EyeFollowingBlendshapesValid = ValidExpressions && _currentFaceState.Status.IsEyeFollowingBlendshapesValid;
		AreVisemesValid = OVRPlugin.GetFaceVisemesState(OVRPlugin.Step.Render, ref _currentFaceVisemesState) == OVRPlugin.Result.Success && _currentFaceVisemesState.IsValid;
	}

	public float GetWeight(FaceExpression expression)
	{
		return this[expression];
	}

	public bool TryGetFaceExpressionWeight(FaceExpression expression, out float weight)
	{
		if (!ValidExpressions || expression < FaceExpression.BrowLowererL || expression >= FaceExpression.Max)
		{
			weight = 0f;
			return false;
		}
		weight = _currentFaceState.ExpressionWeights[(int)expression];
		return true;
	}

	public float GetViseme(FaceViseme viseme)
	{
		CheckVisemesValidity();
		if (viseme < FaceViseme.SIL || viseme >= FaceViseme.Count)
		{
			throw new ArgumentOutOfRangeException("viseme", viseme, $"Value must be between 0 to {15}");
		}
		return _currentFaceVisemesState.Visemes[(int)viseme];
	}

	public bool TryGetFaceViseme(FaceViseme viseme, out float weight)
	{
		if (!AreVisemesValid || viseme < FaceViseme.SIL || viseme >= FaceViseme.Count)
		{
			weight = 0f;
			return false;
		}
		weight = _currentFaceVisemesState.Visemes[(int)viseme];
		return true;
	}

	public void CopyVisemesTo(float[] array, int startIndex = 0)
	{
		if (array == null)
		{
			throw new ArgumentNullException("array");
		}
		if (startIndex < 0 || startIndex >= array.Length)
		{
			throw new ArgumentOutOfRangeException("startIndex", startIndex, $"Value must be between 0 to {array.Length - 1}");
		}
		if (array.Length - startIndex < 15)
		{
			throw new ArgumentException($"Capacity is too small - required {15}, available {array.Length - startIndex}.", "array");
		}
		CheckVisemesValidity();
		for (int i = 0; i < 15; i++)
		{
			array[i + startIndex] = _currentFaceVisemesState.Visemes[i];
		}
	}

	public bool TryGetWeightConfidence(FaceRegionConfidence region, out float weightConfidence)
	{
		if (!ValidExpressions || region < FaceRegionConfidence.Lower || region >= FaceRegionConfidence.Max)
		{
			weightConfidence = 0f;
			return false;
		}
		weightConfidence = _currentFaceState.ExpressionWeightConfidences[(int)region];
		return true;
	}

	public bool TryGetFaceTrackingDataSource(out FaceTrackingDataSource dataSource)
	{
		dataSource = (FaceTrackingDataSource)_currentFaceState.DataSource;
		return ValidExpressions;
	}

	internal void CheckValidity()
	{
		if (!ValidExpressions)
		{
			throw new InvalidOperationException("Face expressions are not valid at this time. Use ValidExpressions to check for validity.");
		}
