	internal void CheckVisemesValidity()
	{
		if (!AreVisemesValid)
		{
			throw new InvalidOperationException("Face visemes are not valid at this time. Use AreVisemesValid to check for validity.");
		}
	}

	public void CopyTo(float[] array, int startIndex = 0)
	{
