		}
		else
		{
			for (int i = 0; i < array.Length; i++)
			{
				SeekStride(i);
				array[i].x = ReadAsFloat(_reader, _activeGltfAccessor.ComponentType);
				array[i].y = ReadAsFloat(_reader, _activeGltfAccessor.ComponentType);
