		},
		{
			"button_y",
			OVRGLTFInputNode.Button_B_Y
		},
		{
			"button_oculus",
			OVRGLTFInputNode.Button_Oculus_Menu
		},
		{
			"trigger_front",
			OVRGLTFInputNode.Trigger_Front
		},
		{
