[DisallowMultipleComponent]
[HelpURL("https://developer.oculus.com/documentation/unity/unity-wide-motion-mode/")]
public class OVRHandTrackingWideMotionModeSample : MonoBehaviour
{
	[SerializeField]
	public Toggle fusionToggle;

	[SerializeField]
	private LineRenderer leftLinePointer;

	[SerializeField]
	private LineRenderer rightLinePointer;

	[SerializeField]
	private OVRHand handLeft;

	[SerializeField]
	private OVRHand handRight;

	[SerializeField]
	private OVRInputModule inputModule;

	private void OnEnable()
	{
		fusionToggle.onValueChanged.AddListener(OnFusionToggleChanged);
	}

	private void OnDisable()
	{
		fusionToggle.onValueChanged.RemoveListener(OnFusionToggleChanged);
	}

	private void Update()
	{
		UpdateLineRenderer();
	}

	private void UpdateLineRenderer()
	{
		leftLinePointer.enabled = false;
		rightLinePointer.enabled = false;
		UpdateLineRendererForHand(isLeft: false);
		UpdateLineRendererForHand(isLeft: true);
	}

	private void UpdateLineRendererForHand(bool isLeft)
	{
		Transform transform = null;
		if (isLeft)
		{
			if (handLeft != null && handLeft.IsPointerPoseValid)
			{
				transform = handLeft.PointerPose;
				if (handLeft.GetFingerIsPinching(OVRHand.HandFinger.Index))
				{
					inputModule.rayTransform = transform;
				}
			}
			else
			{
				transform = null;
			}
		}
		else
		{
			if (handRight != null && handRight.IsPointerPoseValid)
			{
				transform = handRight.PointerPose;
				if (handRight.GetFingerIsPinching(OVRHand.HandFinger.Index))
				{
					inputModule.rayTransform = transform;
				}
			}
			else
			{
				transform = null;
			}
			transform = ((handRight != null && handRight.IsPointerPoseValid) ? handRight.PointerPose : null);
		}
		if (!(transform == null))
		{
			Vector3 position = transform.position;
			LineRenderer obj = (isLeft ? leftLinePointer : rightLinePointer);
			Ray ray = new Ray(position, transform.rotation * Vector3.forward);
			obj.enabled = true;
			obj.SetPosition(0, transform.position + ray.direction * 0.05f);
			obj.SetPosition(1, position + ray.direction * 2.5f);
		}
	}

	private void OnFusionToggleChanged(bool newValue)
	{
		OVRManager.instance.wideMotionModeHandPosesEnabled = newValue;
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-haptics-apis/")]
public static class OVRHaptics
{
	public static class Config
	{
		public static int SampleRateHz { get; private set; }

		public static int SampleSizeInBytes { get; private set; }

		public static int MinimumSafeSamplesQueued { get; private set; }

		public static int MinimumBufferSamplesCount { get; private set; }

		public static int OptimalBufferSamplesCount { get; private set; }

		public static int MaximumBufferSamplesCount { get; private set; }

		static Config()
		{
			Load();
		}

		public static void Load()
		{
			OVRPlugin.HapticsDesc controllerHapticsDesc = OVRPlugin.GetControllerHapticsDesc(2u);
			SampleRateHz = controllerHapticsDesc.SampleRateHz;
			SampleSizeInBytes = controllerHapticsDesc.SampleSizeInBytes;
			MinimumSafeSamplesQueued = controllerHapticsDesc.MinimumSafeSamplesQueued;
			MinimumBufferSamplesCount = controllerHapticsDesc.MinimumBufferSamplesCount;
			OptimalBufferSamplesCount = controllerHapticsDesc.OptimalBufferSamplesCount;
			MaximumBufferSamplesCount = controllerHapticsDesc.MaximumBufferSamplesCount;
		}
	}

	public class OVRHapticsChannel
	{
		private OVRHapticsOutput m_output;

		public OVRHapticsChannel(uint outputIndex)
		{
			m_output = m_outputs[outputIndex];
		}

		public void Preempt(OVRHapticsClip clip)
		{
			m_output.Preempt(clip);
		}

		public void Queue(OVRHapticsClip clip)
		{
			m_output.Queue(clip);
		}

		public void Mix(OVRHapticsClip clip)
		{
			m_output.Mix(clip);
		}

		public void Clear()
		{
			m_output.Clear();
		}
	}

	private class OVRHapticsOutput
	{
		private class ClipPlaybackTracker
		{
			public int ReadCount { get; set; }

			public OVRHapticsClip Clip { get; set; }

			public ClipPlaybackTracker(OVRHapticsClip clip)
			{
				Clip = clip;
			}
		}

		private bool m_lowLatencyMode = true;

		private int m_prevSamplesQueued;

		private float m_prevSamplesQueuedTime;

		private int m_numPredictionHits;

		private int m_numPredictionMisses;

		private int m_numUnderruns;

		private List<ClipPlaybackTracker> m_pendingClips = new List<ClipPlaybackTracker>();

		private uint m_controller;

		private OVRNativeBuffer m_nativeBuffer = new OVRNativeBuffer(Config.MaximumBufferSamplesCount * Config.SampleSizeInBytes);

		private int PrevSampleRateHz = -1;

		public OVRHapticsOutput(uint controller)
		{
			m_controller = controller;
		}

		public void Process()
		{
			if (Config.SampleRateHz == 0)
			{
				if (PrevSampleRateHz != 0)
				{
					UnityEngine.Debug.Log("Unable to process a controller whose SampleRateHz is 0 now.");
					PrevSampleRateHz = 0;
				}
				return;
			}
			PrevSampleRateHz = Config.SampleRateHz;
			if (m_nativeBuffer.GetCapacity() != Config.MaximumBufferSamplesCount * Config.SampleSizeInBytes)
			{
				m_nativeBuffer.Reset(Config.MaximumBufferSamplesCount * Config.SampleSizeInBytes);
			}
			OVRPlugin.HapticsState controllerHapticsState = OVRPlugin.GetControllerHapticsState(m_controller);
			float num = Time.realtimeSinceStartup - m_prevSamplesQueuedTime;
			if (m_prevSamplesQueued > 0)
			{
				int num2 = m_prevSamplesQueued - (int)(num * (float)Config.SampleRateHz + 0.5f);
				if (num2 < 0)
				{
					num2 = 0;
				}
				if (controllerHapticsState.SamplesQueued - num2 == 0)
				{
					m_numPredictionHits++;
				}
				else
				{
					m_numPredictionMisses++;
				}
				if (num2 > 0 && controllerHapticsState.SamplesQueued == 0)
				{
					m_numUnderruns++;
				}
				m_prevSamplesQueued = controllerHapticsState.SamplesQueued;
				m_prevSamplesQueuedTime = Time.realtimeSinceStartup;
			}
			int num3 = Config.OptimalBufferSamplesCount;
			if (m_lowLatencyMode)
			{
				float num4 = 1000f / (float)Config.SampleRateHz;
				int num5 = (int)Mathf.Ceil(num * 1000f / num4);
				int num6 = Config.MinimumSafeSamplesQueued + num5;
				if (num6 < num3)
				{
					num3 = num6;
				}
			}
			if (controllerHapticsState.SamplesQueued > num3)
			{
				return;
			}
			if (num3 > Config.MaximumBufferSamplesCount)
			{
				num3 = Config.MaximumBufferSamplesCount;
			}
			if (num3 > controllerHapticsState.SamplesAvailable)
			{
				num3 = controllerHapticsState.SamplesAvailable;
			}
			int num7 = 0;
			int num8 = 0;
			while (num7 < num3 && num8 < m_pendingClips.Count)
			{
				int num9 = num3 - num7;
				int num10 = m_pendingClips[num8].Clip.Count - m_pendingClips[num8].ReadCount;
				if (num9 > num10)
				{
					num9 = num10;
				}
				if (num9 > 0)
				{
					int length = num9 * Config.SampleSizeInBytes;
					int byteOffset = num7 * Config.SampleSizeInBytes;
					int startIndex = m_pendingClips[num8].ReadCount * Config.SampleSizeInBytes;
					Marshal.Copy(m_pendingClips[num8].Clip.Samples, startIndex, m_nativeBuffer.GetPointer(byteOffset), length);
					m_pendingClips[num8].ReadCount += num9;
					num7 += num9;
				}
				num8++;
			}
			int num11 = m_pendingClips.Count - 1;
			while (num11 >= 0 && m_pendingClips.Count > 0)
			{
				if (m_pendingClips[num11].ReadCount >= m_pendingClips[num11].Clip.Count)
				{
					m_pendingClips.RemoveAt(num11);
				}
				num11--;
			}
			if (num7 > 0)
			{
				OVRPlugin.HapticsBuffer hapticsBuffer = default(OVRPlugin.HapticsBuffer);
				hapticsBuffer.Samples = m_nativeBuffer.GetPointer();
				hapticsBuffer.SamplesCount = num7;
				OVRPlugin.SetControllerHaptics(m_controller, hapticsBuffer);
				m_prevSamplesQueued = OVRPlugin.GetControllerHapticsState(m_controller).SamplesQueued;
				m_prevSamplesQueuedTime = Time.realtimeSinceStartup;
			}
		}

		public void Preempt(OVRHapticsClip clip)
		{
			m_pendingClips.Clear();
			m_pendingClips.Add(new ClipPlaybackTracker(clip));
		}

		public void Queue(OVRHapticsClip clip)
		{
			m_pendingClips.Add(new ClipPlaybackTracker(clip));
		}

		public void Mix(OVRHapticsClip clip)
		{
			int num = 0;
			int num2 = 0;
			int num3 = clip.Count;
			while (num3 > 0 && num < m_pendingClips.Count)
			{
				int num4 = m_pendingClips[num].Clip.Count - m_pendingClips[num].ReadCount;
				num3 -= num4;
				num2 += num4;
				num++;
			}
			if (num3 > 0)
			{
				num2 += num3;
				num3 = 0;
			}
			if (num > 0)
			{
				OVRHapticsClip oVRHapticsClip = new OVRHapticsClip(num2);
				int i = 0;
				for (int j = 0; j < num; j++)
				{
					OVRHapticsClip clip2 = m_pendingClips[j].Clip;
					for (int k = m_pendingClips[j].ReadCount; k < clip2.Count; k++)
					{
						if (Config.SampleSizeInBytes == 1)
						{
							byte sample = 0;
							if (i < clip.Count && k < clip2.Count)
							{
								sample = (byte)Mathf.Clamp(clip.Samples[i] + clip2.Samples[k], 0, 255);
								i++;
							}
							else if (k < clip2.Count)
							{
								sample = clip2.Samples[k];
							}
							oVRHapticsClip.WriteSample(sample);
						}
					}
				}
				for (; i < clip.Count; i++)
				{
					if (Config.SampleSizeInBytes == 1)
					{
						oVRHapticsClip.WriteSample(clip.Samples[i]);
					}
				}
				m_pendingClips[0] = new ClipPlaybackTracker(oVRHapticsClip);
				for (int l = 1; l < num; l++)
				{
					m_pendingClips.RemoveAt(1);
				}
			}
			else
			{
				m_pendingClips.Add(new ClipPlaybackTracker(clip));
			}
		}

		public void Clear()
		{
			m_pendingClips.Clear();
		}
	}

	public static readonly OVRHapticsChannel[] Channels;

	public static readonly OVRHapticsChannel LeftChannel;

	public static readonly OVRHapticsChannel RightChannel;

	private static readonly OVRHapticsOutput[] m_outputs;

	static OVRHaptics()
	{
		Config.Load();
		m_outputs = new OVRHapticsOutput[2]
		{
			new OVRHapticsOutput(1u),
			new OVRHapticsOutput(2u)
		};
		Channels = new OVRHapticsChannel[2]
		{
			(LeftChannel = new OVRHapticsChannel(0u)),
			(RightChannel = new OVRHapticsChannel(1u))
		};
	}

	public static void Process()
	{
		Config.Load();
		for (int i = 0; i < m_outputs.Length; i++)
		{
			m_outputs[i].Process();
		}
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-haptics-apis/")]
public class OVRHapticsClip
{
	public int Count { get; private set; }

	public int Capacity { get; private set; }

	public byte[] Samples { get; private set; }

	public OVRHapticsClip()
	{
		Capacity = OVRHaptics.Config.MaximumBufferSamplesCount;
		Samples = new byte[Capacity * OVRHaptics.Config.SampleSizeInBytes];
	}

	public OVRHapticsClip(int capacity)
	{
		Capacity = ((capacity >= 0) ? capacity : 0);
		Samples = new byte[Capacity * OVRHaptics.Config.SampleSizeInBytes];
	}

	public OVRHapticsClip(byte[] samples, int samplesCount)
	{
		Samples = samples;
		Capacity = Samples.Length / OVRHaptics.Config.SampleSizeInBytes;
		Count = ((samplesCount >= 0) ? samplesCount : 0);
	}

	public OVRHapticsClip(OVRHapticsClip a, OVRHapticsClip b)
	{
		int count = a.Count;
		if (b.Count > count)
		{
			count = b.Count;
		}
		Capacity = count;
		Samples = new byte[Capacity * OVRHaptics.Config.SampleSizeInBytes];
		for (int i = 0; i < a.Count || i < b.Count; i++)
		{
			if (OVRHaptics.Config.SampleSizeInBytes == 1)
			{
				byte sample = 0;
				if (i < a.Count && i < b.Count)
				{
					sample = (byte)Mathf.Clamp(a.Samples[i] + b.Samples[i], 0, 255);
				}
				else if (i < a.Count)
				{
					sample = a.Samples[i];
				}
				else if (i < b.Count)
				{
					sample = b.Samples[i];
				}
				WriteSample(sample);
			}
		}
	}

	public OVRHapticsClip(AudioClip audioClip, int channel = 0)
	{
		float[] array = new float[audioClip.samples * audioClip.channels];
		audioClip.GetData(array, 0);
		InitializeFromAudioFloatTrack(array, audioClip.frequency, audioClip.channels, channel);
	}

	public void WriteSample(byte sample)
	{
		if (Count < Capacity)
		{
			if (OVRHaptics.Config.SampleSizeInBytes == 1)
			{
				Samples[Count * OVRHaptics.Config.SampleSizeInBytes] = sample;
			}
			Count++;
		}
	}

	public void Reset()
	{
		Count = 0;
	}

	private void InitializeFromAudioFloatTrack(float[] sourceData, double sourceFrequency, int sourceChannelCount, int sourceChannel)
	{
		if (OVRHaptics.Config.SampleRateHz == 0)
		{
			UnityEngine.Debug.Log("Unable to initialize a controller whose SampleRateHz is 0 now.");
			return;
		}
		double num = (sourceFrequency + 1E-06) / (double)OVRHaptics.Config.SampleRateHz;
		if (num < 1.0 || num > 2147483647.0)
		{
			return;
		}
		int num2 = (int)num;
		double num3 = num - (double)num2;
		double num4 = 0.0;
		int num5 = sourceData.Length;
		Count = 0;
		Capacity = num5 / sourceChannelCount / num2 + 1;
		Samples = new byte[Capacity * OVRHaptics.Config.SampleSizeInBytes];
		int num6 = sourceChannel % sourceChannelCount;
		while (num6 < num5)
		{
			if (OVRHaptics.Config.SampleSizeInBytes == 1)
			{
				WriteSample((byte)(Mathf.Clamp01(Mathf.Abs(sourceData[num6])) * 255f));
			}
			num6 += num2 * sourceChannelCount;
			num4 += num3;
			if ((int)num4 > 0)
			{
				num6 += (int)num4 * sourceChannelCount;
				num4 -= (double)(int)num4;
			}
		}
	}
}
public class OVRHeadsetEmulator : MonoBehaviour
{
	public enum OpMode
	{
		Off,
		EditorOnly,
		AlwaysOn
	}

	public OpMode opMode = OpMode.EditorOnly;

	public bool resetHmdPoseOnRelease = true;

	public bool resetHmdPoseByMiddleMouseButton = true;

	public KeyCode[] activateKeys = new KeyCode[3]
	{
		KeyCode.LeftControl,
		KeyCode.RightControl,
		KeyCode.F1
	};

	public string[] activateKeyBindings = new string[3] { "<Keyboard>/leftCtrl", "<Keyboard>/rightCtrl", "<Keyboard>/f1" };

	public KeyCode[] pitchKeys = new KeyCode[3]
	{
		KeyCode.LeftAlt,
		KeyCode.RightAlt,
		KeyCode.F2
	};

	public string[] pitchKeyBindings = new string[3] { "<Keyboard>/leftAlt", "<Keyboard>/rightAlt", "<Keyboard>/f2" };

	private InputAction[] activateKeyActions;

	private InputAction[] pitchKeyActions;

	private InputAction middleMouseButtonAction;

	private InputAction mouseScrollAction;

	private InputAction mouseMoveAction;

	private OVRManager manager;

	private const float MOUSE_SCALE_X = -2f;

	private const float MOUSE_SCALE_X_PITCH = -2f;

	private const float MOUSE_SCALE_Y = 2f;

	private const float MOUSE_SCALE_HEIGHT = 1f;

	private const float MAX_ROLL = 85f;

	private bool lastFrameEmulationActivated;

	private Vector3 recordedHeadPoseRelativeOffsetTranslation;

	private Vector3 recordedHeadPoseRelativeOffsetRotation;

	private bool hasSentEvent;

	private bool emulatorHasInitialized;

	private CursorLockMode previousCursorLockMode;

	private void Start()
	{
		activateKeyActions = new InputAction[activateKeyBindings.Length];
		for (int i = 0; i < activateKeyBindings.Length; i++)
		{
			activateKeyActions[i] = new InputAction(null, InputActionType.Value, activateKeyBindings[i]);
			activateKeyActions[i].Enable();
		}
		pitchKeyActions = new InputAction[pitchKeyBindings.Length];
		for (int j = 0; j < pitchKeyBindings.Length; j++)
		{
			pitchKeyActions[j] = new InputAction(null, InputActionType.Value, pitchKeyBindings[j]);
			pitchKeyActions[j].Enable();
		}
		middleMouseButtonAction = new InputAction(null, InputActionType.Button, "<Mouse>/middleButton");
		mouseScrollAction = new InputAction(null, InputActionType.Value, "<Mouse>/scroll/y");
		mouseMoveAction = new InputAction(null, InputActionType.Value, "<Mouse>/delta");
		middleMouseButtonAction.Enable();
		mouseScrollAction.Enable();
		mouseMoveAction.Enable();
	}

	private void Update()
	{
		if (!emulatorHasInitialized)
		{
			if (!OVRManager.OVRManagerinitialized)
			{
				return;
			}
			previousCursorLockMode = Cursor.lockState;
			manager = OVRManager.instance;
			recordedHeadPoseRelativeOffsetTranslation = manager.headPoseRelativeOffsetTranslation;
			recordedHeadPoseRelativeOffsetRotation = manager.headPoseRelativeOffsetRotation;
			emulatorHasInitialized = true;
			lastFrameEmulationActivated = false;
		}
		bool flag = IsEmulationActivated();
		if (flag)
		{
			if (!lastFrameEmulationActivated)
			{
				previousCursorLockMode = Cursor.lockState;
				Cursor.lockState = CursorLockMode.Locked;
			}
			if (!lastFrameEmulationActivated && resetHmdPoseOnRelease)
			{
				manager.headPoseRelativeOffsetTranslation = recordedHeadPoseRelativeOffsetTranslation;
				manager.headPoseRelativeOffsetRotation = recordedHeadPoseRelativeOffsetRotation;
			}
			bool flag2 = false;
			float num = 0f;
			float num2 = 0f;
			float num3 = 0f;
			flag2 = middleMouseButtonAction.phase == InputActionPhase.Performed;
			num = mouseScrollAction.ReadValue<float>();
			Vector2 vector = mouseMoveAction.ReadValue<Vector2>();
			num2 = vector.x * 0.05f;
			num3 = vector.y * 0.05f;
			if (resetHmdPoseByMiddleMouseButton && flag2)
			{
				manager.headPoseRelativeOffsetTranslation = Vector3.zero;
				manager.headPoseRelativeOffsetRotation = Vector3.zero;
			}
			else
			{
				Vector3 headPoseRelativeOffsetTranslation = manager.headPoseRelativeOffsetTranslation;
				float num4 = num * 1f;
				headPoseRelativeOffsetTranslation.y += num4;
				manager.headPoseRelativeOffsetTranslation = headPoseRelativeOffsetTranslation;
				Vector3 headPoseRelativeOffsetRotation = manager.headPoseRelativeOffsetRotation;
				float num5 = headPoseRelativeOffsetRotation.x;
				float num6 = headPoseRelativeOffsetRotation.y;
				float num7 = headPoseRelativeOffsetRotation.z;
				if (IsTweakingPitch())
				{
					num7 += num2 * -2f;
				}
				else
				{
					num5 += num3 * 2f;
					num6 += num2 * -2f;
				}
				manager.headPoseRelativeOffsetRotation = new Vector3(num5, num6, num7);
			}
			if (!hasSentEvent)
			{
				OVRPlugin.SendEvent("headset_emulator", "activated");
				hasSentEvent = true;
			}
		}
		else if (lastFrameEmulationActivated)
		{
			Cursor.lockState = previousCursorLockMode;
			recordedHeadPoseRelativeOffsetTranslation = manager.headPoseRelativeOffsetTranslation;
			recordedHeadPoseRelativeOffsetRotation = manager.headPoseRelativeOffsetRotation;
			if (resetHmdPoseOnRelease)
			{
				manager.headPoseRelativeOffsetTranslation = Vector3.zero;
				manager.headPoseRelativeOffsetRotation = Vector3.zero;
			}
		}
		lastFrameEmulationActivated = flag;
	}

	private bool IsEmulationActivated()
	{
		if (opMode == OpMode.Off)
		{
			return false;
		}
		if (opMode == OpMode.EditorOnly && !Application.isEditor)
		{
			return false;
		}
		InputAction[] array = activateKeyActions;
		for (int i = 0; i < array.Length; i++)
		{
			if (array[i].phase == InputActionPhase.Started)
			{
				return true;
			}
		}
		return false;
	}

	private bool IsTweakingPitch()
	{
		if (!IsEmulationActivated())
		{
			return false;
		}
		InputAction[] array = pitchKeyActions;
		for (int i = 0; i < array.Length; i++)
		{
			if (array[i].phase == InputActionPhase.Started)
			{
				return true;
			}
		}
		return false;
	}

	private void OnDestroy()
	{
		if (activateKeyActions != null)
		{
			InputAction[] array = activateKeyActions;
			for (int i = 0; i < array.Length; i++)
			{
				array[i].Disable();
			}
		}
		if (pitchKeyActions != null)
		{
			InputAction[] array = pitchKeyActions;
			for (int i = 0; i < array.Length; i++)
			{
				array[i].Disable();
			}
		}
		middleMouseButtonAction?.Disable();
		mouseScrollAction?.Disable();
		mouseMoveAction?.Disable();
	}
}
