	private static Vector2 CalculateAbsMax(Vector2 a, Vector2 b)
	{
		float sqrMagnitude = a.sqrMagnitude;
		float sqrMagnitude2 = b.sqrMagnitude;
		if (sqrMagnitude >= sqrMagnitude2)
		{
			return a;
		}
		return b;
	}

	private static float CalculateAbsMax(float a, float b)
	{
		float num = ((a >= 0f) ? a : (0f - a));
		float num2 = ((b >= 0f) ? b : (0f - b));
		if (num >= num2)
		{
			return a;
		}
		return b;
	}

	private static Vector2 CalculateDeadzone(Vector2 a, float deadzone)
	{
		if (a.sqrMagnitude <= deadzone * deadzone)
		{
			return Vector2.zero;
		}
		a *= (a.magnitude - deadzone) / (1f - deadzone);
		if (a.sqrMagnitude > 1f)
		{
			return a.normalized;
		}
		return a;
	}

	private static float CalculateDeadzone(float a, float deadzone)
	{
		float num = ((a >= 0f) ? a : (0f - a));
		if (num <= deadzone)
		{
			return 0f;
		}
		a *= (num - deadzone) / (1f - deadzone);
		if (a * a > 1f)
		{
			if (!(a >= 0f))
			{
				return -1f;
			}
			return 1f;
		}
		return a;
	}

	private static bool ShouldResolveController(Controller controllerType, Controller controllerMask)
	{
		bool result = false;
		if ((controllerType & controllerMask) == controllerType)
		{
			result = true;
		}
		if ((controllerMask & Controller.Touch) == Controller.Touch && (controllerType & Controller.Touch) != Controller.None && (controllerType & Controller.Touch) != Controller.Touch)
		{
			result = false;
		}
		if ((controllerMask & Controller.Hands) == Controller.Hands && (controllerType & Controller.Hands) != Controller.None && (controllerType & Controller.Hands) != Controller.Hands)
		{
			result = false;
		}
		return result;
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-runtime-controller/#use-apis-in-customized-scripts")]
public class OVRKtxTexture
{
	private const uint KTX_TTF_BC7_RGBA = 6u;

	private const uint KTX_TTF_ASTC_4x4_RGBA = 10u;

	public static bool Load(byte[] data, ref OVRTextureData ktxData)
	{
		IntPtr intPtr = Marshal.AllocHGlobal(Marshal.SizeOf(data[0]) * data.Length);
		Marshal.Copy(data, 0, intPtr, data.Length);
		IntPtr texture = OVRPlugin.Ktx.LoadKtxFromMemory(intPtr, (uint)data.Length);
		Marshal.FreeHGlobal(intPtr);
		ktxData.width = (int)OVRPlugin.Ktx.GetKtxTextureWidth(texture);
		ktxData.height = (int)OVRPlugin.Ktx.GetKtxTextureHeight(texture);
		bool num = OVRPlugin.Ktx.TranscodeKtxTexture(texture, 6u);
		ktxData.transcodedFormat = TextureFormat.BC7;
		if (!num)
		{
			UnityEngine.Debug.LogError("Failed to transcode KTX texture.");
			return false;
		}
		uint ktxTextureSize = OVRPlugin.Ktx.GetKtxTextureSize(texture);
		IntPtr intPtr2 = Marshal.AllocHGlobal((int)ktxTextureSize);
		if (!OVRPlugin.Ktx.GetKtxTextureData(texture, intPtr2, ktxTextureSize))
		{
			UnityEngine.Debug.LogError("Failed to get texture data from Ktx texture reference");
			return false;
		}
		byte[] array = new byte[ktxTextureSize];
		Marshal.Copy(intPtr2, array, 0, array.Length);
		Marshal.FreeHGlobal(intPtr2);
		ktxData.data = array;
		OVRPlugin.Ktx.DestroyKtxTexture(texture);
		return true;
	}
}
