	private class Observable<T>
	{
		private T _value;

		public Action<T> OnChanged;

		public T Value
		{
			get
			{
				return _value;
			}
			set
			{
				_ = _value;
				_value = value;
				if (OnChanged != null)
				{
					OnChanged(value);
				}
			}
		}

		public Observable()
		{
		}

		public Observable(T defaultValue)
		{
			_value = defaultValue;
		}

		public Observable(T defaultValue, Action<T> callback)
			: this(defaultValue)
		{
			OnChanged = (Action<T>)Delegate.Combine(OnChanged, callback);
		}
	}

