public class OVRMicrogestureEventSource : MonoBehaviour
{
	[SerializeField]
	private OVRHand _hand;

	public UnityEvent<OVRHand.MicrogestureType> GestureRecognizedEvent;

	public Action<OVRHand.MicrogestureType> WhenGestureRecognized = delegate
	{
	};

	public OVRHand Hand
	{
		get
		{
			return _hand;
		}
		set
		{
			_hand = value;
		}
	}

	private void Update()
	{
		OVRHand.MicrogestureType microgestureType = _hand.GetMicrogestureType();
		if (microgestureType != OVRHand.MicrogestureType.Invalid && microgestureType != OVRHand.MicrogestureType.NoGesture)
		{
			RaiseGestureRecognized(microgestureType);
		}
	}

	private void RaiseGestureRecognized(OVRHand.MicrogestureType gesture)
	{
		GestureRecognizedEvent?.Invoke(gesture);
		WhenGestureRecognized?.Invoke(gesture);
	}
}
public class OVRMicrogesturesSample : MonoBehaviour
{
	[SerializeField]
	private OVRMicrogestureEventSource leftGestureSource;

	[SerializeField]
	private OVRMicrogestureEventSource rightGestureSource;

	[Header("Gesture Labels")]
	[SerializeField]
	private Text leftGestureLabel;

	[SerializeField]
	private Text rightGestureLabel;

	[SerializeField]
	private float gestureShowDuration = 1.5f;

	[Header("Navigation Icons Left")]
	[SerializeField]
	private Image leftArrowL;

	[SerializeField]
	private Image rightArrowL;

	[SerializeField]
	private Image upArrowL;

	[SerializeField]
	private Image downArrowL;

	[SerializeField]
	private Image selectIconL;

	[Header("Navigation Icons Right")]
	[SerializeField]
	private Image leftArrowR;

	[SerializeField]
	private Image rightArrowR;

	[SerializeField]
	private Image upArrowR;

	[SerializeField]
	private Image downArrowR;

	[SerializeField]
	private Image selectIconR;

	[Header("Colors")]
	[SerializeField]
	private Color initialColor = Color.white;

	[SerializeField]
	private Color highlightColor = Color.blue;

	[SerializeField]
	private float highlightDuration = 1f;

	private Dictionary<GameObject, Coroutine> highlightCoroutines = new Dictionary<GameObject, Coroutine>();

	private void Start()
	{
		leftGestureSource.GestureRecognizedEvent.AddListener(delegate(OVRHand.MicrogestureType gesture)
		{
			OnGestureRecognized(OVRPlugin.Hand.HandLeft, gesture);
		});
		rightGestureSource.GestureRecognizedEvent.AddListener(delegate(OVRHand.MicrogestureType gesture)
		{
			OnGestureRecognized(OVRPlugin.Hand.HandRight, gesture);
		});
	}

	private void HighlightGesture(OVRPlugin.Hand hand, OVRHand.MicrogestureType gesture)
	{
		switch (gesture)
		{
		case OVRHand.MicrogestureType.SwipeLeft:
			HighlightIcon((hand == OVRPlugin.Hand.HandLeft) ? leftArrowL : leftArrowR);
			break;
		case OVRHand.MicrogestureType.SwipeRight:
			HighlightIcon((hand == OVRPlugin.Hand.HandLeft) ? rightArrowL : rightArrowR);
			break;
		case OVRHand.MicrogestureType.SwipeForward:
			HighlightIcon((hand == OVRPlugin.Hand.HandLeft) ? upArrowL : upArrowR);
			break;
		case OVRHand.MicrogestureType.SwipeBackward:
			HighlightIcon((hand == OVRPlugin.Hand.HandLeft) ? downArrowL : downArrowR);
			break;
		case OVRHand.MicrogestureType.ThumbTap:
			HighlightIcon((hand == OVRPlugin.Hand.HandLeft) ? selectIconL : selectIconR);
			break;
		}
	}

	private void HighlightIcon(Image icon)
	{
		if (highlightCoroutines.TryGetValue(icon.gameObject, out var value))
		{
			StopCoroutine(value);
			highlightCoroutines.Remove(icon.gameObject);
		}
		highlightCoroutines.Add(icon.gameObject, StartCoroutine(HighlightIconCoroutine(icon)));
	}

	private IEnumerator HighlightIconCoroutine(Image navIcon)
	{
		Color initialCol = initialColor;
		navIcon.color = highlightColor;
		float timer = 0f;
		while (timer < highlightDuration)
		{
			navIcon.color = Color.Lerp(highlightColor, initialCol, timer / highlightDuration);
			timer += Time.deltaTime;
			yield return null;
		}
	}

	private void HighlightIcon(Image navIcon, bool state)
	{
		navIcon.color = (state ? highlightColor : initialColor);
	}

	private void OnGestureRecognized(OVRPlugin.Hand hand, OVRHand.MicrogestureType gesture)
	{
		HighlightGesture(hand, gesture);
		ShowRecognizedGestureLabel((hand == OVRPlugin.Hand.HandLeft) ? leftGestureLabel : rightGestureLabel, gesture.ToString());
	}

	private void ShowRecognizedGestureLabel(Text gestureLabel, string label)
	{
		if (highlightCoroutines.TryGetValue(gestureLabel.gameObject, out var value))
		{
			StopCoroutine(value);
			highlightCoroutines.Remove(gestureLabel.gameObject);
		}
		highlightCoroutines.Add(gestureLabel.gameObject, StartCoroutine(ShowGestureLabel(gestureLabel, label)));
	}

	private IEnumerator ShowGestureLabel(Text gestureLabel, string label)
	{
		gestureLabel.text = label;
		yield return new WaitForSeconds(gestureShowDuration);
		gestureLabel.text = string.Empty;
	}
}
internal static class OVRMixedReality
{
	public static bool useFakeExternalCamera = false;

	public static Vector3 fakeCameraFloorLevelPosition = new Vector3(0f, 2f, -0.5f);

	public static Vector3 fakeCameraEyeLevelPosition = fakeCameraFloorLevelPosition - new Vector3(0f, 1.8f, 0f);

	public static Quaternion fakeCameraRotation = Quaternion.LookRotation((new Vector3(0f, fakeCameraFloorLevelPosition.y, 0f) - fakeCameraFloorLevelPosition).normalized, Vector3.up);

	public static float fakeCameraFov = 60f;

	public static float fakeCameraAspect = 1.7777778f;

	public static OVRComposition currentComposition = null;

	public static void Update(GameObject parentObject, Camera mainCamera, OVRMixedRealityCaptureConfiguration configuration, OVRManager.TrackingOrigin trackingOrigin)
	{
		if (!OVRPlugin.initialized)
		{
			UnityEngine.Debug.LogError("OVRPlugin not initialized");
			return;
		}
		if (!OVRPlugin.IsMixedRealityInitialized())
		{
			OVRPlugin.InitializeMixedReality();
			if (!OVRPlugin.IsMixedRealityInitialized())
			{
				UnityEngine.Debug.LogError("Unable to initialize OVRPlugin_MixedReality");
				return;
			}
			UnityEngine.Debug.Log("OVRPlugin_MixedReality initialized");
		}
		if (!OVRPlugin.IsMixedRealityInitialized())
		{
			return;
		}
		OVRPlugin.UpdateExternalCamera();
		OVRPlugin.UpdateCameraDevices();
		if (currentComposition != null && currentComposition.CompositionMethod() != configuration.compositionMethod)
		{
			currentComposition.Cleanup();
			currentComposition = null;
		}
		if (configuration.compositionMethod == OVRManager.CompositionMethod.External)
		{
			if (currentComposition == null)
			{
				currentComposition = new OVRExternalComposition(parentObject, mainCamera, configuration);
			}
			currentComposition.Update(parentObject, mainCamera, configuration, trackingOrigin);
		}
		else
		{
			UnityEngine.Debug.LogError("Unknown/Unsupported CompositionMethod : " + configuration.compositionMethod);
		}
	}

	public static void Cleanup()
	{
		if (currentComposition != null)
		{
			currentComposition.Cleanup();
			currentComposition = null;
		}
		if (OVRPlugin.IsMixedRealityInitialized())
		{
			OVRPlugin.ShutdownMixedReality();
		}
	}

	public static void RecenterPose()
	{
		if (currentComposition != null)
		{
			currentComposition.RecenterPose();
		}
	}
}
[ExecuteInEditMode]
[HelpURL("https://developer.oculus.com/documentation/unity/unity-ovroverlay/")]
public class OVROverlay : MonoBehaviour
{
	public enum OverlayShape
	{
		Quad = 0,
		Cylinder = 1,
		Cubemap = 2,
		OffcenterCubemap = 4,
		Equirect = 5,
		ReconstructionPassthrough = 7,
		SurfaceProjectedPassthrough = 8,
		Fisheye = 9,
		KeyboardHandsPassthrough = 10,
		KeyboardMaskedHandsPassthrough = 11
	}

	public enum OverlayType
	{
		None,
		Underlay,
		Overlay
	}

	public delegate void ExternalSurfaceObjectCreated();

	protected struct LayerTexture
	{
		public Texture appTexture;

		public IntPtr appTexturePtr;

		public Texture[] swapChain;

		public IntPtr[] swapChainPtr;
	}

	[Tooltip("Specify overlay's type")]
	public OverlayType currentOverlayType = OverlayType.Overlay;

	[Tooltip("If true, the texture's content is copied to the compositor each frame.")]
	public bool isDynamic;

	[Tooltip("If true, the layer would be used to present protected content (e.g. HDCP), the content won't be shown in screenshots or recordings.")]
	public bool isProtectedContent;

	public Rect srcRectLeft = new Rect(0f, 0f, 1f, 1f);

	public Rect srcRectRight = new Rect(0f, 0f, 1f, 1f);

	public Rect destRectLeft = new Rect(0f, 0f, 1f, 1f);

	public Rect destRectRight = new Rect(0f, 0f, 1f, 1f);

	public bool invertTextureRects;

	private OVRPlugin.TextureRectMatrixf textureRectMatrix = OVRPlugin.TextureRectMatrixf.zero;

	public bool overrideTextureRectMatrix;

	public bool overridePerLayerColorScaleAndOffset;

	public Vector4 colorScale = Vector4.one;

	public Vector4 colorOffset = Vector4.zero;

	public bool useExpensiveSuperSample;

	public bool useExpensiveSharpen;

	public bool hidden;

	[Tooltip("If true, the layer will be created as an external surface. externalSurfaceObject contains the Surface object. It's effective only on Android.")]
	public bool isExternalSurface;

	[Tooltip("The width which will be used to create the external surface. It's effective only on Android.")]
	public int externalSurfaceWidth;

	[Tooltip("The height which will be used to create the external surface. It's effective only on Android.")]
	public int externalSurfaceHeight;

	[Tooltip("The compositionDepth defines the order of the OVROverlays in composition. The overlay/underlay with smaller compositionDepth would be composited in the front of the overlay/underlay with larger compositionDepth.")]
	public int compositionDepth;

	private int layerCompositionDepth;

	[Tooltip("The noDepthBufferTesting will stop layer's depth buffer compositing even if the engine has \"Shared Depth Buffer\" enabled. The layer's ordering will be used instead which is determined by it's composition depth and overlay/underlay type.")]
	public bool noDepthBufferTesting = true;

	public OVRPlugin.EyeTextureFormat layerTextureFormat;

	[Tooltip("Specify overlay's shape")]
