	private static string ToSimpleJson<T>(T value)
	{
		ref T reference = ref value;
		T val = default(T);
		object obj;
		if (val == null)
		{
			val = reference;
			reference = ref val;
			if (val == null)
			{
				obj = null;
				goto IL_0042;
			}
		}
		obj = reference.GetType();
		goto IL_0042;
		IL_0042:
		object result;
		if (obj == null || ((Type)obj).IsValueType)
		{
			if (value is bool)
			{
				object obj2 = value;
				return ((bool)((obj2 is bool) ? obj2 : null)) ? "true" : "false";
			}
			if (value is Enum || value is string)
			{
				return $"\"{value}\"";
			}
			ref T reference2 = ref value;
			val = default(T);
			if (val == null)
			{
				val = reference2;
				reference2 = ref val;
				if (val == null)
				{
