public class OVROverlayCanvasManager : MonoBehaviour
{
	private static OVROverlayCanvasManager _instance;

	private List<OVROverlayCanvas> _canvases = new List<OVROverlayCanvas>();

	public static OVROverlayCanvasManager Instance
	{
		get
		{
			if (!(_instance != null))
			{
				if (!Application.isPlaying)
				{
					return null;
				}
				return _instance = new GameObject("OVROverlayCanvasManager").AddComponent<OVROverlayCanvasManager>();
			}
			return _instance;
		}
	}

	public IEnumerable<OVROverlayCanvas> Canvases => _canvases;

	public static void AddCanvas(OVROverlayCanvas canvas)
	{
		Instance?._canvases.Add(canvas);
	}

	public static void RemoveCanvas(OVROverlayCanvas canvas)
	{
		_instance?._canvases.Remove(canvas);
	}

	public bool IsCanvasPriority(OVROverlayCanvas canvas)
	{
		if (canvas.GetViewPriorityScore().HasValue)
		{
			return _canvases.IndexOf(canvas) < OVROverlayCanvasSettings.Instance.MaxSimultaneousCanvases;
		}
		return false;
	}

	protected void Awake()
	{
		_instance = this;
		UnityEngine.Object.DontDestroyOnLoad(this);
	}

	protected void Update()
	{
		_canvases.Sort(delegate(OVROverlayCanvas a, OVROverlayCanvas b)
		{
			float valueOrDefault = a.GetViewPriorityScore().GetValueOrDefault();
			float valueOrDefault2 = b.GetViewPriorityScore().GetValueOrDefault();
			return (!Mathf.Approximately(valueOrDefault, valueOrDefault2)) ? ((int)((valueOrDefault2 - valueOrDefault) * 10000f)) : (b.GetHashCode() - a.GetHashCode());
		});
	}

	protected void OnDestroy()
	{
		if (_instance == this)
		{
			_instance = null;
		}
	}
}
public class OVROverlayCanvasSettings : OVRRuntimeAssetsBase
{
	private const string kAssetName = "OVROverlayCanvasSettings";

	private const string kBuiltInOpaqueShaderName = "UI/Prerendered Opaque";

	private const string kUrpOpaqueShaderName = "URP/UI/Prerendered Opaque";

	private const string kBuiltInTransparentShaderName = "UI/Prerendered";

	private const string kUrpTransparentShaderName = "URP/UI/Prerendered";

	private static OVROverlayCanvasSettings _instance;

	[SerializeField]
	private Shader _transparentImposterShader;

	[SerializeField]
	private Shader _opaqueImposterShader;

	public int MaxSimultaneousCanvases = 1;

	public int CanvasRenderLayer = 31;

	public int CanvasLayer = -1;

	public static OVROverlayCanvasSettings Instance
	{
		get
		{
			if (_instance == null)
			{
				_instance = GetOverlayCanvasSettings();
			}
			return _instance;
		}
	}

	private static OVROverlayCanvasSettings GetOverlayCanvasSettings()
	{
		OVRRuntimeAssetsBase.LoadAsset(out OVROverlayCanvasSettings assetInstance, "OVROverlayCanvasSettings", (Action<OVROverlayCanvasSettings>)null);
		if (assetInstance == null)
		{
			UnityEngine.Debug.LogWarning("Failed to load runtime settings. Using default runtime settings instead.");
			assetInstance = ScriptableObject.CreateInstance<OVROverlayCanvasSettings>();
		}
		assetInstance.EnsureInitialized();
		return assetInstance;
	}

	public void ApplyGlobalSettings()
	{
	}

	public Shader GetShader(OVROverlayCanvas.DrawMode drawMode)
	{
		switch (drawMode)
		{
		case OVROverlayCanvas.DrawMode.Opaque:
		case OVROverlayCanvas.DrawMode.OpaqueWithClip:
		case OVROverlayCanvas.DrawMode.AlphaToMask:
			return _opaqueImposterShader;
		default:
			return _transparentImposterShader;
		}
	}

	private static bool UsingBuiltInRenderPipeline()
	{
		return GraphicsSettings.currentRenderPipeline == null;
	}

	private static void EnsureShaderInitialized(ref Shader shader, string shaderName, string replaceShaderName)
	{
		if (!(shader != null) || !(shader.name != replaceShaderName))
		{
			Shader shader2 = Shader.Find(shaderName);
			if (shader2 == null)
			{
				UnityEngine.Debug.LogError("Failed to find shader \"" + shaderName + "\"");
			}
			else
			{
				shader = shader2;
			}
		}
	}

	private void EnsureInitialized()
	{
		bool flag = UsingBuiltInRenderPipeline();
		EnsureShaderInitialized(ref _opaqueImposterShader, flag ? "UI/Prerendered Opaque" : "URP/UI/Prerendered Opaque", flag ? "URP/UI/Prerendered Opaque" : "UI/Prerendered Opaque");
		EnsureShaderInitialized(ref _transparentImposterShader, flag ? "UI/Prerendered" : "URP/UI/Prerendered", flag ? "URP/UI/Prerendered" : "UI/Prerendered");
	}

	private void OnValidate()
	{
		EnsureInitialized();
	}
}
public class OVROverlayCanvas_TMPChanged : MonoBehaviour
{
	public OVROverlayCanvas TargetCanvas;

	private static Dictionary<GameObject, OVROverlayCanvas> _textObjectToCanvas = new Dictionary<GameObject, OVROverlayCanvas>();

	[RuntimeInitializeOnLoadMethod]
	private static void OnLoad()
	{
		TMPro_EventManager.TEXT_CHANGED_EVENT.Add(OnTextChanged);
	}

	private static void OnTextChanged(UnityEngine.Object target)
	{
		if (target is TMP_Text tMP_Text && _textObjectToCanvas.TryGetValue(tMP_Text.gameObject, out var value))
		{
			value.SetFrameDirty();
		}
	}

	protected void OnEnable()
	{
		_textObjectToCanvas.Add(base.gameObject, TargetCanvas);
	}

	protected void OnDisable()
	{
		_textObjectToCanvas.Remove(base.gameObject);
	}
}
[RequireComponent(typeof(MeshFilter))]
[RequireComponent(typeof(MeshRenderer))]
[ExecuteAlways]
[HelpURL("https://developer.oculus.com/documentation/unity/unity-sf-stereo180video/")]
public class OVROverlayMeshGenerator : MonoBehaviour
{
	private enum CubeFace
	{
		Bottom,
		Front,
		Back,
		Right,
		Left,
		Top,
		COUNT
	}

	private readonly List<int> _Tris = new List<int>();

	private readonly List<Vector2> _UV = new List<Vector2>();

	private readonly List<Vector4> _CubeUV = new List<Vector4>();

	private readonly List<Vector3> _Verts = new List<Vector3>();

	private Transform _CameraRoot;

	private Rect _LastDestRectLeft;

	private Vector3 _LastPosition;

	private Quaternion _LastRotation;

	private Vector3 _LastScale;

	private TextureDimension _LastTextureDimension = TextureDimension.Tex2D;

	private OVROverlay.OverlayShape _LastShape;

	private Rect _LastSrcRectLeft;

	private Mesh _Mesh;

	private MeshCollider _MeshCollider;

	private MeshFilter _MeshFilter;

	private MeshRenderer _MeshRenderer;

	private OVROverlay _Overlay;

	private Transform _Transform;

	private Material _PreviewMaterial;

	protected void OnEnable()
	{
		Initialize();
	}

	protected void OnDestroy()
	{
		if (_Mesh != null)
		{
			if (Application.isPlaying)
			{
				UnityEngine.Object.Destroy(_Mesh);
			}
			else
			{
				UnityEngine.Object.DestroyImmediate(_Mesh);
			}
		}
		if (_PreviewMaterial != null)
		{
			if (Application.isPlaying)
			{
				UnityEngine.Object.Destroy(_PreviewMaterial);
			}
			else
			{
				UnityEngine.Object.DestroyImmediate(_PreviewMaterial);
			}
		}
	}

	private void Initialize()
	{
		_MeshFilter = GetComponent<MeshFilter>();
		_MeshRenderer = GetComponent<MeshRenderer>();
		_MeshCollider = GetComponent<MeshCollider>();
		_Transform = base.transform;
		if ((bool)Camera.main && (bool)Camera.main.transform.parent)
		{
			_CameraRoot = Camera.main.transform.parent;
		}
		TryUpdateMesh();
	}

	public void SetOverlay(OVROverlay overlay)
	{
		_Overlay = overlay;
		Initialize();
	}

	private void TryUpdateMesh()
	{
		if (_Overlay == null)
		{
			return;
		}
		if (_Mesh == null)
		{
			_Mesh = new Mesh
			{
				name = "Overlay"
			};
			_Mesh.hideFlags = HideFlags.DontSaveInEditor | HideFlags.DontSaveInBuild;
		}
		if (_Transform == null)
		{
			_Transform = base.transform;
		}
		OVROverlay.OverlayShape currentOverlayShape = _Overlay.currentOverlayShape;
		Vector3 vector = (_CameraRoot ? (_Transform.position - _CameraRoot.position) : _Transform.position);
		Quaternion rotation = _Transform.rotation;
		Vector3 lossyScale = _Transform.lossyScale;
		Rect rect = (_Overlay.overrideTextureRectMatrix ? _Overlay.destRectLeft : new Rect(0f, 0f, 1f, 1f));
		Rect rect2 = (_Overlay.overrideTextureRectMatrix ? _Overlay.srcRectLeft : new Rect(0f, 0f, 1f, 1f));
		Texture texture = _Overlay.textures[0];
		TextureDimension textureDimension = ((texture != null) ? texture.dimension : TextureDimension.Tex2D);
		if (_LastShape != currentOverlayShape || _LastPosition != vector || _LastRotation != rotation || _LastScale != lossyScale || _LastDestRectLeft != rect || _LastTextureDimension != textureDimension)
		{
			UpdateMesh(currentOverlayShape, vector, rotation, lossyScale, rect, textureDimension == TextureDimension.Cube);
		}
		if ((bool)_MeshRenderer)
		{
			if (_MeshRenderer.sharedMaterial == null || textureDimension != _LastTextureDimension)
			{
				if (_PreviewMaterial != null)
				{
					if (Application.isPlaying)
					{
						UnityEngine.Object.Destroy(_PreviewMaterial);
					}
					else
					{
						UnityEngine.Object.DestroyImmediate(_PreviewMaterial);
					}
				}
				_PreviewMaterial = null;
				switch (textureDimension)
				{
				case TextureDimension.Tex2D:
					_PreviewMaterial = new Material(Shader.Find("Unlit/Transparent"));
					break;
				case TextureDimension.Cube:
					_PreviewMaterial = new Material(Shader.Find("Hidden/CubeCopy"));
					break;
				}
				if (_PreviewMaterial != null)
				{
					_PreviewMaterial.mainTexture = texture;
				}
				_MeshRenderer.sharedMaterial = _PreviewMaterial;
			}
			if (_LastSrcRectLeft != rect2)
			{
				_MeshRenderer.sharedMaterial.mainTextureOffset = rect2.position;
				_MeshRenderer.sharedMaterial.mainTextureScale = rect2.size;
			}
			if (_MeshRenderer.sharedMaterial.mainTexture != texture)
			{
				_MeshRenderer.sharedMaterial.mainTexture = texture;
			}
		}
		if ((bool)_MeshFilter)
		{
			_MeshFilter.sharedMesh = _Mesh;
		}
		if ((bool)_MeshCollider)
		{
			_MeshCollider.sharedMesh = _Mesh;
		}
		_LastShape = currentOverlayShape;
		_LastPosition = vector;
		_LastRotation = rotation;
		_LastScale = lossyScale;
		_LastDestRectLeft = rect;
		_LastSrcRectLeft = rect2;
		_LastTextureDimension = textureDimension;
	}

	private void UpdateMesh(OVROverlay.OverlayShape shape, Vector3 position, Quaternion rotation, Vector3 scale, Rect rect, bool cubemap = false)
	{
		_Verts.Clear();
		_UV.Clear();
		_CubeUV.Clear();
		_Tris.Clear();
		GenerateMesh(_Verts, _UV, _CubeUV, _Tris, shape, position, rotation, scale, rect);
		_Mesh.Clear(keepVertexLayout: false);
		_Mesh.SetVertices(_Verts);
		if (cubemap)
		{
			_Mesh.SetUVs(0, _CubeUV);
		}
		else
		{
			_Mesh.SetUVs(0, _UV);
		}
		_Mesh.SetTriangles(_Tris, 0);
		_Mesh.UploadMeshData(markNoLongerReadable: false);
	}

	public static void GenerateMesh(List<Vector3> verts, List<Vector2> uvs, List<Vector4> cubeUVs, List<int> tris, OVROverlay.OverlayShape shape, Vector3 position, Quaternion rotation, Vector3 scale, Rect rect)
	{
		switch (shape)
		{
		case OVROverlay.OverlayShape.Equirect:
			BuildSphere(verts, uvs, tris, position, rotation, scale, rect);
			break;
		case OVROverlay.OverlayShape.Cubemap:
		case OVROverlay.OverlayShape.OffcenterCubemap:
			BuildCube(verts, uvs, cubeUVs, tris, position, rotation, scale);
			break;
		case OVROverlay.OverlayShape.Quad:
			BuildQuad(verts, uvs, tris, rect);
			break;
		case OVROverlay.OverlayShape.Cylinder:
			BuildHemicylinder(verts, uvs, tris, scale, rect);
			break;
		case (OVROverlay.OverlayShape)3:
			break;
		}
	}

	[MethodImpl(MethodImplOptions.AggressiveInlining)]
	private static Vector3 InverseTransformVert(in Vector3 vert, in Vector3 position, in Vector3 scale, float worldScale)
	{
		return new Vector3((worldScale * vert.x - position.x) / scale.x, (worldScale * vert.y - position.y) / scale.y, (worldScale * vert.z - position.z) / scale.z);
	}

	[MethodImpl(MethodImplOptions.AggressiveInlining)]
	private static Vector2 GetSphereUV(float theta, float phi, float expandScale)
	{
		float x = expandScale * (theta / (MathF.PI * 2f) - 0.5f) + 0.5f;
		float y = expandScale * phi / MathF.PI + 0.5f;
		return new Vector2(x, y);
	}

	[MethodImpl(MethodImplOptions.AggressiveInlining)]
	private static Vector3 GetSphereVert(float theta, float phi)
	{
		return new Vector3((0f - Mathf.Sin(theta)) * Mathf.Cos(phi), Mathf.Sin(phi), (0f - Mathf.Cos(theta)) * Mathf.Cos(phi));
	}

	public static void BuildSphere(List<Vector3> verts, List<Vector2> uv, List<int> triangles, Vector3 position, Quaternion rotation, Vector3 scale, Rect rect, float worldScale = 800f, int latitudes = 128, int longitudes = 128, float expandCoefficient = 1f)
	{
		position = Quaternion.Inverse(rotation) * position;
		latitudes = Mathf.CeilToInt((float)latitudes * rect.height);
		longitudes = Mathf.CeilToInt((float)longitudes * rect.width);
		float num = MathF.PI * 2f * rect.x;
		float num2 = MathF.PI * (0.5f - rect.y - rect.height);
		float num3 = MathF.PI * 2f * rect.width / (float)longitudes;
		float num4 = MathF.PI * rect.height / (float)latitudes;
		float expandScale = 1f / expandCoefficient;
		for (int i = 0; i < latitudes + 1; i++)
		{
			for (int j = 0; j < longitudes + 1; j++)
			{
				float theta = num + (float)j * num3;
				float phi = num2 + (float)i * num4;
				Vector2 sphereUV = GetSphereUV(theta, phi, expandScale);
				uv.Add(new Vector2((sphereUV.x - rect.x) / rect.width, (sphereUV.y - rect.y) / rect.height));
				verts.Add(InverseTransformVert(GetSphereVert(theta, phi), in position, in scale, worldScale));
			}
		}
		for (int k = 0; k < latitudes; k++)
		{
			for (int l = 0; l < longitudes; l++)
			{
				triangles.Add(k * (longitudes + 1) + l);
				triangles.Add((k + 1) * (longitudes + 1) + l);
				triangles.Add((k + 1) * (longitudes + 1) + l + 1);
				triangles.Add((k + 1) * (longitudes + 1) + l + 1);
				triangles.Add(k * (longitudes + 1) + l + 1);
				triangles.Add(k * (longitudes + 1) + l);
			}
		}
	}

	[MethodImpl(MethodImplOptions.AggressiveInlining)]
	private static Vector2 GetCubeUV(CubeFace face, float sideU, float sideV, float expandScale, float expandOffset)
	{
		sideU = sideU * expandScale + expandOffset;
		sideV = sideV * expandScale + expandOffset;
		return face switch
		{
			CubeFace.Bottom => new Vector2(sideU / 3f, sideV / 2f), 
			CubeFace.Front => new Vector2((1f + sideU) / 3f, sideV / 2f), 
			CubeFace.Back => new Vector2((2f + sideU) / 3f, sideV / 2f), 
			CubeFace.Right => new Vector2(sideU / 3f, (1f + sideV) / 2f), 
			CubeFace.Left => new Vector2((1f + sideU) / 3f, (1f + sideV) / 2f), 
			CubeFace.Top => new Vector2((2f + sideU) / 3f, (1f + sideV) / 2f), 
			_ => Vector2.zero, 
		};
	}

	[MethodImpl(MethodImplOptions.AggressiveInlining)]
	private static Vector3 GetCubeVert(CubeFace face, float sideU, float sideV)
	{
		return face switch
		{
			CubeFace.Bottom => new Vector3(0.5f - sideU, -0.5f, 0.5f - sideV), 
			CubeFace.Front => new Vector3(0.5f - sideU, -0.5f + sideV, -0.5f), 
			CubeFace.Back => new Vector3(-0.5f + sideU, -0.5f + sideV, 0.5f), 
			CubeFace.Right => new Vector3(-0.5f, -0.5f + sideV, -0.5f + sideU), 
			CubeFace.Left => new Vector3(0.5f, -0.5f + sideV, 0.5f - sideU), 
			CubeFace.Top => new Vector3(0.5f - sideU, 0.5f, -0.5f + sideV), 
			_ => Vector3.zero, 
		};
	}

	public static void BuildCube(List<Vector3> verts, List<Vector2> uv, List<Vector4> cubeUV, List<int> triangles, Vector3 position, Quaternion rotation, Vector3 scale, float worldScale = 800f, int subQuads = 1, float expandCoefficient = 1.01f)
	{
		position = Quaternion.Inverse(rotation) * position;
		int num = (subQuads + 1) * (subQuads + 1);
		float expandScale = 1f / expandCoefficient;
		float expandOffset = 0.5f - 0.5f / expandCoefficient;
		for (int i = 0; i < 6; i++)
		{
			for (int j = 0; j < subQuads + 1; j++)
			{
				for (int k = 0; k < subQuads + 1; k++)
				{
					float sideU = (float)j / (float)subQuads;
					float sideV = (float)k / (float)subQuads;
					uv.Add(GetCubeUV((CubeFace)i, sideU, sideV, expandScale, expandOffset));
					Vector3 vert = GetCubeVert((CubeFace)i, sideU, sideV);
					verts.Add(InverseTransformVert(in vert, in position, in scale, worldScale));
					cubeUV.Add(vert.normalized);
				}
			}
			for (int l = 0; l < subQuads; l++)
			{
				for (int m = 0; m < subQuads; m++)
				{
					triangles.Add(num * i + (l + 1) * (subQuads + 1) + m);
					triangles.Add(num * i + l * (subQuads + 1) + m);
					triangles.Add(num * i + (l + 1) * (subQuads + 1) + m + 1);
					triangles.Add(num * i + (l + 1) * (subQuads + 1) + m + 1);
					triangles.Add(num * i + l * (subQuads + 1) + m);
					triangles.Add(num * i + l * (subQuads + 1) + m + 1);
				}
			}
		}
	}

	public static void BuildQuad(List<Vector3> verts, List<Vector2> uv, List<int> triangles, Rect rect)
	{
		verts.Add(new Vector3(rect.x - 0.5f, 1f - rect.y - rect.height - 0.5f, 0f));
		verts.Add(new Vector3(rect.x - 0.5f, 1f - rect.y - 0.5f, 0f));
		verts.Add(new Vector3(rect.x + rect.width - 0.5f, 1f - rect.y - 0.5f, 0f));
		verts.Add(new Vector3(rect.x + rect.width - 0.5f, 1f - rect.y - rect.height - 0.5f, 0f));
		uv.Add(new Vector2(0f, 0f));
		uv.Add(new Vector2(0f, 1f));
		uv.Add(new Vector2(1f, 1f));
		uv.Add(new Vector2(1f, 0f));
		triangles.Add(0);
		triangles.Add(1);
		triangles.Add(2);
		triangles.Add(2);
		triangles.Add(3);
		triangles.Add(0);
	}

	public static void BuildHemicylinder(List<Vector3> verts, List<Vector2> uv, List<int> triangles, Vector3 scale, Rect rect, int longitudes = 128)
	{
		float num = Mathf.Abs(scale.y) * rect.height;
		float z = scale.z;
		float num2 = scale.x * rect.width;
		float num3 = num2 / z;
		float num4 = scale.x * (-0.5f + rect.x) / z;
		int num5 = Mathf.CeilToInt((float)longitudes * num3 / (MathF.PI * 2f));
		float num6 = num2 / (float)num5;
		int num7 = Mathf.CeilToInt(num / num6 / 2f);
		for (int i = 0; i < num7 + 1; i++)
		{
			for (int j = 0; j < num5 + 1; j++)
			{
				uv.Add(new Vector2((float)j / (float)num5, 1f - (float)i / (float)num7));
				verts.Add(new Vector3(Mathf.Sin(num4 + (float)j * num3 / (float)num5) * z / scale.x, 0.5f - rect.y - rect.height + rect.height * (1f - (float)i / (float)num7), Mathf.Cos(num4 + (float)j * num3 / (float)num5) * z / scale.z));
			}
		}
		for (int k = 0; k < num7; k++)
		{
			for (int l = 0; l < num5; l++)
			{
				triangles.Add(k * (num5 + 1) + l);
				triangles.Add((k + 1) * (num5 + 1) + l + 1);
				triangles.Add((k + 1) * (num5 + 1) + l);
				triangles.Add((k + 1) * (num5 + 1) + l + 1);
				triangles.Add(k * (num5 + 1) + l);
				triangles.Add(k * (num5 + 1) + l + 1);
			}
		}
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-passthrough-gs/")]
[Feature(Feature.Passthrough)]
public class OVRPassthroughLayer : MonoBehaviour
{
	public enum ProjectionSurfaceType
	{
		Reconstructed,
		UserDefined
	}

	public enum ColorMapEditorType
	{
		None = 0,
		GrayscaleToColor = 1,
		Controls = 1,
		Custom = 2,
		Grayscale = 3,
		ColorAdjustment = 4,
		ColorLut = 5,
		InterpolatedColorLut = 6
	}

	private struct Settings(Texture2D colorLutTargetTexture, Texture2D colorLutSourceTexture, float saturation, float posterize, float brightness, float contrast, Gradient gradient, float lutWeight, bool flipLutY)
	{
		public Texture2D colorLutTargetTexture = colorLutTargetTexture;

		public Texture2D colorLutSourceTexture = colorLutSourceTexture;

		public float saturation = saturation;

		public float posterize = posterize;

		public float brightness = brightness;

		public float contrast = contrast;

		public Gradient gradient = gradient;

		public float lutWeight = lutWeight;

		public bool flipLutY = flipLutY;
	}

	private struct PassthroughMeshInstance
	{
		public ulong meshHandle;

		public ulong instanceHandle;

		public bool updateTransform;

		public Matrix4x4 localToWorld;
	}

	[Serializable]
	internal struct SerializedSurfaceGeometry
	{
		public MeshFilter meshFilter;

		public bool updateTransform;
	}

	private struct DeferredPassthroughMeshAddition
	{
		public GameObject gameObject;

		public bool updateTransform;
	}

	private interface IStyleHandler
	{
		bool IsValid { get; }

		void ApplyStyleSettings(ref OVRPlugin.InsightPassthroughStyle2 style);

		void Update(Settings settings);

		void Clear();
	}

	private class StylesHandler
	{
		private NoneStyleHandler _noneHandler;

		private ColorLutHandler _lutHandler;

		private InterpolatedColorLutHandler _interpolatedLutHandler;

		private MonoToRgbaStyleHandler _monoToRgbaHandler;

		private MonoToMonoStyleHandler _monoToMonoHandler;

		private BCSStyleHandler _bcsHandler;

		private GCHandle _colorMapDataHandle;

		private byte[] _colorMapData;

		public IStyleHandler CurrentStyleHandler;

		public StylesHandler()
		{
			_noneHandler = new NoneStyleHandler();
			_lutHandler = new ColorLutHandler();
			_interpolatedLutHandler = new InterpolatedColorLutHandler();
			_monoToMonoHandler = new MonoToMonoStyleHandler(ref _colorMapDataHandle, _colorMapData);
			_monoToRgbaHandler = new MonoToRgbaStyleHandler(ref _colorMapDataHandle, _colorMapData);
			_bcsHandler = new BCSStyleHandler(ref _colorMapDataHandle, _colorMapData);
		}

		public void SetStyleHandler(OVRPlugin.InsightPassthroughColorMapType type)
		{
			IStyleHandler styleHandler = GetStyleHandler(type);
			if (styleHandler != CurrentStyleHandler)
			{
				if (CurrentStyleHandler != null)
				{
					CurrentStyleHandler.Clear();
				}
				CurrentStyleHandler = styleHandler;
			}
		}

		private IStyleHandler GetStyleHandler(OVRPlugin.InsightPassthroughColorMapType type)
		{
			return type switch
			{
				OVRPlugin.InsightPassthroughColorMapType.None => _noneHandler, 
				OVRPlugin.InsightPassthroughColorMapType.MonoToRgba => _monoToRgbaHandler, 
				OVRPlugin.InsightPassthroughColorMapType.MonoToMono => _monoToMonoHandler, 
				OVRPlugin.InsightPassthroughColorMapType.BrightnessContrastSaturation => _bcsHandler, 
				OVRPlugin.InsightPassthroughColorMapType.ColorLut => _lutHandler, 
				OVRPlugin.InsightPassthroughColorMapType.InterpolatedColorLut => _interpolatedLutHandler, 
				_ => throw new ArgumentException($"Unrecognized color map type {type}."), 
			};
		}

		public void SetColorLutHandler(OVRPassthroughColorLut lut, float weight)
		{
			SetStyleHandler(OVRPlugin.InsightPassthroughColorMapType.ColorLut);
			_lutHandler.Update(lut, weight);
		}

		internal void SetInterpolatedColorLutHandler(OVRPassthroughColorLut lutSource, OVRPassthroughColorLut lutTarget, float weight)
		{
			SetStyleHandler(OVRPlugin.InsightPassthroughColorMapType.InterpolatedColorLut);
			_interpolatedLutHandler.Update(lutSource, lutTarget, weight);
		}

		internal void SetMonoToRgbaHandler(Color[] values)
		{
			SetStyleHandler(OVRPlugin.InsightPassthroughColorMapType.MonoToRgba);
			_monoToRgbaHandler.Update(values);
		}

		internal void SetMonoToMonoHandler(byte[] values)
		{
			SetStyleHandler(OVRPlugin.InsightPassthroughColorMapType.MonoToMono);
			_monoToMonoHandler.Update(values);
		}
	}

	private class NoneStyleHandler : IStyleHandler
	{
		public bool IsValid => true;

		public void ApplyStyleSettings(ref OVRPlugin.InsightPassthroughStyle2 style)
		{
		}

		public void Update(Settings settings)
		{
		}

		public void Clear()
		{
		}
	}

	private abstract class BaseGeneratedStyleHandler : IStyleHandler
	{
		private GCHandle _colorMapDataHandle;

		protected byte[] _colorMapData;

		protected abstract uint MapSize { get; }

		public bool IsValid => true;

		public BaseGeneratedStyleHandler(ref GCHandle colorMapDataHandler, byte[] colorMapData)
		{
			_colorMapDataHandle = colorMapDataHandler;
			_colorMapData = colorMapData;
		}

		public virtual void Update(Settings settings)
		{
		}

		public virtual void ApplyStyleSettings(ref OVRPlugin.InsightPassthroughStyle2 style)
		{
			style.TextureColorMapData = _colorMapDataHandle.AddrOfPinnedObject();
			style.TextureColorMapDataSize = MapSize;
			style.TextureColorMapData = _colorMapDataHandle.AddrOfPinnedObject();
			style.TextureColorMapDataSize = MapSize;
		}

		public void Clear()
		{
			DeallocateColorMapData();
		}

		protected virtual void AllocateColorMapData(uint size = 4096u)
		{
			if (_colorMapData != null && size != _colorMapData.Length)
			{
				DeallocateColorMapData();
			}
			if (_colorMapData == null)
			{
				_colorMapData = new byte[size];
				_colorMapDataHandle = GCHandle.Alloc(_colorMapData, GCHandleType.Pinned);
			}
		}

		protected virtual void DeallocateColorMapData()
		{
			if (_colorMapData != null)
			{
				_colorMapDataHandle.Free();
				_colorMapData = null;
			}
		}

		protected void WriteColorToColorMap(int colorIndex, ref Color color)
		{
			for (int i = 0; i < 4; i++)
			{
				Buffer.BlockCopy(BitConverter.GetBytes(color[i]), 0, _colorMapData, colorIndex * 16 + i * 4, 4);
			}
		}

		protected void WriteFloatToColorMap(int index, float value)
		{
			Buffer.BlockCopy(BitConverter.GetBytes(value), 0, _colorMapData, index * 4, 4);
		}

		protected static void ComputeBrightnessContrastPosterizeMap(byte[] result, float brightness, float contrast, float posterize)
		{
			for (int i = 0; i < 256; i++)
			{
				float num = (float)i / 255f;
				float num2 = contrast + 1f;
				num = (num - 0.5f) * num2 + 0.5f + brightness;
				if (posterize > 0f)
				{
					float num3 = (Mathf.Pow(50f, posterize) - 1f) / 49f;
					num = Mathf.Round(num / num3) * num3;
				}
				result[i] = (byte)(Mathf.Min(Mathf.Max(num, 0f), 1f) * 255f);
			}
		}
	}

	private class MonoToRgbaStyleHandler : BaseGeneratedStyleHandler
	{
		protected byte[] _tmpColorMapData;

		protected override uint MapSize => 4096u;

		public MonoToRgbaStyleHandler(ref GCHandle colorMapDataHandler, byte[] colorMapData)
			: base(ref colorMapDataHandler, colorMapData)
		{
		}

		public override void Update(Settings settings)
		{
			AllocateColorMapData();
			BaseGeneratedStyleHandler.ComputeBrightnessContrastPosterizeMap(_tmpColorMapData, settings.brightness, settings.contrast, settings.posterize);
			for (int i = 0; i < 256; i++)
			{
				Color color = settings.gradient.Evaluate((float)(int)_tmpColorMapData[i] / 255f);
				WriteColorToColorMap(i, ref color);
			}
		}

		public void Update(Color[] values)
		{
			AllocateColorMapData();
			for (int i = 0; i < 256; i++)
			{
				WriteColorToColorMap(i, ref values[i]);
			}
		}

		protected override void AllocateColorMapData(uint size = 4096u)
		{
			base.AllocateColorMapData(size);
			_tmpColorMapData = new byte[256];
		}

		protected override void DeallocateColorMapData()
		{
			base.DeallocateColorMapData();
			_tmpColorMapData = null;
		}
	}

	private class MonoToMonoStyleHandler : BaseGeneratedStyleHandler
	{
		protected override uint MapSize => 256u;

		public MonoToMonoStyleHandler(ref GCHandle colorMapDataHandler, byte[] colorMapData)
			: base(ref colorMapDataHandler, colorMapData)
		{
		}

		public override void Update(Settings settings)
		{
			AllocateColorMapData();
			BaseGeneratedStyleHandler.ComputeBrightnessContrastPosterizeMap(_colorMapData, settings.brightness, settings.contrast, settings.posterize);
		}

		public void Update(byte[] values)
		{
			AllocateColorMapData();
			Buffer.BlockCopy(values, 0, _colorMapData, 0, 256);
		}
	}

	private class BCSStyleHandler : BaseGeneratedStyleHandler
	{
		protected override uint MapSize => 12u;

		public BCSStyleHandler(ref GCHandle colorMapDataHandler, byte[] colorMapData)
			: base(ref colorMapDataHandler, colorMapData)
		{
		}

		public override void Update(Settings settings)
		{
			AllocateColorMapData();
			WriteFloatToColorMap(0, settings.brightness * 100f);
			WriteFloatToColorMap(1, settings.contrast + 1f);
			WriteFloatToColorMap(2, settings.saturation + 1f);
		}
	}

	private class ColorLutHandler : IStyleHandler
	{
		protected bool _currentFlipLutY;

		protected Texture2D _currentColorLutSourceTexture;

		public OVRPassthroughColorLut Lut { get; set; }

		public float Weight { get; set; }

		public bool IsValid { get; protected set; }

		public virtual void ApplyStyleSettings(ref OVRPlugin.InsightPassthroughStyle2 style)
		{
			style.LutSource = Lut._colorLutHandle;
			style.LutWeight = Weight;
		}

		public virtual void Update(Settings settings)
		{
			Update(GetColorLutForTexture(settings.colorLutSourceTexture, Lut, ref _currentColorLutSourceTexture, settings.flipLutY), settings.lutWeight);
		}

		protected OVRPassthroughColorLut GetColorLutForTexture(Texture2D newTexture, OVRPassthroughColorLut lut, ref Texture2D lastTexture, bool flipY)
		{
			if (newTexture == null)
			{
				UnityEngine.Debug.LogError("Trying to update style with null texture.");
				return null;
			}
			if (lastTexture != newTexture || _currentFlipLutY != flipY)
			{
				lut?.Dispose();
				lastTexture = newTexture;
				_currentFlipLutY = flipY;
				return new OVRPassthroughColorLut(newTexture, _currentFlipLutY);
			}
			return lut;
		}

		internal void Update(OVRPassthroughColorLut lut, float weight)
		{
			if (lut == null)
			{
				IsValid = false;
				return;
			}
			IsValid = true;
			Lut = lut;
			Weight = weight;
		}

		public virtual void Clear()
		{
			Lut = null;
			_currentColorLutSourceTexture = null;
		}
	}

	private class InterpolatedColorLutHandler : ColorLutHandler
	{
		private Texture2D _currentColorLutTargetTexture;

		public OVRPassthroughColorLut LutTarget { get; set; }

		public override void ApplyStyleSettings(ref OVRPlugin.InsightPassthroughStyle2 style)
		{
			base.ApplyStyleSettings(ref style);
			style.LutTarget = LutTarget._colorLutHandle;
		}

		public override void Update(Settings settings)
		{
			Update(GetColorLutForTexture(settings.colorLutSourceTexture, base.Lut, ref _currentColorLutSourceTexture, settings.flipLutY), GetColorLutForTexture(settings.colorLutTargetTexture, LutTarget, ref _currentColorLutTargetTexture, settings.flipLutY), settings.lutWeight);
		}

		public void Update(OVRPassthroughColorLut lutSource, OVRPassthroughColorLut lutTarget, float weight)
		{
			if (lutSource == null || lutTarget == null)
			{
				base.IsValid = false;
				return;
			}
			base.IsValid = true;
			base.Lut = lutSource;
			LutTarget = lutTarget;
			base.Weight = weight;
		}

		public override void Clear()
		{
			base.Clear();
			LutTarget = null;
			_currentColorLutTargetTexture = null;
		}
	}

