	public struct Sizei : IEquatable<Sizei>
	{
		public int w;

		public int h;

		public static readonly Sizei zero = new Sizei
		{
			w = 0,
			h = 0
		};

		public bool Equals(Sizei other)
		{
			if (w == other.w)
			{
				return h == other.h;
			}
			return false;
		}

		public override bool Equals(object obj)
		{
			if (obj is Sizei other)
			{
				return Equals(other);
			}
			return false;
		}

		public override int GetHashCode()
		{
			return (w * 397) ^ h;
		}
	}

