		{
			if (version >= OVRP_1_38_0.version)
			{
				if (OVRP_1_38_0.ovrp_Media_GetMrcActivationMode(out var activationMode) == Result.Success)
				{
					return activationMode;
				}
				return MrcActivationMode.Automatic;
			}
			return MrcActivationMode.Automatic;
		}

