public class OVRSceneObjectTransformType : MonoBehaviour
{
	[Serializable]
	public enum Transformation
	{
		Volume,
		Plane,
		None
	}

	[Tooltip("Choose the type of scene anchor (volume/plane) that may modify this transform.")]
