[DisallowMultipleComponent]
[RequireComponent(typeof(OVRSceneAnchor))]
[HelpURL("https://developer.oculus.com/documentation/unity/unity-scene-use-scene-anchors/#further-scene-model-unity-components")]
[Obsolete("OVRSceneManager and associated classes are deprecated (v65), please use MR Utility Kit instead (https://developer.oculus.com/documentation/unity/unity-mr-utility-kit-overview)")]
[Feature(Feature.Scene)]
public class OVRScenePlane : MonoBehaviour, IOVRSceneComponent
{
	private struct GetBoundaryLengthJob : IJob
	{
		public OVRSpace Space;

		[WriteOnly]
		public NativeArray<int> Length;

		public void Execute()
		{
			Length[0] = (OVRPlugin.GetSpaceBoundary2DCount(Space, out var count) ? count : 0);
		}
	}

	private struct GetBoundaryJob : IJob
	{
		public OVRSpace Space;

		public NativeArray<Vector2> Boundary;

		public NativeArray<Vector2> PreviousBoundary;

		private bool HasBoundaryChanged()
		{
			if (!PreviousBoundary.IsCreated)
			{
				return true;
			}
			if (Boundary.Length != PreviousBoundary.Length)
			{
				return true;
			}
			int length = Boundary.Length;
			for (int i = 0; i < length; i++)
			{
				if (Vector2.SqrMagnitude(Boundary[i] - PreviousBoundary[i]) > 1E-06f)
				{
					return true;
				}
			}
			return false;
		}

		private static void SetNaN(NativeArray<Vector2> array)
		{
			if (array.Length > 0)
			{
				array[0] = new Vector2(float.NaN, float.NaN);
			}
		}

		public void Execute()
		{
			if (OVRPlugin.GetSpaceBoundary2D(Space, Boundary) && HasBoundaryChanged())
			{
				SetNaN(PreviousBoundary);
			}
			else
			{
				SetNaN(Boundary);
			}
		}
	}

	[Tooltip("When enabled, scales the child transforms according to the dimensions of this plane. If both Volume and Plane components exist on the game object, the volume takes precedence.")]
	[SerializeField]
	internal bool _scaleChildren = true;

	[Tooltip("When enabled, offsets the child transforms according to the offset of this plane. If both Volume and Plane components exist on the game object, the volume takes precedence.")]
	[SerializeField]
	internal bool _offsetChildren = true;

	internal JobHandle? _jobHandle;

	private NativeArray<Vector2> _previousBoundary;

	private NativeArray<int> _boundaryLength;

	private NativeArray<Vector2> _boundaryBuffer;

	private bool _boundaryRequested;

	private OVRSceneAnchor _sceneAnchor;

	private readonly List<Vector2> _boundary = new List<Vector2>();

	public float Width { get; private set; }

	public float Height { get; private set; }

	public Vector2 Offset { get; private set; }

	public Vector2 Dimensions => new Vector2(Width, Height);

	public IReadOnlyList<Vector2> Boundary => _boundary;

	public bool ScaleChildren
	{
		get
		{
			return _scaleChildren;
		}
		set
		{
			_scaleChildren = value;
			if (_scaleChildren && _sceneAnchor.Space.Valid)
			{
				SetChildScale();
			}
		}
	}

	public bool OffsetChildren
	{
		get
		{
			return _offsetChildren;
		}
		set
		{
			_offsetChildren = value;
			if (_offsetChildren && _sceneAnchor.Space.Valid)
			{
				SetChildOffset();
			}
		}
	}

	private void SetChildScale()
	{
		OVRSceneVolume component;
		bool flag = TryGetComponent<OVRSceneVolume>(out component);
		for (int i = 0; i < base.transform.childCount; i++)
		{
			Transform child = base.transform.GetChild(i);
			if (child.TryGetComponent<OVRSceneObjectTransformType>(out var component2))
			{
				if (component2.TransformType != OVRSceneObjectTransformType.Transformation.Plane)
				{
					continue;
				}
			}
			else if (flag && component.ScaleChildren)
			{
				continue;
			}
			child.localScale = new Vector3(Width, Height, child.localScale.z);
		}
	}

	private void SetChildOffset()
	{
		OVRSceneVolume component;
		bool flag = TryGetComponent<OVRSceneVolume>(out component);
		for (int i = 0; i < base.transform.childCount; i++)
		{
			Transform child = base.transform.GetChild(i);
			if (child.TryGetComponent<OVRSceneObjectTransformType>(out var component2))
			{
				if (component2.TransformType != OVRSceneObjectTransformType.Transformation.Plane)
				{
					continue;
				}
			}
			else if (flag && component.OffsetChildren)
			{
				continue;
			}
			child.localPosition = new Vector3(Offset.x, Offset.y, 0f);
		}
	}

	internal void UpdateTransform()
	{
		if (OVRPlugin.GetSpaceBoundingBox2D(GetComponent<OVRSceneAnchor>().Space, out var rect))
		{
			Width = rect.Size.w;
			Height = rect.Size.h;
			Vector2 vector = base.transform.TransformPoint(rect.Pos.FromVector2f() + rect.Size.FromSizef() / 2f);
			Vector2 vector2 = new Vector2(base.transform.position.x, base.transform.position.y);
			Offset = vector - vector2;
			if (ScaleChildren)
			{
				SetChildScale();
			}
			if (OffsetChildren)
			{
				SetChildOffset();
			}
		}
	}

	private void Awake()
	{
		_sceneAnchor = GetComponent<OVRSceneAnchor>();
		if (_sceneAnchor.Space.Valid)
		{
			((IOVRSceneComponent)this).Initialize();
		}
	}

	private void Start()
	{
		RequestBoundary();
	}

	void IOVRSceneComponent.Initialize()
	{
		UpdateTransform();
	}

	internal void ScheduleGetLengthJob()
	{
		if (!_jobHandle.HasValue && OVRPlugin.GetSpaceComponentStatus(_sceneAnchor.Space, OVRPlugin.SpaceComponentType.Bounded2D, out var flag, out var changePending) && !(!flag || changePending))
		{
			_boundaryLength = new NativeArray<int>(1, Allocator.TempJob);
			_jobHandle = new GetBoundaryLengthJob
			{
				Length = _boundaryLength,
				Space = _sceneAnchor.Space
			}.Schedule();
			_boundaryRequested = false;
		}
	}

	internal void RequestBoundary()
	{
		_boundaryRequested = true;
		if (base.enabled)
		{
			ScheduleGetLengthJob();
		}
	}

	private void Update()
	{
		ref JobHandle? jobHandle = ref _jobHandle;
		if (!jobHandle.HasValue || !jobHandle.GetValueOrDefault().IsCompleted)
		{
			return;
		}
		_jobHandle.Value.Complete();
		_jobHandle = null;
		if (_boundaryLength.IsCreated)
		{
			int num = _boundaryLength[0];
			_boundaryLength.Dispose();
			if (num >= 3)
			{
				using (new OVRProfilerScope("Schedule GetBoundaryJob"))
				{
					_boundaryBuffer = new NativeArray<Vector2>(num, Allocator.TempJob);
					if (!_previousBoundary.IsCreated)
					{
						_previousBoundary = new NativeArray<Vector2>(num, Allocator.Persistent);
					}
					_jobHandle = new GetBoundaryJob
					{
						Space = _sceneAnchor.Space,
						Boundary = _boundaryBuffer,
						PreviousBoundary = _previousBoundary
					}.Schedule();
					return;
				}
			}
			ScheduleGetLengthJob();
		}
		else if (_boundaryBuffer.IsCreated)
		{
			using (new OVRProfilerScope("Copy boundary"))
			{
				if (_previousBoundary.Length == 0 || float.IsNaN(_previousBoundary[0].x))
				{
					if (_previousBoundary.IsCreated)
					{
						_previousBoundary.Dispose();
					}
					_previousBoundary = new NativeArray<Vector2>(_boundaryBuffer.Length, Allocator.Persistent, NativeArrayOptions.UninitializedMemory);
					_previousBoundary.CopyFrom(_boundaryBuffer);
					_boundary.Clear();
					foreach (Vector2 item in _previousBoundary)
					{
						_boundary.Add(new Vector2(0f - item.x, item.y));
					}
				}
			}
			_boundaryBuffer.Dispose();
			if (TryGetComponent<OVRScenePlaneMeshFilter>(out var component))
			{
				component.RequestMeshGeneration();
			}
		}
		else if (_boundaryRequested)
		{
			ScheduleGetLengthJob();
		}
	}

	private void OnDisable()
	{
		if (_boundaryLength.IsCreated)
		{
			_boundaryLength.Dispose(_jobHandle.GetValueOrDefault());
		}
		if (_boundaryBuffer.IsCreated)
		{
			_boundaryBuffer.Dispose(_jobHandle.GetValueOrDefault());
		}
		if (_previousBoundary.IsCreated)
		{
			_previousBoundary.Dispose(_jobHandle.GetValueOrDefault());
		}
		_previousBoundary = default(NativeArray<Vector2>);
		_boundaryBuffer = default(NativeArray<Vector2>);
		_boundaryLength = default(NativeArray<int>);
		_jobHandle = null;
	}
}
[RequireComponent(typeof(MeshFilter))]
[HelpURL("https://developer.oculus.com/documentation/unity/unity-scene-use-scene-anchors/#further-scene-model-unity-components")]
[Obsolete("OVRSceneManager and associated classes are deprecated (v65), please use MR Utility Kit instead (https://developer.oculus.com/documentation/unity/unity-mr-utility-kit-overview)")]
[Feature(Feature.Scene)]
public class OVRScenePlaneMeshFilter : MonoBehaviour
{
	private struct TriangulateBoundaryJob : IJob
	{
		private struct NList : IDisposable
		{
			private NativeArray<int> _data;

			public int Count { get; private set; }

			public int this[int index] => _data[index];

			public NList(int capacity, Allocator allocator)
			{
				Count = capacity;
				_data = new NativeArray<int>(capacity, allocator);
				for (int i = 0; i < capacity; i++)
				{
					_data[i] = i;
				}
			}

			public void RemoveAt(int index)
			{
				int count = Count - 1;
				Count = count;
				for (int i = index; i < Count; i++)
				{
					_data[i] = _data[i + 1];
				}
			}

			public int GetAt(int index)
			{
				if (index >= Count)
				{
					return _data[index % Count];
				}
				if (index < 0)
				{
					return _data[index % Count + Count];
				}
				return _data[index];
			}

			public void Dispose()
			{
				_data.Dispose();
			}
		}

		[Unity.Collections.ReadOnly]
		public NativeArray<Vector2> Boundary;

		[WriteOnly]
		public NativeArray<int> Triangles;

		public void Execute()
		{
			if (Boundary.Length == 0 || float.IsNaN(Boundary[0].x))
			{
				return;
			}
			NList nList = new NList(Boundary.Length, Allocator.Temp);
			using (nList)
			{
				bool flag = true;
				int index = 0;
				while (nList.Count > 3)
				{
					if (!flag)
					{
						UnityEngine.Debug.LogError("[OVRScenePlaneMeshFilter] Plane boundary triangulation failed.");
						Triangles[0] = 0;
						Triangles[1] = 0;
						Triangles[2] = 0;
						return;
					}
					flag = false;
					for (int i = 0; i < nList.Count; i++)
					{
						int num = nList[i];
						int at = nList.GetAt(i - 1);
						int at2 = nList.GetAt(i + 1);
						Vector2 vector = Boundary[num];
						Vector2 vector2 = Boundary[at];
						Vector2 vector3 = Boundary[at2];
						Vector2 a = vector2 - vector;
						Vector2 b = vector3 - vector;
						if (Cross(a, b) < 0f)
						{
							continue;
						}
						bool flag2 = true;
						for (int j = 0; j < Boundary.Length; j++)
						{
							if (j != num && j != at && j != at2 && PointInTriangle(Boundary[j], vector, vector2, vector3))
							{
								flag2 = false;
								break;
							}
						}
						if (flag2)
						{
							Triangles[index++] = at2;
							Triangles[index++] = num;
							Triangles[index++] = at;
							nList.RemoveAt(i);
							flag = true;
							break;
						}
					}
				}
				Triangles[index++] = nList[2];
				Triangles[index++] = nList[1];
				Triangles[index] = nList[0];
			}
		}

		private static float Cross(Vector2 a, Vector2 b)
		{
			return a.x * b.y - a.y * b.x;
		}

		private static bool PointInTriangle(Vector2 p, Vector2 a, Vector2 b, Vector2 c)
		{
			if (Cross(b - a, p - a) >= 0f && Cross(c - b, p - b) >= 0f)
			{
				return Cross(a - c, p - c) >= 0f;
			}
			return false;
		}
	}

	private MeshFilter _meshFilter;

	private Mesh _mesh;

	private JobHandle? _jobHandle;

	private bool _meshRequested;

	private NativeArray<Vector2> _boundary;

	private NativeArray<int> _triangles;

	private void Start()
	{
		_mesh = new Mesh();
		_meshFilter = GetComponent<MeshFilter>();
		_meshFilter.sharedMesh = _mesh;
		OVRSceneAnchor component = GetComponent<OVRSceneAnchor>();
		_mesh.name = (component ? string.Format("{0} {1}", "OVRScenePlaneMeshFilter", component.Uuid) : "OVRScenePlaneMeshFilter (anonymous)");
		RequestMeshGeneration();
	}

	internal void ScheduleMeshGeneration()
	{
		if (_jobHandle.HasValue || !TryGetComponent<OVRScenePlane>(out var component) || component.Boundary.Count < 3)
		{
			return;
		}
		using (new OVRProfilerScope("ScheduleMeshGeneration"))
		{
			int count = component.Boundary.Count;
			using (new OVRProfilerScope("Copy boundary"))
			{
				_boundary = new NativeArray<Vector2>(count, Allocator.TempJob, NativeArrayOptions.UninitializedMemory);
				for (int i = 0; i < component.Boundary.Count; i++)
				{
					_boundary[i] = component.Boundary[i];
				}
			}
			using (new OVRProfilerScope("Schedule TriangulateBoundaryJob"))
			{
				_triangles = new NativeArray<int>((count - 2) * 3, Allocator.TempJob);
				_jobHandle = new TriangulateBoundaryJob
				{
					Boundary = _boundary,
					Triangles = _triangles
				}.Schedule();
			}
		}
	}

	private void Update()
	{
		ref JobHandle? jobHandle = ref _jobHandle;
		if (!jobHandle.HasValue || !jobHandle.GetValueOrDefault().IsCompleted)
		{
			return;
		}
		_jobHandle.Value.Complete();
		_jobHandle = null;
		if (_boundary.IsCreated && _triangles.IsCreated)
		{
			try
			{
				if (_triangles[0] == 0 && _triangles[1] == 0 && _triangles[2] == 0)
				{
					return;
				}
				using (new OVRProfilerScope("Update mesh"))
				{
					NativeArray<Vector3> nativeArray = new NativeArray<Vector3>(_boundary.Length, Allocator.Temp, NativeArrayOptions.UninitializedMemory);
					NativeArray<Vector3> nativeArray2 = new NativeArray<Vector3>(_boundary.Length, Allocator.Temp, NativeArrayOptions.UninitializedMemory);
					NativeArray<Vector2> nativeArray3 = new NativeArray<Vector2>(_boundary.Length, Allocator.Temp, NativeArrayOptions.UninitializedMemory);
					using (new OVRProfilerScope("Prepare mesh data"))
					{
						for (int i = 0; i < _boundary.Length; i++)
						{
							Vector2 vector = _boundary[i];
							nativeArray[i] = new Vector3(vector.x, vector.y, 0f);
							nativeArray2[i] = new Vector3(0f, 0f, 1f);
							nativeArray3[i] = new Vector2(vector.x, vector.y);
						}
					}
					using (nativeArray)
					{
						using (nativeArray2)
						{
							using (nativeArray3)
							{
								using (new OVRProfilerScope("Set mesh data"))
								{
									_mesh.Clear();
									_mesh.SetVertices(nativeArray);
									_mesh.SetIndices(_triangles, MeshTopology.Triangles, 0);
									_mesh.SetNormals(nativeArray2);
									_mesh.SetUVs(0, nativeArray3);
									return;
								}
							}
						}
					}
				}
			}
			finally
			{
				_boundary.Dispose();
				_triangles.Dispose();
			}
		}
		if (_meshRequested)
		{
			ScheduleMeshGeneration();
		}
	}

	internal void RequestMeshGeneration()
	{
		_meshRequested = true;
		if (base.enabled)
		{
			ScheduleMeshGeneration();
		}
	}

	private void OnDisable()
	{
		if (_triangles.IsCreated)
		{
			_triangles.Dispose(_jobHandle.GetValueOrDefault());
		}
		_triangles = default(NativeArray<int>);
		_jobHandle = null;
	}
}
[Serializable]
[HelpURL("https://developer.oculus.com/documentation/unity/unity-scene-use-scene-anchors/")]
[Obsolete("OVRSceneManager and associated classes are deprecated (v65), please use MR Utility Kit instead (https://developer.oculus.com/documentation/unity/unity-mr-utility-kit-overview)")]
public class OVRScenePrefabOverride : ISerializationCallbackReceiver
{
	[FormerlySerializedAs("prefab")]
	public OVRSceneAnchor Prefab;

	[FormerlySerializedAs("classificationLabel")]
	public string ClassificationLabel = "";

	[FormerlySerializedAs("editorClassificationIndex")]
	[SerializeField]
	private int _editorClassificationIndex;

	void ISerializationCallbackReceiver.OnBeforeSerialize()
	{
	}

	void ISerializationCallbackReceiver.OnAfterDeserialize()
	{
		UpdateEditorClassificationIndex();
	}

	internal void UpdateEditorClassificationIndex()
	{
		if (ClassificationLabel != "")
		{
			_editorClassificationIndex = IndexOf(ClassificationLabel, OVRSceneManager.Classification.List);
			if (_editorClassificationIndex < 0)
			{
				UnityEngine.Debug.LogError("[OVRScenePrefabOverride] OnAfterDeserialize() " + ClassificationLabel + " not found. The Classification list in OVRSceneManager has likely changed");
			}
		}
		else
		{
			_editorClassificationIndex = 0;
		}
		static int IndexOf(string label, IEnumerable<string> collection)
		{
			int num = 0;
			foreach (string item in collection)
			{
				if (item == label)
				{
					return num;
				}
				num++;
			}
			return -1;
		}
	}
}
[DisallowMultipleComponent]
[RequireComponent(typeof(OVRSceneAnchor))]
[HelpURL("https://developer.oculus.com/documentation/unity/unity-scene-use-scene-anchors/#further-scene-model-unity-components")]
[Obsolete("OVRSceneManager and associated classes are deprecated (v65), please use MR Utility Kit instead (https://developer.oculus.com/documentation/unity/unity-mr-utility-kit-overview)")]
[Feature(Feature.Scene)]
public class OVRSceneRoom : MonoBehaviour, IOVRSceneComponent
{
	private OVRSceneAnchor _sceneAnchor;

	private OVRSceneManager _sceneManager;

	private Guid _uuid;

	internal static readonly Dictionary<Guid, OVRSceneRoom> SceneRooms = new Dictionary<Guid, OVRSceneRoom>();

	internal static readonly List<OVRSceneRoom> SceneRoomsList = new List<OVRSceneRoom>();

	public OVRScenePlane Floor { get; private set; }

	public OVRScenePlane Ceiling { get; private set; }

	public OVRScenePlane[] Walls { get; private set; } = Array.Empty<OVRScenePlane>();

	private void Awake()
	{
		_sceneAnchor = GetComponent<OVRSceneAnchor>();
		_sceneManager = UnityEngine.Object.FindAnyObjectByType<OVRSceneManager>();
		_uuid = _sceneAnchor.Uuid;
		if (_sceneAnchor.Space.Valid)
		{
			((IOVRSceneComponent)this).Initialize();
		}
	}

	void IOVRSceneComponent.Initialize()
	{
		SceneRooms[_uuid] = this;
		SceneRoomsList.Add(this);
	}

	internal async OVRTask<bool> LoadRoom(Guid floor, Guid ceiling, Guid[] walls)
	{
		HashSet<Guid> set;
		using (new OVRObjectPool.HashSetScope<Guid>(out set))
		{
			List<OVRAnchor> anchors;
			using (new OVRObjectPool.ListScope<OVRAnchor>(out anchors))
			{
				set.Add(floor);
				set.Add(ceiling);
				Guid[] array = walls;
				foreach (Guid item in array)
				{
					set.Add(item);
				}
				if (_sceneAnchor.Anchor.TryGetComponent<OVRAnchorContainer>(out var component))
				{
					array = component.Uuids;
					foreach (Guid item2 in array)
					{
						set.Add(item2);
					}
				}
				if (!(await OVRSceneManager.FetchAnchorsAsync(set, anchors)))
				{
					return false;
				}
				List<bool> list;
				using (new OVRObjectPool.ListScope<bool>(out list))
				{
					List<OVRTask<bool>> list2;
					using (new OVRObjectPool.ListScope<OVRTask<bool>>(out list2))
					{
						foreach (OVRAnchor item3 in anchors)
						{
							if (item3.TryGetComponent<OVRLocatable>(out var component2))
							{
								list2.Add(component2.SetEnabledAsync(enabled: true));
							}
						}
						await OVRTask.WhenAll(list2, list);
					}
				}
				foreach (OVRAnchor item4 in anchors)
				{
					if (item4.TryGetComponent<OVRLocatable>(out var component3) && component3.IsEnabled)
					{
						OVRPlugin.GetSpaceComponentStatus(item4.Handle, OVRPlugin.SpaceComponentType.Bounded2D, out var flag, out var changePending);
						OVRPlugin.GetSpaceComponentStatus(item4.Handle, OVRPlugin.SpaceComponentType.Bounded3D, out var flag2, out changePending);
						OVRPlugin.GetSpaceComponentStatus(item4.Handle, OVRPlugin.SpaceComponentType.TriangleMesh, out var flag3, out changePending);
						OVRSceneAnchor prefab = ((flag && !(flag2 || flag3)) ? _sceneManager.PlanePrefab : (flag2 ? _sceneManager.VolumePrefab : null));
						OVRSceneAnchor oVRSceneAnchor = _sceneManager.InstantiateSceneAnchor(item4, prefab);
						if ((bool)oVRSceneAnchor)
						{
							oVRSceneAnchor.transform.parent = base.transform;
							oVRSceneAnchor.IsTracked = true;
						}
					}
				}
				Floor = GetPlane(floor);
				Ceiling = GetPlane(ceiling);
				List<OVRScenePlane> list3;
				using (new OVRObjectPool.ListScope<OVRScenePlane>(out list3))
				{
					array = walls;
					for (int i = 0; i < array.Length; i++)
					{
						if (TryGetPlane(array[i], out var plane))
						{
							list3.Add(plane);
						}
					}
					Walls = list3.ToArray();
				}
			}
		}
		return true;
		static OVRScenePlane GetPlane(Guid uuid)
		{
			if (!TryGetPlane(uuid, out var plane2))
			{
				return null;
			}
			return plane2;
		}
		static bool TryGetPlane(Guid uuid, out OVRScenePlane reference)
		{
			reference = null;
			if (OVRSceneAnchor.SceneAnchors.TryGetValue(uuid, out var value))
			{
				return value.TryGetComponent<OVRScenePlane>(out reference);
			}
			return false;
		}
	}

	private void OnDestroy()
	{
		SceneRooms.Remove(_uuid);
		SceneRoomsList.Remove(this);
	}

	[Conditional("DEVELOPMENT_BUILD")]
	[Conditional("UNITY_EDITOR")]
	private void Log(string message)
	{
		UnityEngine.Debug.Log("[OVRSceneRoom] " + message, base.gameObject);
	}

	[Conditional("DEVELOPMENT_BUILD")]
	[Conditional("UNITY_EDITOR")]
	private void LogWarning(string message)
	{
		UnityEngine.Debug.LogWarning("[OVRSceneRoom] " + message, base.gameObject);
	}

	[Conditional("DEVELOPMENT_BUILD")]
	[Conditional("UNITY_EDITOR")]
	private void LogError(string message)
	{
		UnityEngine.Debug.LogError("[OVRSceneRoom] " + message, base.gameObject);
	}
}
[DisallowMultipleComponent]
[RequireComponent(typeof(OVRSceneAnchor))]
[HelpURL("https://developer.oculus.com/documentation/unity/unity-scene-use-scene-anchors/#further-scene-model-unity-components")]
[Obsolete("OVRSceneManager and associated classes are deprecated (v65), please use MR Utility Kit instead (https://developer.oculus.com/documentation/unity/unity-mr-utility-kit-overview)")]
[Feature(Feature.Scene)]
public class OVRSceneVolume : MonoBehaviour, IOVRSceneComponent
{
	[Tooltip("When enabled, scales the child transforms according to the dimensions of this volume. If both Volume and Plane components exist on the game object, the volume takes precedence.")]
	[SerializeField]
	internal bool _scaleChildren = true;

	[Tooltip("When enabled, offsets the child transforms according to the offset of this volume. If both Volume and Plane components exist on the game object, the volume takes precedence.")]
	[SerializeField]
	internal bool _offsetChildren;

	private OVRSceneAnchor _sceneAnchor;

	public float Width { get; private set; }

	public float Height { get; private set; }

	public float Depth { get; private set; }

	public Vector3 Dimensions => new Vector3(Width, Height, Depth);

	public Vector3 Offset { get; private set; }

	public bool ScaleChildren
	{
		get
		{
			return _scaleChildren;
		}
		set
		{
			_scaleChildren = value;
			if (_scaleChildren && _sceneAnchor.Space.Valid)
			{
				SetChildScale();
			}
		}
	}

	public bool OffsetChildren
	{
		get
		{
			return _offsetChildren;
		}
		set
		{
			_offsetChildren = value;
			if (_offsetChildren && _sceneAnchor.Space.Valid)
			{
				SetChildOffset();
			}
		}
	}

	private void Awake()
	{
		_sceneAnchor = GetComponent<OVRSceneAnchor>();
		if (_sceneAnchor.Space.Valid)
		{
			((IOVRSceneComponent)this).Initialize();
		}
	}

	void IOVRSceneComponent.Initialize()
	{
		UpdateTransform();
	}

	private void SetChildScale()
	{
		for (int i = 0; i < base.transform.childCount; i++)
		{
			Transform child = base.transform.GetChild(i);
			if (!child.TryGetComponent<OVRSceneObjectTransformType>(out var component) || component.TransformType == OVRSceneObjectTransformType.Transformation.Volume)
			{
				child.localScale = Dimensions;
			}
		}
	}

	private void SetChildOffset()
	{
		for (int i = 0; i < base.transform.childCount; i++)
		{
			Transform child = base.transform.GetChild(i);
			if (!child.TryGetComponent<OVRSceneObjectTransformType>(out var component) || component.TransformType == OVRSceneObjectTransformType.Transformation.Volume)
			{
				child.localPosition = Offset;
			}
		}
	}

	internal void UpdateTransform()
	{
		if (OVRPlugin.GetSpaceBoundingBox3D(_sceneAnchor.Space, out var bounds))
		{
			Width = bounds.Size.w;
			Height = bounds.Size.h;
			Depth = bounds.Size.d;
			Vector3 position = base.transform.position;
			Vector3 vector = base.transform.TransformPoint(bounds.Pos.FromVector3f() + bounds.Size.FromSize3f());
			Vector3 vector2 = base.transform.TransformPoint(bounds.Pos.FromVector3f() + bounds.Size.FromSize3f() / 2f);
			vector2.y = vector.y;
			Offset = new Vector3(vector2.x - position.x, vector2.z - position.z, vector2.y - position.y);
			if (ScaleChildren)
			{
				SetChildScale();
			}
			if (OffsetChildren)
			{
				SetChildOffset();
			}
		}
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-scene-use-scene-anchors/#further-scene-model-unity-components")]
[RequireComponent(typeof(MeshFilter))]
[Obsolete("OVRSceneManager and associated classes are deprecated (v65), please use MR Utility Kit instead (https://developer.oculus.com/documentation/unity/unity-mr-utility-kit-overview)")]
[Feature(Feature.Scene)]
public class OVRSceneVolumeMeshFilter : MonoBehaviour
{
	private struct GetTriangleMeshCountsJob : IJob
	{
		public OVRSpace Space;

		[WriteOnly]
		public NativeArray<int> Results;

		public void Execute()
		{
			Results[0] = -1;
			Results[1] = -1;
			if (OVRPlugin.GetSpaceTriangleMeshCounts(Space, out var vertexCount, out var triangleCount))
			{
				Results[0] = vertexCount;
				Results[1] = triangleCount;
			}
		}
	}

	private struct GetTriangleMeshJob : IJob
	{
		public OVRSpace Space;

		[WriteOnly]
		public NativeArray<Vector3> Vertices;

		[WriteOnly]
		public NativeArray<int> Triangles;

		public void Execute()
		{
			OVRPlugin.GetSpaceTriangleMesh(Space, Vertices, Triangles);
		}
	}

	private struct PopulateMeshDataJob : IJob
	{
		[Unity.Collections.ReadOnly]
		public NativeArray<Vector3> Vertices;

		[Unity.Collections.ReadOnly]
		public NativeArray<int> Triangles;

		[WriteOnly]
		public Mesh.MeshData MeshData;

		public void Execute()
		{
			MeshData.SetVertexBufferParams(Vertices.Length, new VertexAttributeDescriptor(VertexAttribute.Position, VertexAttributeFormat.Float32, 3, 0), new VertexAttributeDescriptor(VertexAttribute.Normal, VertexAttributeFormat.Float32, 3, 1));
			NativeArray<Vector3> vertexData = MeshData.GetVertexData<Vector3>();
			for (int i = 0; i < vertexData.Length; i++)
			{
				Vector3 vector = Vertices[i];
				vertexData[i] = new Vector3(0f - vector.x, vector.y, vector.z);
			}
			MeshData.SetIndexBufferParams(Triangles.Length, IndexFormat.UInt32);
			NativeArray<int> indexData = MeshData.GetIndexData<int>();
			for (int j = 0; j < indexData.Length; j += 3)
			{
				indexData[j] = Triangles[j];
				indexData[j + 1] = Triangles[j + 2];
				indexData[j + 2] = Triangles[j + 1];
			}
			MeshData.subMeshCount = 1;
			MeshData.SetSubMesh(0, new SubMeshDescriptor(0, Triangles.Length));
		}
	}

	private struct BakeMeshJob : IJob
	{
		public int MeshID;

		public bool Convex;

		public void Execute()
		{
			Physics.BakeMesh(MeshID, Convex);
		}
	}

	private Mesh _mesh;

	private MeshFilter _meshFilter;

	public bool IsCompleted { get; private set; }

	private void Start()
	{
		_mesh = new Mesh
		{
			name = "OVRSceneVolumeMeshFilter (anonymous)"
		};
		_meshFilter = GetComponent<MeshFilter>();
		_meshFilter.sharedMesh = _mesh;
		StartCoroutine(CreateVolumeMesh());
	}

	private IEnumerator CreateVolumeMesh()
	{
		if (!TryGetComponent<OVRSceneAnchor>(out var sceneAnchor))
		{
			IsCompleted = true;
			yield break;
		}
		int num;
		int num2;
		using (NativeArray<int> meshCountResults = new NativeArray<int>(2, Allocator.TempJob))
		{
			JobHandle job = new GetTriangleMeshCountsJob
			{
				Space = sceneAnchor.Space,
				Results = meshCountResults
			}.Schedule();
			while (!IsJobDone(job))
			{
				yield return null;
			}
			num = meshCountResults[0];
			num2 = meshCountResults[1];
		}
		if (num == -1)
		{
			IsCompleted = true;
			yield break;
		}
		NativeArray<Vector3> vertices = new NativeArray<Vector3>(num, Allocator.Persistent);
		NativeArray<int> triangles = new NativeArray<int>(num2 * 3, Allocator.Persistent);
		Mesh.MeshDataArray meshDataArray = Mesh.AllocateWritableMeshData(1);
		JobHandle dependsOn = new GetTriangleMeshJob
		{
			Space = sceneAnchor.Space,
			Vertices = vertices,
			Triangles = triangles
		}.Schedule();
		JobHandle inputDeps = new PopulateMeshDataJob
		{
			Vertices = vertices,
			Triangles = triangles,
			MeshData = meshDataArray[0]
		}.Schedule(dependsOn);
		JobHandle disposeVerticesJob = JobHandle.CombineDependencies(vertices.Dispose(inputDeps), triangles.Dispose(inputDeps));
		while (!IsJobDone(disposeVerticesJob))
		{
			yield return null;
		}
		Mesh.ApplyAndDisposeWritableMeshData(meshDataArray, _mesh);
		_mesh.RecalculateNormals();
		_mesh.RecalculateBounds();
		if (TryGetComponent<MeshCollider>(out var collider))
		{
			JobHandle job = new BakeMeshJob
			{
				MeshID = _mesh.GetInstanceID(),
				Convex = collider.convex
			}.Schedule();
			while (!IsJobDone(job))
			{
				yield return null;
			}
			collider.sharedMesh = _mesh;
		}
		IsCompleted = true;
	}

	private static bool IsJobDone(JobHandle job)
	{
		bool isCompleted = job.IsCompleted;
		if (isCompleted)
		{
			job.Complete();
		}
		return isCompleted;
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-scene-use-scene-anchors/#further-scene-model-unity-components")]
[DisallowMultipleComponent]
[RequireComponent(typeof(OVRSceneAnchor))]
[Obsolete("OVRSceneManager and associated classes are deprecated (v65), please use MR Utility Kit instead (https://developer.oculus.com/documentation/unity/unity-mr-utility-kit-overview)")]
[Feature(Feature.Scene)]
public class OVRSemanticClassification : MonoBehaviour, IOVRSceneComponent
{
	public const char LabelSeparator = ',';

	private readonly List<string> _labels = new List<string>();

	public IReadOnlyList<string> Labels => _labels;

	public bool Contains(string label)
	{
		foreach (string label2 in _labels)
		{
			if (label2 == label)
			{
				return true;
			}
		}
		return false;
	}

	private void Awake()
	{
		if (GetComponent<OVRSceneAnchor>().Space.Valid)
		{
			((IOVRSceneComponent)this).Initialize();
		}
	}

	void IOVRSceneComponent.Initialize()
	{
		if (OVRPlugin.GetSpaceSemanticLabels(GetComponent<OVRSceneAnchor>().Space, out var labels))
		{
			_labels.Clear();
			_labels.AddRange(ValidateAndUpgradeLabels(labels).Split(','));
		}
	}

	internal static string ValidateAndUpgradeLabels(string labels)
	{
		List<string> list;
		using (new OVRObjectPool.ListScope<string>(out list))
		{
			string[] array = labels.Split(',');
			bool flag = false;
			bool flag2 = false;
			bool flag3 = false;
			bool flag4 = false;
			string[] array2 = array;
			foreach (string text in array2)
			{
				list.Add(text);
				switch (text)
				{
				case "TABLE":
					flag = true;
					break;
				case "DESK":
					flag2 = true;
					break;
				case "INVISIBLE_WALL_FACE":
					flag3 = true;
					break;
				case "WALL_FACE":
					flag4 = true;
					break;
				}
			}
			if (flag && !flag2)
			{
				list.Add("DESK");
			}
			else if (flag2 && !flag)
			{
				list.Add("TABLE");
			}
			if (flag3 && !flag4)
			{
				list.Add("WALL_FACE");
			}
			return string.Join(','.ToString(), list);
		}
	}
}
