[Feature(Feature.VirtualKeyboard)]
public class OVRVirtualKeyboardInputFieldTextHandler : OVRVirtualKeyboard.AbstractTextHandler
{
	[SerializeField]
	private InputField inputField;

	private bool _isSelected;

	public InputField InputField
	{
		get
		{
			return inputField;
		}
		set
		{
			if (!(value == inputField))
			{
				if ((bool)inputField)
				{
					inputField.onValueChanged.RemoveListener(ProxyOnValueChanged);
				}
				inputField = value;
				if ((bool)inputField)
				{
					inputField.onValueChanged.AddListener(ProxyOnValueChanged);
				}
				OnTextChanged?.Invoke(Text);
			}
		}
	}

	public override Action<string> OnTextChanged { get; set; }

	public override string Text
	{
		get
		{
			if (!inputField)
			{
				return string.Empty;
			}
			return inputField.text;
		}
	}

	public override bool SubmitOnEnter
	{
		get
		{
			if ((bool)inputField)
			{
				return inputField.lineType != InputField.LineType.MultiLineNewline;
			}
			return false;
		}
	}

	public override bool IsFocused
	{
		get
		{
			if ((bool)inputField)
			{
				return inputField.isFocused;
			}
			return false;
		}
	}

	public override void Submit()
	{
		if ((bool)inputField)
		{
			inputField.onEndEdit.Invoke(inputField.text);
		}
	}

	public override void AppendText(string s)
	{
		if ((bool)inputField)
		{
			inputField.text += s;
		}
	}

	public override void ApplyBackspace()
	{
		if ((bool)inputField && !string.IsNullOrEmpty(inputField.text))
		{
			inputField.text = Text.Substring(0, Text.Length - 1);
		}
	}

	public override void MoveTextEnd()
	{
		if ((bool)inputField)
		{
			inputField.MoveTextEnd(shift: false);
		}
	}

	protected void Start()
	{
		if ((bool)inputField)
		{
			inputField.onValueChanged.AddListener(ProxyOnValueChanged);
		}
	}

	protected void ProxyOnValueChanged(string arg0)
	{
		OnTextChanged?.Invoke(arg0);
	}
}
[RequireComponent(typeof(OVRVirtualKeyboardSampleInputHandler))]
[HelpURL("https://developer.oculus.com/documentation/unity/VK-unity-sample/")]
[Feature(Feature.VirtualKeyboard)]
public class OVRVirtualKeyboardSampleControls : MonoBehaviour
{
	private struct OVRVirtualKeyboardBackup
	{
		private readonly Vector3 _position;

		private readonly Quaternion _rotation;

		private readonly Vector3 _scale;

		private readonly Transform _rightControllerDirectTransform;

		private readonly Transform _rightControllerRootTransform;

		private readonly Transform _leftControllerDirectTransform;

		private readonly Transform _leftControllerRootTransform;

		private readonly bool _controllerRayInteraction;

		private readonly bool _controllerDirectInteraction;

		private readonly OVRHand _handLeft;

		private readonly OVRHand _handRight;

		private readonly bool _handRayInteraction;

		private readonly bool _handDirectInteraction;

		private readonly OVRPhysicsRaycaster _controllerRaycaster;

		private readonly OVRPhysicsRaycaster _handRaycaster;

		private readonly InputField _textHandlerField;

		public OVRVirtualKeyboardBackup(OVRVirtualKeyboard keyboard)
		{
			_position = keyboard.transform.position;
			_rotation = keyboard.transform.rotation;
			_scale = keyboard.transform.localScale;
			_rightControllerDirectTransform = keyboard.rightControllerDirectTransform;
			_rightControllerRootTransform = keyboard.rightControllerRootTransform;
			_leftControllerDirectTransform = keyboard.leftControllerDirectTransform;
			_leftControllerRootTransform = keyboard.leftControllerRootTransform;
			_controllerRayInteraction = keyboard.controllerRayInteraction;
			_controllerDirectInteraction = keyboard.controllerDirectInteraction;
			_controllerRaycaster = keyboard.controllerRaycaster;
			_handLeft = keyboard.handLeft;
			_handRight = keyboard.handRight;
			_handRayInteraction = keyboard.handRayInteraction;
			_handDirectInteraction = keyboard.handDirectInteraction;
			_handRaycaster = keyboard.handRaycaster;
			_textHandlerField = null;
			if (keyboard.TextHandler is OVRVirtualKeyboardInputFieldTextHandler oVRVirtualKeyboardInputFieldTextHandler)
			{
				_textHandlerField = oVRVirtualKeyboardInputFieldTextHandler.InputField;
			}
		}

		public void RestoreTo(OVRVirtualKeyboard keyboard)
		{
			keyboard.transform.SetPositionAndRotation(_position, _rotation);
			keyboard.transform.localScale = _scale;
			keyboard.rightControllerDirectTransform = _rightControllerDirectTransform;
			keyboard.rightControllerRootTransform = _rightControllerRootTransform;
			keyboard.leftControllerDirectTransform = _leftControllerDirectTransform;
			keyboard.leftControllerRootTransform = _leftControllerRootTransform;
			keyboard.controllerRayInteraction = _controllerRayInteraction;
			keyboard.controllerDirectInteraction = _controllerDirectInteraction;
			keyboard.controllerRaycaster = _controllerRaycaster;
			keyboard.handLeft = _handLeft;
			keyboard.handRight = _handRight;
			keyboard.handRayInteraction = _handRayInteraction;
			keyboard.handDirectInteraction = _handDirectInteraction;
			keyboard.handRaycaster = _handRaycaster;
			if (keyboard.TextHandler == null)
			{
				keyboard.TextHandler = keyboard.gameObject.AddComponent<OVRVirtualKeyboardInputFieldTextHandler>();
			}
			OVRVirtualKeyboardInputFieldTextHandler oVRVirtualKeyboardInputFieldTextHandler = keyboard.TextHandler as OVRVirtualKeyboardInputFieldTextHandler;
			if ((bool)oVRVirtualKeyboardInputFieldTextHandler)
			{
				oVRVirtualKeyboardInputFieldTextHandler.InputField = _textHandlerField;
			}
		}
	}

	private const float THUMBSTICK_DEADZONE = 0.2f;

	[SerializeField]
	private Button ShowButton;

	[SerializeField]
	private Button MoveButton;

	[SerializeField]
	private Button HideButton;

	[SerializeField]
	private Button MoveNearButton;

	[SerializeField]
	private Button MoveFarButton;

	[SerializeField]
	private Button DestroyKeyboardButton;

	[SerializeField]
	private OVRVirtualKeyboard keyboard;

	[SerializeField]
	private OVRVirtualKeyboard keyboardPrefab;

	private OVRVirtualKeyboardSampleInputHandler inputHandler;

	private bool isMovingKeyboard_;

	private bool isMovingKeyboardFinished_;

	private float keyboardMoveDistance_;

	private float keyboardScale_ = 1f;

	private OVRVirtualKeyboardBackup keyboardBackup;

	private void Start()
	{
		inputHandler = GetComponent<OVRVirtualKeyboardSampleInputHandler>();
		keyboard.KeyboardHiddenEvent.AddListener(OnHideKeyboard);
		if ((bool)MoveNearButton)
		{
			MoveNearButton.onClick.AddListener(MoveKeyboardNear);
		}
		if ((bool)MoveFarButton)
		{
			MoveFarButton.onClick.AddListener(MoveKeyboardFar);
		}
		if ((bool)DestroyKeyboardButton)
		{
			DestroyKeyboardButton.onClick.AddListener(DestroyKeyboard);
		}
		StartCoroutine(CreateKeyboard());
	}

	private void OnDestroy()
	{
		if (!(keyboard == null))
		{
			keyboard.KeyboardHiddenEvent.RemoveListener(OnHideKeyboard);
			if ((bool)MoveNearButton)
			{
				MoveNearButton.onClick.RemoveListener(MoveKeyboardNear);
			}
			if ((bool)MoveFarButton)
			{
				MoveFarButton.onClick.RemoveListener(MoveKeyboardFar);
			}
			if ((bool)DestroyKeyboardButton)
			{
				DestroyKeyboardButton.onClick.RemoveListener(DestroyKeyboard);
			}
		}
	}

	public void ShowKeyboard()
	{
		if (keyboard == null)
		{
			StartCoroutine(CreateKeyboard());
			return;
		}
		keyboard.gameObject.SetActive(value: true);
		UpdateButtonInteractable();
	}

	private IEnumerator CreateKeyboard()
	{
		Text showButtonText = null;
		if ((bool)ShowButton && (bool)HideButton && (bool)DestroyKeyboardButton)
		{
			showButtonText = ShowButton.GetComponentInChildren<Text>();
			showButtonText.text = "Creating Keyboard...";
			ShowButton.interactable = false;
			HideButton.interactable = false;
			DestroyKeyboardButton.interactable = false;
		}
		if (keyboard == null)
		{
			if ((bool)keyboardPrefab)
			{
				keyboard = UnityEngine.Object.Instantiate(keyboardPrefab);
			}
			if (!keyboard)
			{
				GameObject gameObject = new GameObject();
				keyboard = gameObject.AddComponent<OVRVirtualKeyboard>();
			}
			keyboardBackup.RestoreTo(keyboard);
			inputHandler.OVRVirtualKeyboard = keyboard;
		}
		yield return new OVRVirtualKeyboard.WaitUntilKeyboardVisible(keyboard);
		if ((bool)showButtonText)
		{
			showButtonText.text = "Show Keyboard";
		}
		UpdateButtonInteractable();
	}

	public void MoveKeyboard()
	{
		if (keyboard.gameObject.activeSelf)
		{
			isMovingKeyboard_ = true;
			Transform transform = keyboard.transform;
			keyboardMoveDistance_ = (inputHandler.InputRayPosition - transform.position).magnitude;
			keyboardScale_ = transform.localScale.x;
			UpdateButtonInteractable();
			keyboard.InputEnabled = false;
		}
	}

	public void MoveKeyboardNear()
	{
		if (keyboard.gameObject.activeSelf)
		{
			keyboard.UseSuggestedLocation(OVRVirtualKeyboard.KeyboardPosition.Near);
		}
	}

	public void MoveKeyboardFar()
	{
		if (keyboard.gameObject.activeSelf)
		{
			keyboard.UseSuggestedLocation(OVRVirtualKeyboard.KeyboardPosition.Far);
		}
	}

	public void HideKeyboard()
	{
		keyboard.gameObject.SetActive(value: false);
		isMovingKeyboard_ = false;
		UpdateButtonInteractable();
	}

	public void DestroyKeyboard()
	{
		if (keyboard != null)
		{
			keyboardBackup = new OVRVirtualKeyboardBackup(keyboard);
			UnityEngine.Object.Destroy(keyboard.gameObject);
			keyboard = null;
			UpdateButtonInteractable();
		}
	}

	private void OnHideKeyboard()
	{
		UpdateButtonInteractable();
	}

	private void UpdateButtonInteractable()
	{
		bool flag = keyboard != null;
		bool interactable = flag && keyboard.gameObject.activeSelf && !isMovingKeyboard_;
		if ((bool)ShowButton)
		{
			ShowButton.interactable = !flag || !keyboard.gameObject.activeSelf;
		}
		if ((bool)MoveButton)
		{
			MoveButton.interactable = interactable;
		}
		if ((bool)MoveNearButton)
		{
			MoveNearButton.interactable = interactable;
		}
		if ((bool)MoveFarButton)
		{
			MoveFarButton.interactable = interactable;
		}
		if ((bool)HideButton)
		{
			HideButton.interactable = interactable;
		}
		if ((bool)DestroyKeyboardButton)
		{
			DestroyKeyboardButton.interactable = flag;
		}
	}

	private void Update()
	{
		bool flag = OVRInput.Get(OVRInput.Button.One | OVRInput.Button.Three | OVRInput.Button.PrimaryIndexTrigger | OVRInput.Button.SecondaryIndexTrigger, OVRInput.Controller.All);
		if (isMovingKeyboardFinished_ && !flag)
		{
			keyboard.InputEnabled = true;
			isMovingKeyboard_ = false;
			isMovingKeyboardFinished_ = false;
			UpdateButtonInteractable();
		}
		if (isMovingKeyboard_ && !isMovingKeyboardFinished_)
		{
			keyboardMoveDistance_ *= 1f + inputHandler.AnalogStickY * 0.01f;
			keyboardMoveDistance_ = Mathf.Clamp(keyboardMoveDistance_, 0.1f, 100f);
			keyboardScale_ += inputHandler.AnalogStickX * 0.01f;
			keyboardScale_ = Mathf.Clamp(keyboardScale_, 0.25f, 2f);
			Quaternion inputRayRotation = inputHandler.InputRayRotation;
			Transform obj = keyboard.transform;
			obj.SetPositionAndRotation(inputHandler.InputRayPosition + keyboardMoveDistance_ * (inputRayRotation * Vector3.forward), inputRayRotation);
			obj.localScale = Vector3.one * keyboardScale_;
			if (flag)
			{
				isMovingKeyboardFinished_ = true;
			}
		}
	}
}
[Feature(Feature.VirtualKeyboard)]
public class OVRVirtualKeyboardSampleInputHandler : MonoBehaviour
{
	private const float RAY_MAX_DISTANCE = 100f;

	private const float THUMBSTICK_DEADZONE = 0.2f;

	private const float COLLISION_BOUNDS_ADDED_BLEED_PERCENT = 0.1f;

	private const float LINEPOINTER_THINNING_THRESHOLD = 0.015f;

	public OVRVirtualKeyboard OVRVirtualKeyboard;

	[SerializeField]
	private OVRRaycaster raycaster;

	[SerializeField]
	private OVRInputModule inputModule;

	[SerializeField]
	private LineRenderer leftLinePointer;

	[SerializeField]
	private LineRenderer rightLinePointer;

	private OVRInput.Controller? interactionDevice_;

	private float linePointerInitialWidth_;

	public float AnalogStickX => ApplyDeadzone(OVRInput.Get(OVRInput.Axis2D.PrimaryThumbstick).x + OVRInput.Get(OVRInput.Axis2D.SecondaryThumbstick).x);

	public float AnalogStickY => ApplyDeadzone(OVRInput.Get(OVRInput.Axis2D.PrimaryThumbstick).y + OVRInput.Get(OVRInput.Axis2D.SecondaryThumbstick).y);

	public Vector3 InputRayPosition => inputModule.rayTransform.position;

	public Quaternion InputRayRotation
	{
		get
		{
			if (interactionDevice_ != OVRInput.Controller.LHand)
			{
				return inputModule.rayTransform.rotation;
			}
			return inputModule.rayTransform.rotation * Quaternion.Euler(Vector3.forward * 180f);
		}
	}

	private static float ApplyDeadzone(float value)
	{
		if (value > 0.2f)
		{
			return (value - 0.2f) / 0.8f;
		}
		if (value < -0.2f)
		{
			return (value + 0.2f) / 0.8f;
		}
		return 0f;
	}

	private void Start()
	{
		LineRenderer lineRenderer = rightLinePointer;
		bool flag = (leftLinePointer.enabled = false);
		lineRenderer.enabled = flag;
		linePointerInitialWidth_ = Math.Max(rightLinePointer.startWidth, leftLinePointer.startWidth);
	}

	private void Update()
	{
		UpdateInteractionAnchor();
		UpdateLineRenderer();
	}

	private void UpdateLineRenderer()
	{
		if (leftLinePointer != null)
		{
			leftLinePointer.enabled = false;
			UpdateLineRendererFromSource(OVRVirtualKeyboard.InputSource.ControllerLeft);
			UpdateLineRendererFromSource(OVRVirtualKeyboard.InputSource.HandLeft);
		}
		if (rightLinePointer != null)
		{
			rightLinePointer.enabled = false;
			UpdateLineRendererFromSource(OVRVirtualKeyboard.InputSource.ControllerRight);
			UpdateLineRendererFromSource(OVRVirtualKeyboard.InputSource.HandRight);
		}
	}

	private void UpdateLineRendererFromSource(OVRVirtualKeyboard.InputSource source)
	{
		Transform transform = null;
		switch (source)
		{
		case OVRVirtualKeyboard.InputSource.ControllerLeft:
			transform = ((OVRInput.IsControllerConnected(OVRInput.Controller.LTouch) && (OVRInput.GetControllerIsInHandState(OVRInput.Hand.HandLeft) == OVRInput.ControllerInHandState.NoHand || OVRInput.GetControllerIsInHandState(OVRInput.Hand.HandLeft) == OVRInput.ControllerInHandState.ControllerInHand)) ? OVRVirtualKeyboard.leftControllerDirectTransform : null);
			break;
		case OVRVirtualKeyboard.InputSource.ControllerRight:
			transform = ((OVRInput.IsControllerConnected(OVRInput.Controller.RTouch) && (OVRInput.GetControllerIsInHandState(OVRInput.Hand.HandRight) == OVRInput.ControllerInHandState.NoHand || OVRInput.GetControllerIsInHandState(OVRInput.Hand.HandRight) == OVRInput.ControllerInHandState.ControllerInHand)) ? OVRVirtualKeyboard.rightControllerDirectTransform : null);
			break;
		case OVRVirtualKeyboard.InputSource.HandLeft:
			transform = (OVRVirtualKeyboard.handLeft.IsPointerPoseValid ? OVRVirtualKeyboard.handLeft.PointerPose : null);
			break;
		case OVRVirtualKeyboard.InputSource.HandRight:
			transform = (OVRVirtualKeyboard.handRight.IsPointerPoseValid ? OVRVirtualKeyboard.handRight.PointerPose : null);
			break;
		}
		if (transform == null || transform.position == Vector3.zero)
		{
			return;
		}
		Vector3 position = transform.position;
		LineRenderer lineRenderer = ((source == OVRVirtualKeyboard.InputSource.ControllerLeft || source == OVRVirtualKeyboard.InputSource.HandLeft) ? leftLinePointer : rightLinePointer);
		lineRenderer.startWidth = linePointerInitialWidth_;
		if ((bool)OVRVirtualKeyboard && OVRVirtualKeyboard.isActiveAndEnabled && (bool)OVRVirtualKeyboard.Collider)
		{
			Vector3 vector = OVRVirtualKeyboard.transform.InverseTransformPoint(position) * OVRVirtualKeyboard.transform.localScale.x;
			Bounds bounds = new Bounds
			{
				size = OVRVirtualKeyboard.Collider.bounds.size
			};
			bounds.Expand(Vector3.one * 0.1f);
			if (bounds.Contains(vector))
			{
				lineRenderer.enabled = false;
				return;
			}
			float magnitude = (bounds.ClosestPoint(vector) - vector).magnitude;
			if (magnitude < 0.015f)
			{
				lineRenderer.startWidth = Mathf.Lerp(0f, linePointerInitialWidth_, magnitude / 0.015f);
			}
		}
		lineRenderer.endWidth = lineRenderer.startWidth;
		lineRenderer.enabled = true;
		lineRenderer.SetPosition(0, transform.position);
		Ray ray = new Ray(position, transform.rotation * Vector3.forward);
		if ((bool)OVRVirtualKeyboard.Collider && OVRVirtualKeyboard.Collider.Raycast(ray, out var hitInfo, 100f))
		{
			lineRenderer.SetPosition(1, hitInfo.point);
		}
		else
		{
			lineRenderer.SetPosition(1, position + ray.direction * 2.5f);
		}
	}

	private void UpdateInteractionAnchor()
	{
		OVRInput.Controller controller = OVRInput.Controller.None;
		controller = ((OVRVirtualKeyboard.leftControllerRootTransform != null && OVRInput.GetDown(OVRInput.RawButton.LIndexTrigger)) ? OVRInput.Controller.LTouch : controller);
		controller = ((OVRVirtualKeyboard.rightControllerRootTransform != null && OVRInput.GetDown(OVRInput.RawButton.RIndexTrigger)) ? OVRInput.Controller.RTouch : controller);
		controller = ((OVRVirtualKeyboard.handLeft != null && OVRVirtualKeyboard.handLeft.GetFingerIsPinching(OVRHand.HandFinger.Index)) ? OVRInput.Controller.LHand : controller);
		controller = ((OVRVirtualKeyboard.handRight != null && OVRVirtualKeyboard.handRight.GetFingerIsPinching(OVRHand.HandFinger.Index)) ? OVRInput.Controller.RHand : controller);
		int num;
		switch (controller)
		{
		case OVRInput.Controller.None:
			return;
		default:
			num = ((controller == OVRInput.Controller.LTouch) ? 1 : 0);
			break;
		case OVRInput.Controller.LHand:
			num = 1;
			break;
		}
		bool flag = (byte)num != 0;
		raycaster.pointer = (flag ? OVRVirtualKeyboard.handLeft.gameObject : OVRVirtualKeyboard.handRight.gameObject);
		interactionDevice_ = controller;
		OVRInputModule oVRInputModule = inputModule;
		oVRInputModule.rayTransform = controller switch
		{
			OVRInput.Controller.LHand => OVRVirtualKeyboard.handLeft.PointerPose, 
			OVRInput.Controller.LTouch => OVRVirtualKeyboard.handLeft.transform, 
			OVRInput.Controller.RHand => OVRVirtualKeyboard.handRight.PointerPose, 
			_ => OVRVirtualKeyboard.handRight.transform, 
		};
	}
}
