[HelpURL("https://developer.oculus.com/documentation/unity/controller-animations/")]
public class OVRControllerHelper : MonoBehaviour, OVRInputModule.InputSource
{
	private enum ControllerType
	{
		QuestAndRiftS = 1,
		Rift,
		Quest2,
		TouchPro,
		TouchPlus
	}

	public GameObject m_modelOculusTouchQuestAndRiftSLeftController;

	public GameObject m_modelOculusTouchQuestAndRiftSRightController;

	public GameObject m_modelOculusTouchRiftLeftController;

	public GameObject m_modelOculusTouchRiftRightController;

	public GameObject m_modelOculusTouchQuest2LeftController;

	public GameObject m_modelOculusTouchQuest2RightController;

	public GameObject m_modelMetaTouchProLeftController;

	public GameObject m_modelMetaTouchProRightController;

	public GameObject m_modelMetaTouchPlusLeftController;

	public GameObject m_modelMetaTouchPlusRightController;

	public OVRInput.Controller m_controller;

	public OVRInput.InputDeviceShowState m_showState = OVRInput.InputDeviceShowState.ControllerInHandOrNoHand;

	public bool showWhenHandsArePoweredByNaturalControllerPoses;

	private Animator m_animator;

	public OVRRayHelper RayHelper;

	private GameObject m_activeController;

	private bool m_controllerModelsInitialized;

	private bool m_hasInputFocus = true;

	private bool m_hasInputFocusPrev;

	private bool m_isActive;

	private ControllerType activeControllerType = ControllerType.Rift;

	private bool m_prevControllerConnected;

	private bool m_prevControllerConnectedCached;

	private OVRInput.ControllerInHandState m_prevControllerInHandState;

	private void Start()
	{
		if (OVRManager.OVRManagerinitialized)
		{
			InitializeControllerModels();
		}
	}

	private void OnEnable()
	{
		OVRInputModule.TrackInputSource(this);
		SceneManager.activeSceneChanged += OnSceneChanged;
	}

	private void OnDisable()
	{
		OVRInputModule.UntrackInputSource(this);
		SceneManager.activeSceneChanged -= OnSceneChanged;
	}

	private void OnSceneChanged(Scene unloading, Scene loading)
	{
		OVRInputModule.TrackInputSource(this);
	}

	private void InitializeControllerModels()
	{
		if (m_controllerModelsInitialized)
		{
			return;
		}
		OVRPlugin.SystemHeadset systemHeadsetType = OVRPlugin.GetSystemHeadsetType();
		OVRPlugin.Hand hand = ((m_controller != OVRInput.Controller.LTouch) ? OVRPlugin.Hand.HandRight : OVRPlugin.Hand.HandLeft);
		OVRPlugin.InteractionProfile interactionProfile = OVRPlugin.GetCurrentInteractionProfile(hand);
		if (OVRPlugin.IsMultimodalHandsControllersSupported())
		{
			OVRPlugin.InteractionProfile currentDetachedInteractionProfile = OVRPlugin.GetCurrentDetachedInteractionProfile(hand);
			if (currentDetachedInteractionProfile != OVRPlugin.InteractionProfile.None)
			{
				interactionProfile = currentDetachedInteractionProfile;
			}
		}
		switch (systemHeadsetType)
		{
		case OVRPlugin.SystemHeadset.Rift_CV1:
			activeControllerType = ControllerType.Rift;
			break;
		case OVRPlugin.SystemHeadset.Oculus_Quest_2:
			if (interactionProfile == OVRPlugin.InteractionProfile.TouchPro)
			{
				activeControllerType = ControllerType.TouchPro;
			}
			else
			{
				activeControllerType = ControllerType.Quest2;
			}
			break;
		case OVRPlugin.SystemHeadset.Oculus_Link_Quest_2:
			if (interactionProfile == OVRPlugin.InteractionProfile.TouchPro)
			{
				activeControllerType = ControllerType.TouchPro;
			}
			else
			{
				activeControllerType = ControllerType.Quest2;
			}
			break;
		case OVRPlugin.SystemHeadset.Meta_Quest_Pro:
			activeControllerType = ControllerType.TouchPro;
			break;
		case OVRPlugin.SystemHeadset.Meta_Link_Quest_Pro:
			activeControllerType = ControllerType.TouchPro;
			break;
		case OVRPlugin.SystemHeadset.Meta_Quest_3:
		case OVRPlugin.SystemHeadset.Meta_Quest_3S:
		case OVRPlugin.SystemHeadset.Meta_Link_Quest_3:
		case OVRPlugin.SystemHeadset.Meta_Link_Quest_3S:
			if (interactionProfile == OVRPlugin.InteractionProfile.TouchPro)
			{
				activeControllerType = ControllerType.TouchPro;
			}
			else
			{
				activeControllerType = ControllerType.TouchPlus;
			}
			break;
		default:
			activeControllerType = ControllerType.QuestAndRiftS;
			break;
		}
		UnityEngine.Debug.LogFormat("OVRControllerHelp: Active controller type: {0} for product {1} (headset {2}, hand {3})", activeControllerType, OVRPlugin.productName, systemHeadsetType, hand);
		m_modelOculusTouchQuestAndRiftSLeftController.SetActive(value: false);
		m_modelOculusTouchQuestAndRiftSRightController.SetActive(value: false);
		m_modelOculusTouchRiftLeftController.SetActive(value: false);
		m_modelOculusTouchRiftRightController.SetActive(value: false);
		m_modelOculusTouchQuest2LeftController.SetActive(value: false);
		m_modelOculusTouchQuest2RightController.SetActive(value: false);
		m_modelMetaTouchProLeftController.SetActive(value: false);
		m_modelMetaTouchProRightController.SetActive(value: false);
		m_modelMetaTouchPlusLeftController.SetActive(value: false);
		m_modelMetaTouchPlusRightController.SetActive(value: false);
		OVRManager.InputFocusAcquired += InputFocusAquired;
		OVRManager.InputFocusLost += InputFocusLost;
		m_controllerModelsInitialized = true;
	}

	private void Update()
	{
		m_isActive = false;
		if (!m_controllerModelsInitialized)
		{
			if (!OVRManager.OVRManagerinitialized)
			{
				return;
			}
			InitializeControllerModels();
		}
		OVRInput.ControllerInHandState controllerIsInHandState = OVRInput.GetControllerIsInHandState((m_controller != OVRInput.Controller.LTouch) ? OVRInput.Hand.HandRight : OVRInput.Hand.HandLeft);
		bool flag = OVRInput.IsControllerConnected(m_controller);
		if (flag != m_prevControllerConnected || !m_prevControllerConnectedCached || controllerIsInHandState != m_prevControllerInHandState || m_hasInputFocus != m_hasInputFocusPrev)
		{
			if (activeControllerType == ControllerType.Rift)
			{
				m_modelOculusTouchQuestAndRiftSLeftController.SetActive(value: false);
				m_modelOculusTouchQuestAndRiftSRightController.SetActive(value: false);
				m_modelOculusTouchRiftLeftController.SetActive(flag && m_controller == OVRInput.Controller.LTouch);
				m_modelOculusTouchRiftRightController.SetActive(flag && m_controller == OVRInput.Controller.RTouch);
				m_modelOculusTouchQuest2LeftController.SetActive(value: false);
				m_modelOculusTouchQuest2RightController.SetActive(value: false);
				m_modelMetaTouchProLeftController.SetActive(value: false);
				m_modelMetaTouchProRightController.SetActive(value: false);
				m_modelMetaTouchPlusLeftController.SetActive(value: false);
				m_modelMetaTouchPlusRightController.SetActive(value: false);
				m_animator = ((m_controller == OVRInput.Controller.LTouch) ? m_modelOculusTouchRiftLeftController.GetComponent<Animator>() : m_modelOculusTouchRiftRightController.GetComponent<Animator>());
				m_activeController = ((m_controller == OVRInput.Controller.LTouch) ? m_modelOculusTouchRiftLeftController : m_modelOculusTouchRiftRightController);
			}
			else if (activeControllerType == ControllerType.Quest2)
			{
				m_modelOculusTouchQuestAndRiftSLeftController.SetActive(value: false);
				m_modelOculusTouchQuestAndRiftSRightController.SetActive(value: false);
				m_modelOculusTouchRiftLeftController.SetActive(value: false);
				m_modelOculusTouchRiftRightController.SetActive(value: false);
				m_modelOculusTouchQuest2LeftController.SetActive(flag && m_controller == OVRInput.Controller.LTouch);
				m_modelOculusTouchQuest2RightController.SetActive(flag && m_controller == OVRInput.Controller.RTouch);
				m_modelMetaTouchProLeftController.SetActive(value: false);
				m_modelMetaTouchProRightController.SetActive(value: false);
				m_modelMetaTouchPlusLeftController.SetActive(value: false);
				m_modelMetaTouchPlusRightController.SetActive(value: false);
				m_animator = ((m_controller == OVRInput.Controller.LTouch) ? m_modelOculusTouchQuest2LeftController.GetComponent<Animator>() : m_modelOculusTouchQuest2RightController.GetComponent<Animator>());
				m_activeController = ((m_controller == OVRInput.Controller.LTouch) ? m_modelOculusTouchQuest2LeftController : m_modelOculusTouchQuest2RightController);
			}
			else if (activeControllerType == ControllerType.QuestAndRiftS)
			{
				m_modelOculusTouchQuestAndRiftSLeftController.SetActive(flag && m_controller == OVRInput.Controller.LTouch);
				m_modelOculusTouchQuestAndRiftSRightController.SetActive(flag && m_controller == OVRInput.Controller.RTouch);
				m_modelOculusTouchRiftLeftController.SetActive(value: false);
				m_modelOculusTouchRiftRightController.SetActive(value: false);
				m_modelOculusTouchQuest2LeftController.SetActive(value: false);
				m_modelOculusTouchQuest2RightController.SetActive(value: false);
				m_modelMetaTouchProLeftController.SetActive(value: false);
				m_modelMetaTouchProRightController.SetActive(value: false);
				m_modelMetaTouchPlusLeftController.SetActive(value: false);
				m_modelMetaTouchPlusRightController.SetActive(value: false);
				m_animator = ((m_controller == OVRInput.Controller.LTouch) ? m_modelOculusTouchQuestAndRiftSLeftController.GetComponent<Animator>() : m_modelOculusTouchQuestAndRiftSRightController.GetComponent<Animator>());
				m_activeController = ((m_controller == OVRInput.Controller.LTouch) ? m_modelOculusTouchQuestAndRiftSLeftController : m_modelOculusTouchQuestAndRiftSRightController);
			}
			else if (activeControllerType == ControllerType.TouchPro)
			{
				m_modelOculusTouchQuestAndRiftSLeftController.SetActive(value: false);
				m_modelOculusTouchQuestAndRiftSRightController.SetActive(value: false);
				m_modelOculusTouchRiftLeftController.SetActive(value: false);
				m_modelOculusTouchRiftRightController.SetActive(value: false);
				m_modelOculusTouchQuest2LeftController.SetActive(value: false);
				m_modelOculusTouchQuest2RightController.SetActive(value: false);
				m_modelMetaTouchProLeftController.SetActive(flag && m_controller == OVRInput.Controller.LTouch);
				m_modelMetaTouchProRightController.SetActive(flag && m_controller == OVRInput.Controller.RTouch);
				m_modelMetaTouchPlusLeftController.SetActive(value: false);
				m_modelMetaTouchPlusRightController.SetActive(value: false);
				m_animator = ((m_controller == OVRInput.Controller.LTouch) ? m_modelMetaTouchProLeftController.GetComponent<Animator>() : m_modelMetaTouchProRightController.GetComponent<Animator>());
				m_activeController = ((m_controller == OVRInput.Controller.LTouch) ? m_modelMetaTouchProLeftController : m_modelMetaTouchProRightController);
			}
			else
			{
				m_modelOculusTouchQuestAndRiftSLeftController.SetActive(value: false);
				m_modelOculusTouchQuestAndRiftSRightController.SetActive(value: false);
				m_modelOculusTouchRiftLeftController.SetActive(value: false);
				m_modelOculusTouchRiftRightController.SetActive(value: false);
				m_modelOculusTouchQuest2LeftController.SetActive(value: false);
				m_modelOculusTouchQuest2RightController.SetActive(value: false);
				m_modelMetaTouchProLeftController.SetActive(value: false);
				m_modelMetaTouchProRightController.SetActive(value: false);
				m_modelMetaTouchPlusLeftController.SetActive(flag && m_controller == OVRInput.Controller.LTouch);
				m_modelMetaTouchPlusRightController.SetActive(flag && m_controller == OVRInput.Controller.RTouch);
				m_animator = ((m_controller == OVRInput.Controller.LTouch) ? m_modelMetaTouchPlusLeftController.GetComponent<Animator>() : m_modelMetaTouchPlusRightController.GetComponent<Animator>());
				m_activeController = ((m_controller == OVRInput.Controller.LTouch) ? m_modelMetaTouchPlusLeftController : m_modelMetaTouchPlusRightController);
			}
			m_prevControllerConnected = flag;
			m_prevControllerConnectedCached = true;
			m_prevControllerInHandState = controllerIsInHandState;
			m_hasInputFocusPrev = m_hasInputFocus;
		}
		bool flag2 = m_hasInputFocus && flag;
		switch (m_showState)
		{
		case OVRInput.InputDeviceShowState.ControllerInHandOrNoHand:
			if (controllerIsInHandState == OVRInput.ControllerInHandState.ControllerNotInHand)
			{
				flag2 = false;
			}
			break;
		case OVRInput.InputDeviceShowState.ControllerInHand:
			if (controllerIsInHandState != OVRInput.ControllerInHandState.ControllerInHand)
			{
				flag2 = false;
			}
			break;
		case OVRInput.InputDeviceShowState.ControllerNotInHand:
			if (controllerIsInHandState != OVRInput.ControllerInHandState.ControllerNotInHand)
			{
				flag2 = false;
			}
			break;
		case OVRInput.InputDeviceShowState.NoHand:
			if (controllerIsInHandState != OVRInput.ControllerInHandState.NoHand)
			{
				flag2 = false;
			}
			break;
		}
		if (!showWhenHandsArePoweredByNaturalControllerPoses && OVRPlugin.IsControllerDrivenHandPosesEnabled() && OVRPlugin.AreControllerDrivenHandPosesNatural())
		{
			flag2 = false;
		}
		m_isActive = flag2;
		if (m_activeController != null)
		{
			m_activeController.SetActive(flag2);
		}
		if (RayHelper != null)
		{
			RayHelper.gameObject.SetActive(flag2);
		}
		if (m_animator != null && m_animator.gameObject.activeSelf)
		{
			m_animator.SetFloat("Button 1", OVRInput.Get(OVRInput.Button.One, m_controller) ? 1f : 0f);
			m_animator.SetFloat("Button 2", OVRInput.Get(OVRInput.Button.Two, m_controller) ? 1f : 0f);
			m_animator.SetFloat("Button 3", OVRInput.Get(OVRInput.Button.Start, m_controller) ? 1f : 0f);
			m_animator.SetFloat("Joy X", OVRInput.Get(OVRInput.Axis2D.PrimaryThumbstick, m_controller).x);
			m_animator.SetFloat("Joy Y", OVRInput.Get(OVRInput.Axis2D.PrimaryThumbstick, m_controller).y);
			m_animator.SetFloat("Trigger", OVRInput.Get(OVRInput.Axis1D.PrimaryIndexTrigger, m_controller));
			m_animator.SetFloat("Grip", OVRInput.Get(OVRInput.Axis1D.PrimaryHandTrigger, m_controller));
		}
	}

	public void InputFocusAquired()
	{
		m_hasInputFocus = true;
	}

	public void InputFocusLost()
	{
		m_hasInputFocus = false;
	}

	public bool IsPressed()
	{
		return OVRInput.GetDown(OVRInput.Button.PrimaryIndexTrigger, m_controller);
	}

	public bool IsReleased()
	{
		return OVRInput.GetUp(OVRInput.Button.PrimaryIndexTrigger, m_controller);
	}

	public Transform GetPointerRayTransform()
	{
		return base.transform;
	}

	public bool IsValid()
	{
		return this != null;
	}

	public bool IsActive()
	{
		return m_isActive;
	}

	public OVRPlugin.Hand GetHand()
	{
		if (m_controller != OVRInput.Controller.LTouch)
		{
			return OVRPlugin.Hand.HandRight;
		}
		return OVRPlugin.Hand.HandLeft;
	}

	public void UpdatePointerRay(OVRInputRayData rayData)
	{
		if ((bool)RayHelper)
		{
			rayData.IsActive = OVRInput.Get(OVRInput.Button.PrimaryIndexTrigger, m_controller);
			rayData.ActivationStrength = OVRInput.Get(OVRInput.Axis1D.PrimaryIndexTrigger, m_controller);
			RayHelper.UpdatePointerRay(rayData);
		}
	}
}
public class OVRControllerTest : MonoBehaviour
{
	public class BoolMonitor
	{
		public delegate bool BoolGenerator();

		private string m_name = "";

		private BoolGenerator m_generator;

		private bool m_prevValue;

		private bool m_currentValue;

		private bool m_currentValueRecentlyChanged;

		private float m_displayTimeout;

		private float m_displayTimer;

		public BoolMonitor(string name, BoolGenerator generator, float displayTimeout = 0.5f)
		{
			m_name = name;
			m_generator = generator;
			m_displayTimeout = displayTimeout;
		}

		public void Update()
		{
			m_prevValue = m_currentValue;
			m_currentValue = m_generator();
			if (m_currentValue != m_prevValue)
			{
				m_currentValueRecentlyChanged = true;
				m_displayTimer = m_displayTimeout;
			}
			if (m_displayTimer > 0f)
			{
				m_displayTimer -= Time.deltaTime;
				if (m_displayTimer <= 0f)
				{
					m_currentValueRecentlyChanged = false;
					m_displayTimer = 0f;
				}
			}
		}

		public void AppendToStringBuilder(ref StringBuilder sb)
		{
			sb.Append(m_name);
			if (m_currentValue && m_currentValueRecentlyChanged)
			{
				sb.Append(": *True*\n");
			}
			else if (m_currentValue)
			{
				sb.Append(":  True \n");
			}
			else if (!m_currentValue && m_currentValueRecentlyChanged)
			{
				sb.Append(": *False*\n");
			}
			else if (!m_currentValue)
			{
				sb.Append(":  False \n");
			}
		}
	}

	public Text uiText;

	private List<BoolMonitor> monitors;

	private StringBuilder data;

	private static string prevConnected = "";

	private static BoolMonitor controllers = new BoolMonitor("Controllers Changed", () => OVRInput.GetConnectedControllers().ToString() != prevConnected);

	private void Start()
	{
		if (uiText != null)
		{
			uiText.supportRichText = false;
		}
		data = new StringBuilder(2048);
		monitors = new List<BoolMonitor>
		{
			new BoolMonitor("One", () => OVRInput.Get(OVRInput.Button.One)),
			new BoolMonitor("OneDown", () => OVRInput.GetDown(OVRInput.Button.One)),
			new BoolMonitor("OneUp", () => OVRInput.GetUp(OVRInput.Button.One)),
			new BoolMonitor("One (Touch)", () => OVRInput.Get(OVRInput.Touch.One)),
			new BoolMonitor("OneDown (Touch)", () => OVRInput.GetDown(OVRInput.Touch.One)),
			new BoolMonitor("OneUp (Touch)", () => OVRInput.GetUp(OVRInput.Touch.One)),
			new BoolMonitor("Two", () => OVRInput.Get(OVRInput.Button.Two)),
			new BoolMonitor("TwoDown", () => OVRInput.GetDown(OVRInput.Button.Two)),
			new BoolMonitor("TwoUp", () => OVRInput.GetUp(OVRInput.Button.Two)),
			new BoolMonitor("PrimaryIndexTrigger", () => OVRInput.Get(OVRInput.Button.PrimaryIndexTrigger)),
			new BoolMonitor("PrimaryIndexTriggerDown", () => OVRInput.GetDown(OVRInput.Button.PrimaryIndexTrigger)),
			new BoolMonitor("PrimaryIndexTriggerUp", () => OVRInput.GetUp(OVRInput.Button.PrimaryIndexTrigger)),
			new BoolMonitor("PrimaryIndexTrigger (Touch)", () => OVRInput.Get(OVRInput.Touch.PrimaryIndexTrigger)),
			new BoolMonitor("PrimaryIndexTriggerDown (Touch)", () => OVRInput.GetDown(OVRInput.Touch.PrimaryIndexTrigger)),
			new BoolMonitor("PrimaryIndexTriggerUp (Touch)", () => OVRInput.GetUp(OVRInput.Touch.PrimaryIndexTrigger)),
			new BoolMonitor("PrimaryHandTrigger", () => OVRInput.Get(OVRInput.Button.PrimaryHandTrigger)),
			new BoolMonitor("PrimaryHandTriggerDown", () => OVRInput.GetDown(OVRInput.Button.PrimaryHandTrigger)),
			new BoolMonitor("PrimaryHandTriggerUp", () => OVRInput.GetUp(OVRInput.Button.PrimaryHandTrigger)),
			new BoolMonitor("Up", () => OVRInput.Get(OVRInput.Button.Up)),
			new BoolMonitor("Down", () => OVRInput.Get(OVRInput.Button.Down)),
			new BoolMonitor("Left", () => OVRInput.Get(OVRInput.Button.Left)),
			new BoolMonitor("Right", () => OVRInput.Get(OVRInput.Button.Right)),
			new BoolMonitor("Start", () => OVRInput.Get(OVRInput.RawButton.Start)),
			new BoolMonitor("StartDown", () => OVRInput.GetDown(OVRInput.RawButton.Start)),
			new BoolMonitor("StartUp", () => OVRInput.GetUp(OVRInput.RawButton.Start)),
			new BoolMonitor("Back", () => OVRInput.Get(OVRInput.RawButton.Back)),
			new BoolMonitor("BackDown", () => OVRInput.GetDown(OVRInput.RawButton.Back)),
			new BoolMonitor("BackUp", () => OVRInput.GetUp(OVRInput.RawButton.Back)),
			new BoolMonitor("A", () => OVRInput.Get(OVRInput.RawButton.A)),
			new BoolMonitor("ADown", () => OVRInput.GetDown(OVRInput.RawButton.A)),
			new BoolMonitor("AUp", () => OVRInput.GetUp(OVRInput.RawButton.A))
		};
	}

	private void Update()
	{
		OVRInput.Controller activeController = OVRInput.GetActiveController();
		data.Length = 0;
		byte controllerBatteryPercentRemaining = OVRInput.GetControllerBatteryPercentRemaining();
		data.AppendFormat("Battery: {0}\n", controllerBatteryPercentRemaining);
		float appFramerate = OVRPlugin.GetAppFramerate();
		data.AppendFormat("Framerate: {0:F2}\n", appFramerate);
		string arg = activeController.ToString();
		data.AppendFormat("Active: {0}\n", arg);
		string arg2 = OVRInput.GetConnectedControllers().ToString();
		data.AppendFormat("Connected: {0}\n", arg2);
		data.AppendFormat("PrevConnected: {0}\n", prevConnected);
		controllers.Update();
		controllers.AppendToStringBuilder(ref data);
		prevConnected = arg2;
		Quaternion localControllerRotation = OVRInput.GetLocalControllerRotation(activeController);
		data.AppendFormat("Orientation: ({0:F2}, {1:F2}, {2:F2}, {3:F2})\n", localControllerRotation.x, localControllerRotation.y, localControllerRotation.z, localControllerRotation.w);
		Vector3 localControllerAngularVelocity = OVRInput.GetLocalControllerAngularVelocity(activeController);
		data.AppendFormat("AngVel: ({0:F2}, {1:F2}, {2:F2})\n", localControllerAngularVelocity.x, localControllerAngularVelocity.y, localControllerAngularVelocity.z);
		Vector3 localControllerAngularAcceleration = OVRInput.GetLocalControllerAngularAcceleration(activeController);
		data.AppendFormat("AngAcc: ({0:F2}, {1:F2}, {2:F2})\n", localControllerAngularAcceleration.x, localControllerAngularAcceleration.y, localControllerAngularAcceleration.z);
		Vector3 localControllerPosition = OVRInput.GetLocalControllerPosition(activeController);
		data.AppendFormat("Position: ({0:F2}, {1:F2}, {2:F2})\n", localControllerPosition.x, localControllerPosition.y, localControllerPosition.z);
		Vector3 localControllerVelocity = OVRInput.GetLocalControllerVelocity(activeController);
		data.AppendFormat("Vel: ({0:F2}, {1:F2}, {2:F2})\n", localControllerVelocity.x, localControllerVelocity.y, localControllerVelocity.z);
		Vector3 localControllerAcceleration = OVRInput.GetLocalControllerAcceleration(activeController);
		data.AppendFormat("Acc: ({0:F2}, {1:F2}, {2:F2})\n", localControllerAcceleration.x, localControllerAcceleration.y, localControllerAcceleration.z);
		float num = OVRInput.Get(OVRInput.Axis1D.PrimaryIndexTrigger);
		data.AppendFormat("PrimaryIndexTriggerAxis1D: ({0:F2})\n", num);
		float num2 = OVRInput.Get(OVRInput.Axis1D.PrimaryHandTrigger);
		data.AppendFormat("PrimaryHandTriggerAxis1D: ({0:F2})\n", num2);
		for (int i = 0; i < monitors.Count; i++)
		{
			monitors[i].Update();
			monitors[i].AppendToStringBuilder(ref data);
		}
		if (uiText != null)
		{
			uiText.text = data.ToString();
		}
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-core-overview/#prefabs")]
public class OVRCubemapCapture : MonoBehaviour
{
	public bool autoTriggerAfterLaunch = true;

	public float autoTriggerDelay = 1f;

	private float autoTriggerElapse;

	public KeyCode triggeredByKey = KeyCode.F8;

	public string pathName;

	public int cubemapSize = 2048;

	private void Update()
	{
		if (autoTriggerAfterLaunch)
		{
			autoTriggerElapse += Time.deltaTime;
			if (autoTriggerElapse >= autoTriggerDelay)
			{
				autoTriggerAfterLaunch = false;
				TriggerCubemapCapture(base.transform.position, cubemapSize, pathName);
			}
		}
	}

	public static void TriggerCubemapCapture(Vector3 capturePos, int cubemapSize = 2048, string pathName = null)
	{
		GameObject obj = new GameObject("CubemapCamera", typeof(Camera));
		obj.hideFlags = HideFlags.HideAndDontSave;
		obj.transform.position = capturePos;
		obj.transform.rotation = Quaternion.identity;
		Camera component = obj.GetComponent<Camera>();
		component.farClipPlane = 10000f;
		component.enabled = false;
		Cubemap cubemap = new Cubemap(cubemapSize, TextureFormat.RGB24, mipChain: false);
		RenderIntoCubemap(component, cubemap);
		SaveCubemapCapture(cubemap, pathName);
		UnityEngine.Object.DestroyImmediate(cubemap);
		UnityEngine.Object.DestroyImmediate(obj);
	}

	public static void RenderIntoCubemap(Camera ownerCamera, Cubemap outCubemap)
	{
		int width = outCubemap.width;
		int height = outCubemap.height;
		CubemapFace[] array = new CubemapFace[6]
		{
			CubemapFace.PositiveX,
			CubemapFace.NegativeX,
			CubemapFace.PositiveY,
			CubemapFace.NegativeY,
			CubemapFace.PositiveZ,
			CubemapFace.NegativeZ
		};
		Vector3[] array2 = new Vector3[6]
		{
			new Vector3(0f, 90f, 0f),
			new Vector3(0f, -90f, 0f),
			new Vector3(-90f, 0f, 0f),
			new Vector3(90f, 0f, 0f),
			new Vector3(0f, 0f, 0f),
			new Vector3(0f, 180f, 0f)
		};
		RenderTexture active = RenderTexture.active;
		float fieldOfView = ownerCamera.fieldOfView;
		float aspect = ownerCamera.aspect;
		Quaternion rotation = ownerCamera.transform.rotation;
		RenderTexture renderTexture = new RenderTexture(width, height, 24);
		renderTexture.antiAliasing = 8;
		renderTexture.dimension = TextureDimension.Tex2D;
		renderTexture.hideFlags = HideFlags.HideAndDontSave;
		Texture2D texture2D = new Texture2D(width, height, TextureFormat.RGB24, mipChain: false);
		texture2D.hideFlags = HideFlags.HideAndDontSave;
		ownerCamera.targetTexture = renderTexture;
		ownerCamera.fieldOfView = 90f;
		ownerCamera.aspect = 1f;
		Color[] array3 = new Color[texture2D.height * texture2D.width];
		for (int i = 0; i < array.Length; i++)
		{
			ownerCamera.transform.eulerAngles = array2[i];
			ownerCamera.Render();
			RenderTexture.active = renderTexture;
			texture2D.ReadPixels(new Rect(0f, 0f, width, height), 0, 0);
			Color[] pixels = texture2D.GetPixels();
			for (int j = 0; j < height; j++)
			{
				for (int k = 0; k < width; k++)
				{
					array3[j * width + k] = pixels[(height - 1 - j) * width + k];
				}
			}
			outCubemap.SetPixels(array3, array[i]);
		}
		outCubemap.SmoothEdges();
		RenderTexture.active = active;
		ownerCamera.fieldOfView = fieldOfView;
		ownerCamera.aspect = aspect;
		ownerCamera.transform.rotation = rotation;
		ownerCamera.targetTexture = active;
		UnityEngine.Object.DestroyImmediate(texture2D);
		UnityEngine.Object.DestroyImmediate(renderTexture);
	}

	public static bool SaveCubemapCapture(Cubemap cubemap, string pathName = null)
	{
		int width = cubemap.width;
		int height = cubemap.height;
		int num = 0;
		int y = 0;
		bool flag = true;
		string text;
		string text2;
		if (string.IsNullOrEmpty(pathName))
		{
			text = Application.persistentDataPath + "/OVR_ScreenShot360/";
			text2 = null;
		}
		else
		{
			text = Path.GetDirectoryName(pathName);
			text2 = Path.GetFileName(pathName);
			if (text[text.Length - 1] != '/' || text[text.Length - 1] != '\\')
			{
				text += "/";
			}
		}
		if (string.IsNullOrEmpty(text2))
		{
			text2 = "OVR_" + DateTime.Now.ToString("hh_mm_ss") + ".png";
		}
		string extension = Path.GetExtension(text2);
		if (extension == ".png")
		{
			flag = true;
		}
		else
		{
			if (!(extension == ".jpg"))
			{
				UnityEngine.Debug.LogError("Unsupported file format" + extension);
				return false;
			}
			flag = false;
		}
		try
		{
			Directory.CreateDirectory(text);
		}
		catch (Exception ex)
		{
			UnityEngine.Debug.LogError("Failed to create path " + text + " since " + ex.ToString());
			return false;
		}
		Texture2D texture2D = new Texture2D(width * 6, height, TextureFormat.RGB24, mipChain: false);
		if (texture2D == null)
		{
			UnityEngine.Debug.LogError("[OVRScreenshotWizard] Failed creating the texture!");
			return false;
		}
		CubemapFace[] array = new CubemapFace[6]
		{
			CubemapFace.PositiveX,
			CubemapFace.NegativeX,
			CubemapFace.PositiveY,
			CubemapFace.NegativeY,
			CubemapFace.PositiveZ,
			CubemapFace.NegativeZ
		};
		for (int i = 0; i < array.Length; i++)
		{
			Color[] array2 = null;
			Color[] pixels = cubemap.GetPixels(array[i]);
			array2 = new Color[pixels.Length];
			for (int j = 0; j < height; j++)
			{
				for (int k = 0; k < width; k++)
				{
					array2[j * width + k] = pixels[(height - 1 - j) * width + k];
				}
			}
			texture2D.SetPixels(num, y, width, height, array2);
			num += width;
		}
		try
		{
			byte[] bytes = (flag ? texture2D.EncodeToPNG() : texture2D.EncodeToJPG());
			File.WriteAllBytes(text + text2, bytes);
			UnityEngine.Debug.Log("Cubemap file created " + text + text2);
		}
		catch (Exception ex2)
		{
			UnityEngine.Debug.LogError("Failed to save cubemap file since " + ex2.ToString());
			return false;
		}
		UnityEngine.Object.DestroyImmediate(texture2D);
		return true;
	}
}
