[HelpURL("https://developer.oculus.com/documentation/unity/move-face-tracking/")]
[Feature(Feature.FaceTracking)]
public static class OVRCustomFaceExtensions
{
	public static OVRFaceExpressions.FaceExpression[] AutoGenerateMapping(Mesh skinnedMesh, string[] blendShapeNames, OVRFaceExpressions.FaceExpression[] faceExpressions, bool allowDuplicateMapping)
	{
		OVRFaceExpressions.FaceExpression[] array = new OVRFaceExpressions.FaceExpression[skinnedMesh.blendShapeCount];
		HashSet<string>[] array2 = new HashSet<string>[blendShapeNames.Length];
		for (int i = 0; i < blendShapeNames.Length; i++)
		{
			array2[i] = TokenizeString(blendShapeNames[i]);
		}
		HashSet<OVRFaceExpressions.FaceExpression> hashSet = new HashSet<OVRFaceExpressions.FaceExpression>();
		for (int j = 0; j < skinnedMesh.blendShapeCount; j++)
		{
			string blendShapeName = skinnedMesh.GetBlendShapeName(j);
			OVRFaceExpressions.FaceExpression faceExpression = FindBestMatch(array2, blendShapeName, faceExpressions, OVRFaceExpressions.FaceExpression.Invalid);
			if (!allowDuplicateMapping && hashSet.Contains(faceExpression) && !IsLipsToward(blendShapeName))
			{
				array[j] = OVRFaceExpressions.FaceExpression.Invalid;
				continue;
			}
			array[j] = faceExpression;
			hashSet.Add(faceExpression);
		}
		return array;
	}

	private static OVRFaceExpressions.FaceExpression FindBestMatch(HashSet<string>[] tokenizedOptions, string searchString, OVRFaceExpressions.FaceExpression[] expressions, OVRFaceExpressions.FaceExpression fallback)
	{
		searchString = searchString.Substring(searchString.LastIndexOf('.') + 1);
		HashSet<string> first = TokenizeString(searchString);
		OVRFaceExpressions.FaceExpression result = fallback;
		int num = 2;
		for (int i = 0; i < tokenizedOptions.Length; i++)
		{
			int num2 = 0;
			HashSet<string> second = tokenizedOptions[i];
			foreach (string item in first.Intersect(second))
			{
				num2 += item.Length;
			}
			if (num2 > num)
			{
				num = num2;
				result = expressions[i];
			}
		}
		return result;
	}

	private static bool IsLipsToward(string blendshapeName)
	{
		blendshapeName = blendshapeName.Substring(blendshapeName.IndexOf('.') + 1);
		switch (blendshapeName)
		{
		default:
			return blendshapeName == "lipsToward_RT";
		case "lipsToward_LB":
		case "lipsToward_RB":
		case "lipsToward_LT":
			return true;
		}
	}

	internal static HashSet<string> TokenizeString(string s)
	{
		char[] separator = new char[6] { ' ', '_', '-', ',', '.', ';' };
		IEnumerable<string> enumerable = SplitCamelCase(s).Split(separator).Concat(s.Split(separator));
		HashSet<string> hashSet = new HashSet<string>();
		foreach (string item in enumerable)
		{
			string text = item.ToLowerInvariant();
			if (text == "left" || text == "l")
			{
				hashSet.Add("L");
			}
			if (text == "right" || text == "r")
			{
				hashSet.Add("R");
			}
			hashSet.Add(text);
		}
		return hashSet;
	}

	private static string SplitCamelCase(string input)
	{
		return Regex.Replace(input, "([A-Z])", " $1", RegexOptions.Compiled).Trim();
	}

	public static void AutoMapBlendshapes(this OVRCustomFace customFace)
	{
		OVRCustomFace.RetargetingType retargetingType = customFace.retargetingType;
		SkinnedMeshRenderer component = customFace.GetComponent<SkinnedMeshRenderer>();
		try
		{
			OVRFaceExpressions.FaceExpression[] array = retargetingType switch
			{
				OVRCustomFace.RetargetingType.OculusFace => OculusFaceAutoGenerateMapping(component.sharedMesh, customFace._allowDuplicateMapping), 
				OVRCustomFace.RetargetingType.Custom => CustomAutoGeneratedMapping(customFace, component.sharedMesh, customFace._allowDuplicateMapping), 
				_ => throw new InvalidEnumArgumentException("Invalid RetargetingType"), 
			};
			if (array != null)
			{
				if (customFace._mappings == null || customFace._mappings.Length != component.sharedMesh.blendShapeCount)
				{
					customFace._mappings = new OVRFaceExpressions.FaceExpression[component.sharedMesh.blendShapeCount];
				}
				for (int i = 0; i < component.sharedMesh.blendShapeCount; i++)
				{
					customFace._mappings[i] = array[i];
				}
			}
		}
		catch (Exception ex)
		{
			UnityEngine.Debug.LogError("Auto Map Face Error: " + ex.Message);
		}
	}

	public static void ClearBlendshapes(this OVRCustomFace customFace)
	{
		SkinnedMeshRenderer component = customFace.GetComponent<SkinnedMeshRenderer>();
		for (int i = 0; i < component.sharedMesh.blendShapeCount; i++)
		{
			customFace._mappings[i] = OVRFaceExpressions.FaceExpression.Invalid;
		}
	}

	internal static OVRFaceExpressions.FaceExpression[] OculusFaceAutoGenerateMapping(Mesh sharedMesh, bool allowDuplicateMapping)
	{
		string[] names = Enum.GetNames(typeof(OVRFaceExpressions.FaceExpression));
		OVRFaceExpressions.FaceExpression[] faceExpressions = (OVRFaceExpressions.FaceExpression[])Enum.GetValues(typeof(OVRFaceExpressions.FaceExpression));
		return AutoGenerateMapping(sharedMesh, names, faceExpressions, allowDuplicateMapping);
	}

	internal static OVRFaceExpressions.FaceExpression[] CustomAutoGeneratedMapping(OVRCustomFace customFace, Mesh sharedMesh, bool allowDuplicateMapping)
	{
		var (blendShapeNames, faceExpressions) = customFace.GetCustomBlendShapeNameAndExpressionPairs();
		return AutoGenerateMapping(sharedMesh, blendShapeNames, faceExpressions, allowDuplicateMapping);
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/move-samples/")]
[Feature(Feature.BodyTracking)]
public class OVRCustomSkeleton : OVRSkeleton, ISerializationCallbackReceiver
{
	public enum RetargetingType
	{
		OculusSkeleton
	}

	[HideInInspector]
	[SerializeField]
	private List<Transform> _customBones_V2;

	[SerializeField]
	[HideInInspector]
	internal RetargetingType retargetingType;

	public List<Transform> CustomBones => _customBones_V2;

	protected override Transform GetBoneTransform(BoneId boneId)
	{
		return _customBones_V2[(int)boneId];
	}

	void ISerializationCallbackReceiver.OnBeforeSerialize()
	{
	}

	void ISerializationCallbackReceiver.OnAfterDeserialize()
	{
		AllocateBones();
	}

	private void AllocateBones()
	{
		int num = 84;
		if (_customBones_V2.Count != num)
		{
			while (_customBones_V2.Count < num)
			{
				_customBones_V2.Add(null);
			}
		}
	}

	internal override void SetSkeletonType(SkeletonType skeletonType)
	{
		base.SetSkeletonType(skeletonType);
		if (_customBones_V2 == null)
		{
			_customBones_V2 = new List<Transform>();
		}
		AllocateBones();
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-sf-distancegrab/#scene-walkthrough")]
public class OVRDebugInfo : MonoBehaviour
{
	private GameObject debugUIManager;

	private GameObject debugUIObject;

	private GameObject riftPresent;

	private GameObject fps;

	private GameObject ipd;

	private GameObject fov;

	private GameObject height;

	private GameObject depth;

	private GameObject resolutionEyeTexture;

	private GameObject latencies;

	private GameObject texts;

	private string strRiftPresent;

	private string strFPS;

	private string strIPD;

	private string strFOV;

	private string strHeight;

	private string strDepth;

	private string strResolutionEyeTexture;

	private string strLatencies;

	private float updateInterval = 0.5f;

	private float accum;

	private int frames;

	private float timeLeft;

	private bool initUIComponent;

	private bool isInited;

	private float offsetY = 55f;

	private float riftPresentTimeout;

	private bool showVRVars;

	private void Awake()
	{
		debugUIManager = new GameObject();
		debugUIManager.name = "DebugUIManager";
		debugUIManager.transform.parent = GameObject.Find("LeftEyeAnchor").transform;
		RectTransform rectTransform = debugUIManager.AddComponent<RectTransform>();
		rectTransform.sizeDelta = new Vector2(100f, 100f);
		rectTransform.localScale = new Vector3(0.001f, 0.001f, 0.001f);
		rectTransform.localPosition = new Vector3(0.01f, 0.17f, 0.53f);
		rectTransform.localEulerAngles = Vector3.zero;
		Canvas canvas = debugUIManager.AddComponent<Canvas>();
		canvas.renderMode = RenderMode.WorldSpace;
		canvas.pixelPerfect = false;
	}

	private void Update()
	{
		if (initUIComponent && !isInited)
		{
			InitUIComponents();
		}
		UpdateDeviceDetection();
		if (showVRVars)
		{
			debugUIManager.SetActive(value: true);
			UpdateVariable();
			UpdateStrings();
		}
		else
		{
			debugUIManager.SetActive(value: false);
		}
	}

	private void OnDestroy()
	{
		isInited = false;
	}

	private void InitUIComponents()
	{
		float num = 0f;
		int fontSize = 20;
		debugUIObject = new GameObject();
		debugUIObject.name = "DebugInfo";
		debugUIObject.transform.parent = GameObject.Find("DebugUIManager").transform;
		debugUIObject.transform.localPosition = new Vector3(0f, 100f, 0f);
		debugUIObject.transform.localEulerAngles = Vector3.zero;
		debugUIObject.transform.localScale = new Vector3(1f, 1f, 1f);
		if (!string.IsNullOrEmpty(strFPS))
		{
			fps = VariableObjectManager(fps, "FPS", num -= offsetY, strFPS, fontSize);
		}
		if (!string.IsNullOrEmpty(strIPD))
		{
			ipd = VariableObjectManager(ipd, "IPD", num -= offsetY, strIPD, fontSize);
		}
		if (!string.IsNullOrEmpty(strFOV))
		{
			fov = VariableObjectManager(fov, "FOV", num -= offsetY, strFOV, fontSize);
		}
		if (!string.IsNullOrEmpty(strHeight))
		{
			height = VariableObjectManager(height, "Height", num -= offsetY, strHeight, fontSize);
		}
		if (!string.IsNullOrEmpty(strDepth))
		{
			depth = VariableObjectManager(depth, "Depth", num -= offsetY, strDepth, fontSize);
		}
		if (!string.IsNullOrEmpty(strResolutionEyeTexture))
		{
			resolutionEyeTexture = VariableObjectManager(resolutionEyeTexture, "Resolution", num -= offsetY, strResolutionEyeTexture, fontSize);
		}
		if (!string.IsNullOrEmpty(strLatencies))
		{
			latencies = VariableObjectManager(latencies, "Latency", num -= offsetY, strLatencies, 17);
			num = 0f;
		}
		initUIComponent = false;
		isInited = true;
	}

	private void UpdateVariable()
	{
		UpdateIPD();
		UpdateEyeHeightOffset();
		UpdateEyeDepthOffset();
		UpdateFOV();
		UpdateResolutionEyeTexture();
		UpdateLatencyValues();
		UpdateFPS();
	}

	private void UpdateStrings()
	{
		if (!(debugUIObject == null))
		{
			if (!string.IsNullOrEmpty(strFPS))
			{
				fps.GetComponentInChildren<Text>().text = strFPS;
			}
			if (!string.IsNullOrEmpty(strIPD))
			{
				ipd.GetComponentInChildren<Text>().text = strIPD;
			}
			if (!string.IsNullOrEmpty(strFOV))
			{
				fov.GetComponentInChildren<Text>().text = strFOV;
			}
			if (!string.IsNullOrEmpty(strResolutionEyeTexture))
			{
				resolutionEyeTexture.GetComponentInChildren<Text>().text = strResolutionEyeTexture;
			}
			if (!string.IsNullOrEmpty(strLatencies))
			{
				latencies.GetComponentInChildren<Text>().text = strLatencies;
				latencies.GetComponentInChildren<Text>().fontSize = 14;
			}
			if (!string.IsNullOrEmpty(strHeight))
			{
				height.GetComponentInChildren<Text>().text = strHeight;
			}
			if (!string.IsNullOrEmpty(strDepth))
			{
				depth.GetComponentInChildren<Text>().text = strDepth;
			}
		}
	}

	private void RiftPresentGUI(GameObject guiMainOBj)
	{
		riftPresent = ComponentComposition(riftPresent);
		riftPresent.transform.SetParent(guiMainOBj.transform);
		riftPresent.name = "RiftPresent";
		RectTransform component = riftPresent.GetComponent<RectTransform>();
		component.localPosition = new Vector3(0f, 0f, 0f);
		component.localScale = new Vector3(1f, 1f, 1f);
		component.localEulerAngles = Vector3.zero;
		Text componentInChildren = riftPresent.GetComponentInChildren<Text>();
		componentInChildren.text = strRiftPresent;
		componentInChildren.fontSize = 20;
	}

	private void UpdateDeviceDetection()
	{
		if (riftPresentTimeout >= 0f)
		{
			riftPresentTimeout -= Time.deltaTime;
		}
	}

	private GameObject VariableObjectManager(GameObject gameObject, string name, float posY, string str, int fontSize)
	{
		gameObject = ComponentComposition(gameObject);
		gameObject.name = name;
		gameObject.transform.SetParent(debugUIObject.transform);
		RectTransform component = gameObject.GetComponent<RectTransform>();
		component.localPosition = new Vector3(0f, posY -= offsetY, 0f);
		Text componentInChildren = gameObject.GetComponentInChildren<Text>();
		componentInChildren.text = str;
		componentInChildren.fontSize = fontSize;
		gameObject.transform.localEulerAngles = Vector3.zero;
		component.localScale = new Vector3(1f, 1f, 1f);
		return gameObject;
	}

	private GameObject ComponentComposition(GameObject GO)
	{
		GO = new GameObject();
		GO.AddComponent<RectTransform>();
		GO.AddComponent<CanvasRenderer>();
		GO.AddComponent<Image>();
		GO.GetComponent<RectTransform>().sizeDelta = new Vector2(350f, 50f);
		GO.GetComponent<Image>().color = new Color(0.02745098f, 0.1764706f, 0.2784314f, 40f / 51f);
		texts = new GameObject();
		texts.AddComponent<RectTransform>();
		texts.AddComponent<CanvasRenderer>();
		texts.AddComponent<Text>();
		texts.GetComponent<RectTransform>().sizeDelta = new Vector2(350f, 50f);
		texts.GetComponent<Text>().font = Resources.GetBuiltinResource(typeof(Font), "Arial.ttf") as Font;
		texts.GetComponent<Text>().alignment = TextAnchor.MiddleCenter;
		texts.transform.SetParent(GO.transform);
		texts.name = "TextBox";
		return GO;
	}

	private void UpdateIPD()
	{
		strIPD = $"IPD (mm): {OVRManager.profile.ipd * 1000f:F4}";
	}

	private void UpdateEyeHeightOffset()
	{
		float eyeHeight = OVRManager.profile.eyeHeight;
		strHeight = $"Eye Height (m): {eyeHeight:F3}";
	}

	private void UpdateEyeDepthOffset()
	{
		float eyeDepth = OVRManager.profile.eyeDepth;
		strDepth = $"Eye Depth (m): {eyeDepth:F3}";
	}

	private void UpdateFOV()
	{
		strFOV = $"FOV (deg): {OVRManager.display.GetEyeRenderDesc(XRNode.LeftEye).fov.y:F3}";
	}

	private void UpdateResolutionEyeTexture()
	{
		OVRDisplay.EyeRenderDesc eyeRenderDesc = OVRManager.display.GetEyeRenderDesc(XRNode.LeftEye);
		OVRDisplay.EyeRenderDesc eyeRenderDesc2 = OVRManager.display.GetEyeRenderDesc(XRNode.RightEye);
		float renderViewportScale = XRSettings.renderViewportScale;
		float num = (int)(renderViewportScale * (eyeRenderDesc.resolution.x + eyeRenderDesc2.resolution.x));
		float num2 = (int)(renderViewportScale * Mathf.Max(eyeRenderDesc.resolution.y, eyeRenderDesc2.resolution.y));
		strResolutionEyeTexture = $"Resolution : {num} x {num2}";
	}

	private void UpdateLatencyValues()
	{
		OVRDisplay.LatencyData latency = OVRManager.display.latency;
		if (latency.render < 1E-06f && latency.timeWarp < 1E-06f && latency.postPresent < 1E-06f)
		{
			strLatencies = $"Latency values are not available.";
			return;
		}
		strLatencies = $"Render: {latency.render:F3} TimeWarp: {latency.timeWarp:F3} Post-Present: {latency.postPresent:F3}\nRender Error: {latency.renderError:F3} TimeWarp Error: {latency.timeWarpError:F3}";
	}

	private void UpdateFPS()
	{
		timeLeft -= Time.unscaledDeltaTime;
		accum += Time.unscaledDeltaTime;
		frames++;
		if ((double)timeLeft <= 0.0)
		{
			float num = (float)frames / accum;
			strFPS = $"FPS: {num:F2}";
			timeLeft += updateInterval;
			accum = 0f;
			frames = 0;
		}
	}
}
internal static class OVRDeserialize
{
	public struct DisplayRefreshRateChangedData
	{
		public float FromRefreshRate;

		public float ToRefreshRate;
	}

