	{
		return hand switch
		{
			OVRHand.Hand.HandLeft => OVRSkeleton.SkeletonType.HandLeft, 
			OVRHand.Hand.HandRight => OVRSkeleton.SkeletonType.HandRight, 
			_ => OVRSkeleton.SkeletonType.None, 
		};
	}

