[HelpURL("https://developer.oculus.com/documentation/unity/unity-sf-customhands/")]
public class OVRGrabber : MonoBehaviour
{
	public float grabBegin = 0.55f;

	public float grabEnd = 0.35f;

	[SerializeField]
	protected bool m_parentHeldObject;

	[SerializeField]
	protected bool m_moveHandPosition;

	[SerializeField]
	protected Transform m_gripTransform;

	[SerializeField]
	protected Collider[] m_grabVolumes;

	[SerializeField]
	protected OVRInput.Controller m_controller;

	[SerializeField]
	protected Transform m_parentTransform;

	[SerializeField]
	protected GameObject m_player;

	protected bool m_grabVolumeEnabled = true;

	protected Vector3 m_lastPos;

	protected Quaternion m_lastRot;

	protected Quaternion m_anchorOffsetRotation;

	protected Vector3 m_anchorOffsetPosition;

	protected float m_prevFlex;

	protected OVRGrabbable m_grabbedObj;

	protected Vector3 m_grabbedObjectPosOff;

	protected Quaternion m_grabbedObjectRotOff;

	protected Dictionary<OVRGrabbable, int> m_grabCandidates = new Dictionary<OVRGrabbable, int>();

	protected bool m_operatingWithoutOVRCameraRig = true;

	public OVRGrabbable grabbedObject => m_grabbedObj;

	public void ForceRelease(OVRGrabbable grabbable)
	{
		if (m_grabbedObj != null && m_grabbedObj == grabbable)
		{
			GrabEnd();
		}
	}

	protected virtual void Awake()
	{
		m_anchorOffsetPosition = base.transform.localPosition;
		m_anchorOffsetRotation = base.transform.localRotation;
		if (m_moveHandPosition)
		{
			return;
		}
		OVRCameraRig componentInParent = base.transform.GetComponentInParent<OVRCameraRig>();
		if (componentInParent != null)
		{
			componentInParent.UpdatedAnchors += delegate
			{
				OnUpdatedAnchors();
			};
			m_operatingWithoutOVRCameraRig = false;
		}
	}

	protected virtual void Start()
	{
		m_lastPos = base.transform.position;
		m_lastRot = base.transform.rotation;
		if (m_parentTransform == null)
		{
			m_parentTransform = base.gameObject.transform;
		}
		SetPlayerIgnoreCollision(base.gameObject, ignore: true);
	}

	public virtual void Update()
	{
		if (m_operatingWithoutOVRCameraRig)
		{
			OnUpdatedAnchors();
		}
	}

	private void OnUpdatedAnchors()
	{
		Vector3 vector = m_parentTransform.TransformPoint(m_anchorOffsetPosition);
		Quaternion rot = m_parentTransform.rotation * m_anchorOffsetRotation;
		if (m_moveHandPosition)
		{
			GetComponent<Rigidbody>().MovePosition(vector);
			GetComponent<Rigidbody>().MoveRotation(rot);
		}
		if (!m_parentHeldObject)
		{
			MoveGrabbedObject(vector, rot);
		}
		m_lastPos = base.transform.position;
		m_lastRot = base.transform.rotation;
		float prevFlex = m_prevFlex;
		m_prevFlex = OVRInput.Get(OVRInput.Axis1D.PrimaryHandTrigger, m_controller);
		CheckForGrabOrRelease(prevFlex);
	}

	private void OnDestroy()
	{
		if (m_grabbedObj != null)
		{
			GrabEnd();
		}
	}

	private void OnTriggerEnter(Collider otherCollider)
	{
		OVRGrabbable oVRGrabbable = otherCollider.GetComponent<OVRGrabbable>() ?? otherCollider.GetComponentInParent<OVRGrabbable>();
		if (!(oVRGrabbable == null))
		{
			int value = 0;
			m_grabCandidates.TryGetValue(oVRGrabbable, out value);
			m_grabCandidates[oVRGrabbable] = value + 1;
		}
	}

	private void OnTriggerExit(Collider otherCollider)
	{
		OVRGrabbable oVRGrabbable = otherCollider.GetComponent<OVRGrabbable>() ?? otherCollider.GetComponentInParent<OVRGrabbable>();
		if (oVRGrabbable == null)
		{
			return;
		}
		int value = 0;
		if (m_grabCandidates.TryGetValue(oVRGrabbable, out value))
		{
			if (value > 1)
			{
				m_grabCandidates[oVRGrabbable] = value - 1;
			}
			else
			{
				m_grabCandidates.Remove(oVRGrabbable);
			}
		}
	}

	protected void CheckForGrabOrRelease(float prevFlex)
	{
		if (m_prevFlex >= grabBegin && prevFlex < grabBegin)
		{
			GrabBegin();
		}
		else if (m_prevFlex <= grabEnd && prevFlex > grabEnd)
		{
			GrabEnd();
		}
	}

	protected virtual void GrabBegin()
	{
		float num = float.MaxValue;
		OVRGrabbable oVRGrabbable = null;
		Collider grabPoint = null;
		foreach (OVRGrabbable key in m_grabCandidates.Keys)
		{
			if (key.isGrabbed && !key.allowOffhandGrab)
			{
				continue;
			}
			for (int i = 0; i < key.grabPoints.Length; i++)
			{
				Collider collider = key.grabPoints[i];
				Vector3 vector = collider.ClosestPointOnBounds(m_gripTransform.position);
				float sqrMagnitude = (m_gripTransform.position - vector).sqrMagnitude;
				if (sqrMagnitude < num)
				{
					num = sqrMagnitude;
					oVRGrabbable = key;
					grabPoint = collider;
				}
			}
		}
		GrabVolumeEnable(enabled: false);
		if (!(oVRGrabbable != null))
		{
			return;
		}
		if (oVRGrabbable.isGrabbed)
		{
			oVRGrabbable.grabbedBy.OffhandGrabbed(oVRGrabbable);
		}
		m_grabbedObj = oVRGrabbable;
		m_grabbedObj.GrabBegin(this, grabPoint);
		m_lastPos = base.transform.position;
		m_lastRot = base.transform.rotation;
		if (m_grabbedObj.snapPosition)
		{
			m_grabbedObjectPosOff = m_gripTransform.localPosition;
			if ((bool)m_grabbedObj.snapOffset)
			{
				Vector3 position = m_grabbedObj.snapOffset.position;
				if (m_controller == OVRInput.Controller.LTouch)
				{
					position.x = 0f - position.x;
				}
				m_grabbedObjectPosOff += position;
			}
		}
		else
		{
			Vector3 vector2 = m_grabbedObj.transform.position - base.transform.position;
			vector2 = Quaternion.Inverse(base.transform.rotation) * vector2;
			m_grabbedObjectPosOff = vector2;
		}
		if (m_grabbedObj.snapOrientation)
		{
			m_grabbedObjectRotOff = m_gripTransform.localRotation;
			if ((bool)m_grabbedObj.snapOffset)
			{
				m_grabbedObjectRotOff = m_grabbedObj.snapOffset.rotation * m_grabbedObjectRotOff;
			}
		}
		else
		{
			Quaternion grabbedObjectRotOff = Quaternion.Inverse(base.transform.rotation) * m_grabbedObj.transform.rotation;
			m_grabbedObjectRotOff = grabbedObjectRotOff;
		}
		MoveGrabbedObject(m_lastPos, m_lastRot, forceTeleport: true);
		SetPlayerIgnoreCollision(m_grabbedObj.gameObject, ignore: true);
		if (m_parentHeldObject)
		{
			m_grabbedObj.transform.parent = base.transform;
		}
	}

	protected virtual void MoveGrabbedObject(Vector3 pos, Quaternion rot, bool forceTeleport = false)
	{
		if (!(m_grabbedObj == null))
		{
			Rigidbody grabbedRigidbody = m_grabbedObj.grabbedRigidbody;
			Vector3 position = pos + rot * m_grabbedObjectPosOff;
			Quaternion quaternion = rot * m_grabbedObjectRotOff;
			if (forceTeleport)
			{
				grabbedRigidbody.transform.position = position;
				grabbedRigidbody.transform.rotation = quaternion;
			}
			else
			{
				grabbedRigidbody.MovePosition(position);
				grabbedRigidbody.MoveRotation(quaternion);
			}
		}
	}

	protected void GrabEnd()
	{
		if (m_grabbedObj != null)
		{
			OVRPose oVRPose = new OVRPose
			{
				position = OVRInput.GetLocalControllerPosition(m_controller),
				orientation = OVRInput.GetLocalControllerRotation(m_controller)
			};
			OVRPose oVRPose2 = new OVRPose
			{
				position = m_anchorOffsetPosition,
				orientation = m_anchorOffsetRotation
			};
			oVRPose *= oVRPose2;
			OVRPose oVRPose3 = base.transform.ToOVRPose() * oVRPose.Inverse();
			Vector3 linearVelocity = oVRPose3.orientation * OVRInput.GetLocalControllerVelocity(m_controller);
			Vector3 angularVelocity = oVRPose3.orientation * OVRInput.GetLocalControllerAngularVelocity(m_controller);
			GrabbableRelease(linearVelocity, angularVelocity);
		}
		GrabVolumeEnable(enabled: true);
	}

	protected void GrabbableRelease(Vector3 linearVelocity, Vector3 angularVelocity)
	{
		m_grabbedObj.GrabEnd(linearVelocity, angularVelocity);
		if (m_parentHeldObject)
		{
			m_grabbedObj.transform.parent = null;
		}
		m_grabbedObj = null;
	}

	protected virtual void GrabVolumeEnable(bool enabled)
	{
		if (m_grabVolumeEnabled != enabled)
		{
			m_grabVolumeEnabled = enabled;
			for (int i = 0; i < m_grabVolumes.Length; i++)
			{
				m_grabVolumes[i].enabled = m_grabVolumeEnabled;
			}
			if (!m_grabVolumeEnabled)
			{
				m_grabCandidates.Clear();
			}
		}
	}

	protected virtual void OffhandGrabbed(OVRGrabbable grabbable)
	{
		if (m_grabbedObj == grabbable)
		{
			GrabbableRelease(Vector3.zero, Vector3.zero);
		}
	}

	protected void SetPlayerIgnoreCollision(GameObject grabbable, bool ignore)
	{
		if (!(m_player != null))
		{
			return;
		}
		Collider[] componentsInChildren = m_player.GetComponentsInChildren<Collider>();
		foreach (Collider collider in componentsInChildren)
		{
			Collider[] componentsInChildren2 = grabbable.GetComponentsInChildren<Collider>();
			foreach (Collider collider2 in componentsInChildren2)
			{
				if (!collider2.isTrigger && !collider.isTrigger)
				{
					Physics.IgnoreCollision(collider2, collider, ignore);
				}
			}
		}
	}
}
[HelpURL("https://developer.oculus.com/reference/unity/latest/class_o_v_r_grid_cube")]
public class OVRGridCube : MonoBehaviour
{
	public KeyCode GridKey = KeyCode.G;

	private GameObject CubeGrid;

	private bool CubeGridOn;

	private bool CubeSwitchColorOld;

	private bool CubeSwitchColor;

	private int gridSizeX = 6;

	private int gridSizeY = 4;

	private int gridSizeZ = 6;

	private float gridScale = 0.3f;

	private float cubeScale = 0.03f;

	private OVRCameraRig CameraController;

	private void Update()
	{
		UpdateCubeGrid();
	}

	public void SetOVRCameraController(ref OVRCameraRig cameraController)
	{
		CameraController = cameraController;
	}

	private void UpdateCubeGrid()
	{
		if (CubeGrid != null)
		{
			CubeSwitchColor = !OVRManager.tracker.isPositionTracked;
			if (CubeSwitchColor != CubeSwitchColorOld)
			{
				CubeGridSwitchColor(CubeSwitchColor);
			}
			CubeSwitchColorOld = CubeSwitchColor;
		}
	}

	private void CreateCubeGrid()
	{
		UnityEngine.Debug.LogWarning("Create CubeGrid");
		CubeGrid = new GameObject("CubeGrid");
		CubeGrid.layer = CameraController.gameObject.layer;
		for (int i = -gridSizeX; i <= gridSizeX; i++)
		{
			for (int j = -gridSizeY; j <= gridSizeY; j++)
			{
				for (int k = -gridSizeZ; k <= gridSizeZ; k++)
				{
					int num = 0;
					if ((i == 0 && j == 0) || (i == 0 && k == 0) || (j == 0 && k == 0))
					{
						num = ((i != 0 || j != 0 || k != 0) ? 1 : 2);
					}
					GameObject obj = GameObject.CreatePrimitive(PrimitiveType.Cube);
					obj.GetComponent<BoxCollider>().enabled = false;
					obj.layer = CameraController.gameObject.layer;
					Renderer component = obj.GetComponent<Renderer>();
					component.shadowCastingMode = ShadowCastingMode.Off;
					component.receiveShadows = false;
					switch (num)
					{
					case 0:
						component.material.color = Color.red;
						break;
					case 1:
						component.material.color = Color.white;
						break;
					default:
						component.material.color = Color.yellow;
						break;
					}
					obj.transform.position = new Vector3((float)i * gridScale, (float)j * gridScale, (float)k * gridScale);
					float num2 = 0.7f;
					if (num == 1)
					{
						num2 = 1f;
					}
					if (num == 2)
					{
						num2 = 2f;
					}
					obj.transform.localScale = new Vector3(cubeScale * num2, cubeScale * num2, cubeScale * num2);
					obj.transform.parent = CubeGrid.transform;
				}
			}
		}
	}

	private void CubeGridSwitchColor(bool CubeSwitchColor)
	{
		Color color = Color.red;
		if (CubeSwitchColor)
		{
			color = Color.blue;
		}
		Transform transform = CubeGrid.transform;
		for (int i = 0; i < transform.childCount; i++)
		{
			Material material = transform.GetChild(i).GetComponent<Renderer>().material;
			if (material.color == Color.red || material.color == Color.blue)
			{
				material.color = color;
			}
		}
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-handtracking/")]
[Feature(Feature.Hands)]
public class OVRHand : MonoBehaviour, OVRInputModule.InputSource, OVRSkeleton.IOVRSkeletonDataProvider, OVRSkeletonRenderer.IOVRSkeletonRendererDataProvider, OVRMesh.IOVRMeshDataProvider, OVRMeshRenderer.IOVRMeshRendererDataProvider
{
	public enum Hand
	{
		None = -1,
		HandLeft,
		HandRight
	}

	public enum HandFinger
	{
		Thumb,
		Index,
		Middle,
		Ring,
		Pinky,
		Max
	}

	public enum TrackingConfidence
	{
		Low = 0,
		High = 1065353216
	}

	public enum MicrogestureType
	{
		NoGesture = 0,
		SwipeLeft = 1,
		SwipeRight = 2,
		SwipeForward = 3,
		SwipeBackward = 4,
		ThumbTap = 5,
		Invalid = -1
	}

	[SerializeField]
	internal Hand HandType = Hand.None;

	[SerializeField]
	private Transform _pointerPoseRoot;

	public OVRInput.InputDeviceShowState m_showState = OVRInput.InputDeviceShowState.ControllerNotInHand;

	public OVRRayHelper RayHelper;

	private GameObject _pointerPoseGO;

	private OVRPlugin.HandState _handState;

	private bool _wasIndexPinching;

	private bool _wasReleased;

	private OVRPlugin.HandTrackingState _handTrackingState;

	private bool _handTrackingStateValid;

	private static OVRHandSkeletonVersion GlobalHandSkeletonVersion => OVRRuntimeSettings.Instance.HandSkeletonVersion;

	public bool IsDataValid { get; private set; }

	public bool IsDataHighConfidence { get; private set; }

	public bool IsTracked { get; private set; }

	public bool IsSystemGestureInProgress { get; private set; }

	public bool IsPointerPoseValid { get; private set; }

	public Transform PointerPose
	{
		get
		{
			if (_pointerPoseGO == null)
			{
				InitializePointerPose();
			}
			return _pointerPoseGO.transform;
		}
	}

	public float HandScale { get; private set; }

	public TrackingConfidence HandConfidence { get; private set; }

	public bool IsDominantHand { get; private set; }

	private void InitializePointerPose()
	{
		_pointerPoseGO = new GameObject(string.Format("{0} {1}", HandType, "PointerPose"));
		UnityEngine.Object.DontDestroyOnLoad(_pointerPoseGO);
		_pointerPoseGO.hideFlags = HideFlags.HideAndDontSave;
		if (_pointerPoseRoot != null)
		{
			PointerPose.SetParent(_pointerPoseRoot, worldPositionStays: false);
		}
	}

	private void Awake()
	{
		if (_pointerPoseGO == null)
		{
			InitializePointerPose();
		}
		if (RayHelper != null)
		{
			RayHelper.transform.SetParent(PointerPose, worldPositionStays: false);
		}
		GetHandState(OVRPlugin.Step.Render);
	}

	private void Update()
	{
		GetHandState(OVRPlugin.Step.Render);
		bool fingerIsPinching = GetFingerIsPinching(HandFinger.Index);
		_wasReleased = !fingerIsPinching && _wasIndexPinching;
		_wasIndexPinching = fingerIsPinching;
		if ((bool)RayHelper && !IsActive() && RayHelper.isActiveAndEnabled)
		{
			RayHelper.gameObject.SetActive(value: false);
		}
	}

	private void FixedUpdate()
	{
		if (OVRPlugin.nativeXrApi != OVRPlugin.XrApi.OpenXR)
		{
			GetHandState(OVRPlugin.Step.Physics);
		}
		if (RayHelper != null)
		{
			RayHelper.gameObject.SetActive(IsDataValid);
		}
	}

	private void OnDestroy()
	{
		if (_pointerPoseGO != null)
		{
			UnityEngine.Object.Destroy(_pointerPoseGO);
		}
	}

	private void GetHandState(OVRPlugin.Step step)
	{
		if (OVRPlugin.GetHandState(step, (OVRPlugin.Hand)HandType, ref _handState))
		{
			IsTracked = (_handState.Status & OVRPlugin.HandStatus.HandTracked) != 0;
			IsSystemGestureInProgress = (_handState.Status & OVRPlugin.HandStatus.SystemGestureInProgress) != 0;
			IsPointerPoseValid = (_handState.Status & OVRPlugin.HandStatus.InputStateValid) != 0;
			IsDominantHand = (_handState.Status & OVRPlugin.HandStatus.DominantHand) != 0;
			PointerPose.localPosition = _handState.PointerPose.Position.FromFlippedZVector3f();
			PointerPose.localRotation = _handState.PointerPose.Orientation.FromFlippedZQuatf();
			HandScale = _handState.HandScale;
			HandConfidence = (TrackingConfidence)_handState.HandConfidence;
			IsDataValid = true;
			IsDataHighConfidence = IsTracked && HandConfidence == TrackingConfidence.High;
			_handTrackingStateValid = OVRPlugin.GetHandTrackingState(step, (OVRPlugin.Hand)HandType, ref _handTrackingState);
			OVRInput.ControllerInHandState controllerIsInHandState = OVRInput.GetControllerIsInHandState((OVRInput.Hand)HandType);
			if (controllerIsInHandState == OVRInput.ControllerInHandState.ControllerInHand)
			{
				IsSystemGestureInProgress = false;
				IsPointerPoseValid = false;
			}
			switch (m_showState)
			{
			case OVRInput.InputDeviceShowState.ControllerInHandOrNoHand:
				if (controllerIsInHandState == OVRInput.ControllerInHandState.ControllerNotInHand)
				{
					IsDataValid = false;
				}
				break;
			case OVRInput.InputDeviceShowState.ControllerInHand:
				if (controllerIsInHandState != OVRInput.ControllerInHandState.ControllerInHand)
				{
					IsDataValid = false;
				}
				break;
			case OVRInput.InputDeviceShowState.ControllerNotInHand:
				if (controllerIsInHandState != OVRInput.ControllerInHandState.ControllerNotInHand)
				{
					IsDataValid = false;
				}
				break;
			case OVRInput.InputDeviceShowState.NoHand:
				if (controllerIsInHandState != OVRInput.ControllerInHandState.NoHand)
				{
					IsDataValid = false;
				}
				break;
			}
			if (OVRPlugin.HandSkeletonVersion != GlobalHandSkeletonVersion)
			{
				IsDataValid = false;
			}
		}
		else
		{
			IsTracked = false;
			IsSystemGestureInProgress = false;
			IsPointerPoseValid = false;
			PointerPose.localPosition = Vector3.zero;
			PointerPose.localRotation = Quaternion.identity;
			HandScale = 1f;
			HandConfidence = TrackingConfidence.Low;
			IsDataValid = false;
			IsDataHighConfidence = false;
			_handTrackingStateValid = false;
		}
	}

	public bool GetFingerIsPinching(HandFinger finger)
	{
		if (IsDataValid)
		{
			return ((uint)_handState.Pinches & (uint)(1 << (int)finger)) != 0;
		}
		return false;
	}

	public float GetFingerPinchStrength(HandFinger finger)
	{
		if (IsDataValid && _handState.PinchStrength != null && _handState.PinchStrength.Length == 5)
		{
			return _handState.PinchStrength[(int)finger];
		}
		return 0f;
	}

	public TrackingConfidence GetFingerConfidence(HandFinger finger)
	{
		if (IsDataValid && _handState.FingerConfidences != null && _handState.FingerConfidences.Length == 5)
		{
			return (TrackingConfidence)_handState.FingerConfidences[(int)finger];
		}
		return TrackingConfidence.Low;
	}

	OVRSkeleton.SkeletonType OVRSkeleton.IOVRSkeletonDataProvider.GetSkeletonType()
	{
		return HandType switch
		{
			Hand.HandLeft => GlobalHandSkeletonVersion switch
			{
				OVRHandSkeletonVersion.OVR => OVRSkeleton.SkeletonType.HandLeft, 
				OVRHandSkeletonVersion.OpenXR => OVRSkeleton.SkeletonType.XRHandLeft, 
				_ => OVRSkeleton.SkeletonType.None, 
			}, 
			Hand.HandRight => GlobalHandSkeletonVersion switch
			{
				OVRHandSkeletonVersion.OVR => OVRSkeleton.SkeletonType.HandRight, 
				OVRHandSkeletonVersion.OpenXR => OVRSkeleton.SkeletonType.XRHandRight, 
				_ => OVRSkeleton.SkeletonType.None, 
			}, 
			_ => OVRSkeleton.SkeletonType.None, 
		};
	}

	OVRSkeleton.SkeletonPoseData OVRSkeleton.IOVRSkeletonDataProvider.GetSkeletonPoseData()
	{
		OVRSkeleton.SkeletonPoseData result = new OVRSkeleton.SkeletonPoseData
		{
			IsDataValid = IsDataValid
		};
		if (IsDataValid)
		{
			result.RootPose = _handState.RootPose;
			result.RootScale = _handState.HandScale;
			result.BoneRotations = _handState.BoneRotations;
			result.BoneTranslations = _handState.BonePositions;
			result.IsDataHighConfidence = IsTracked && HandConfidence == TrackingConfidence.High;
		}
		return result;
	}

	OVRSkeletonRenderer.SkeletonRendererData OVRSkeletonRenderer.IOVRSkeletonRendererDataProvider.GetSkeletonRendererData()
	{
		OVRSkeletonRenderer.SkeletonRendererData result = new OVRSkeletonRenderer.SkeletonRendererData
		{
			IsDataValid = IsDataValid
		};
		if (IsDataValid)
		{
			result.RootScale = _handState.HandScale;
			result.IsDataHighConfidence = IsTracked && HandConfidence == TrackingConfidence.High;
			result.ShouldUseSystemGestureMaterial = IsSystemGestureInProgress;
		}
		return result;
	}

	public MicrogestureType GetMicrogestureType()
	{
		OVRPlugin.SendMicrogestureHint();
		if (!_handTrackingStateValid)
		{
			return MicrogestureType.Invalid;
		}
		int microgesture = (int)_handTrackingState.Microgesture;
		if (microgesture < 0 || microgesture > 5)
		{
			return MicrogestureType.Invalid;
		}
		return (MicrogestureType)microgesture;
	}

	OVRMesh.MeshType OVRMesh.IOVRMeshDataProvider.GetMeshType()
	{
		return HandType switch
		{
			Hand.None => OVRMesh.MeshType.None, 
			Hand.HandLeft => GlobalHandSkeletonVersion switch
			{
				OVRHandSkeletonVersion.OVR => OVRMesh.MeshType.HandLeft, 
				OVRHandSkeletonVersion.OpenXR => OVRMesh.MeshType.XRHandLeft, 
				_ => OVRMesh.MeshType.None, 
			}, 
			Hand.HandRight => GlobalHandSkeletonVersion switch
			{
				OVRHandSkeletonVersion.OVR => OVRMesh.MeshType.HandRight, 
				OVRHandSkeletonVersion.OpenXR => OVRMesh.MeshType.XRHandRight, 
				_ => OVRMesh.MeshType.None, 
			}, 
			_ => OVRMesh.MeshType.None, 
		};
	}

	OVRMeshRenderer.MeshRendererData OVRMeshRenderer.IOVRMeshRendererDataProvider.GetMeshRendererData()
	{
		OVRMeshRenderer.MeshRendererData result = new OVRMeshRenderer.MeshRendererData
		{
			IsDataValid = IsDataValid
		};
		if (IsDataValid)
		{
			result.IsDataHighConfidence = IsTracked && HandConfidence == TrackingConfidence.High;
			result.ShouldUseSystemGestureMaterial = IsSystemGestureInProgress;
		}
		return result;
	}

	public void OnEnable()
	{
		OVRInputModule.TrackInputSource(this);
		SceneManager.activeSceneChanged += OnSceneChanged;
		if ((bool)RayHelper && ShouldShowHandUIRay())
		{
			RayHelper.gameObject.SetActive(value: true);
		}
	}

	public void OnDisable()
	{
		OVRInputModule.UntrackInputSource(this);
		SceneManager.activeSceneChanged -= OnSceneChanged;
		if ((bool)RayHelper)
		{
			RayHelper.gameObject.SetActive(value: false);
		}
	}

	private void OnSceneChanged(Scene unloading, Scene loading)
	{
		OVRInputModule.TrackInputSource(this);
	}

	public void OnValidate()
	{
		OVRSkeleton component = GetComponent<OVRSkeleton>();
		if (component != null && component.GetSkeletonType() != HandType.AsSkeletonType(GlobalHandSkeletonVersion))
		{
			component.SetSkeletonType(HandType.AsSkeletonType(GlobalHandSkeletonVersion));
		}
		OVRMesh component2 = GetComponent<OVRMesh>();
		if (component2 != null && component2.GetMeshType() != HandType.AsMeshType(GlobalHandSkeletonVersion))
		{
			component2.SetMeshType(HandType.AsMeshType(GlobalHandSkeletonVersion));
		}
	}

	public bool IsPressed()
	{
		return GetFingerIsPinching(HandFinger.Index);
	}

	public bool IsReleased()
	{
		return _wasReleased;
	}

	public Transform GetPointerRayTransform()
	{
		PointerPose.name = base.name;
		return PointerPose;
	}

	private bool ShouldShowHandUIRay()
	{
		if (m_showState == OVRInput.InputDeviceShowState.ControllerInHand)
		{
			return OVRPlugin.AreControllerDrivenHandPosesNatural();
		}
		return true;
	}

	public bool IsValid()
	{
		return this != null;
	}

	public bool IsActive()
	{
		if (ShouldShowHandUIRay())
		{
			return IsDataValid;
		}
		return false;
	}

	public OVRPlugin.Hand GetHand()
	{
		return (OVRPlugin.Hand)HandType;
	}

	public void UpdatePointerRay(OVRInputRayData rayData)
	{
		if ((bool)RayHelper)
		{
			rayData.ActivationStrength = GetFingerPinchStrength(HandFinger.Index);
			RayHelper.UpdatePointerRay(rayData);
		}
	}
}
[Feature(Feature.Hands)]
public class OVRHandTest : MonoBehaviour
{
	public class BoolMonitor
	{
		public delegate bool BoolGenerator();

		private string m_name = "";

		private BoolGenerator m_generator;

		private bool m_prevValue;

		private bool m_currentValue;

		private bool m_currentValueRecentlyChanged;

		private float m_displayTimeout;

		private float m_displayTimer;

		public BoolMonitor(string name, BoolGenerator generator, float displayTimeout = 0.5f)
		{
			m_name = name;
			m_generator = generator;
			m_displayTimeout = displayTimeout;
		}

		public void Update()
		{
			m_prevValue = m_currentValue;
			m_currentValue = m_generator();
			if (m_currentValue != m_prevValue)
			{
				m_currentValueRecentlyChanged = true;
				m_displayTimer = m_displayTimeout;
			}
			if (m_displayTimer > 0f)
			{
				m_displayTimer -= Time.deltaTime;
				if (m_displayTimer <= 0f)
				{
					m_currentValueRecentlyChanged = false;
					m_displayTimer = 0f;
				}
			}
		}

		public void AppendToStringBuilder(ref StringBuilder sb)
		{
			sb.Append(m_name);
			if (m_currentValue && m_currentValueRecentlyChanged)
			{
				sb.Append(": *True*\n");
			}
			else if (m_currentValue)
			{
				sb.Append(":  True \n");
			}
			else if (!m_currentValue && m_currentValueRecentlyChanged)
			{
				sb.Append(": *False*\n");
			}
			else if (!m_currentValue)
			{
				sb.Append(":  False \n");
			}
		}
	}

	public Text uiText;

	private List<BoolMonitor> monitors;

	private StringBuilder data;

	private OVRPlugin.HandState hs_LH;

	private OVRPlugin.HandState hs_RH;

	private OVRPlugin.Skeleton skel_LH;

	private OVRPlugin.Skeleton skel_RH;

	private OVRPlugin.Mesh mesh_LH = new OVRPlugin.Mesh();

	private OVRPlugin.Mesh mesh_RH = new OVRPlugin.Mesh();

	private bool result_skel_LH;

	private bool result_skel_RH;

	private bool result_mesh_LH;

	private bool result_mesh_RH;

	private static string prevConnected = "";

	private static BoolMonitor controllers = new BoolMonitor("Controllers Changed", () => OVRInput.GetConnectedControllers().ToString() != prevConnected);

	private void Start()
	{
		if (uiText != null)
		{
			uiText.supportRichText = false;
		}
		data = new StringBuilder(2048);
		monitors = new List<BoolMonitor>
		{
			new BoolMonitor("One", () => OVRInput.Get(OVRInput.Button.One))
		};
		result_skel_LH = OVRPlugin.GetSkeleton(OVRPlugin.SkeletonType.HandLeft, out skel_LH);
		result_skel_RH = OVRPlugin.GetSkeleton(OVRPlugin.SkeletonType.HandRight, out skel_RH);
		result_mesh_LH = OVRPlugin.GetMesh(OVRPlugin.MeshType.HandLeft, out mesh_LH);
		result_mesh_RH = OVRPlugin.GetMesh(OVRPlugin.MeshType.HandRight, out mesh_RH);
	}

	private void Update()
	{
		data.Length = 0;
		OVRInput.Controller activeController = OVRInput.GetActiveController();
		string arg = activeController.ToString();
		data.AppendFormat("Active: {0}\n", arg);
		string arg2 = OVRInput.GetConnectedControllers().ToString();
		data.AppendFormat("Connected: {0}\n", arg2);
		data.AppendFormat("PrevConnected: {0}\n", prevConnected);
		controllers.Update();
		controllers.AppendToStringBuilder(ref data);
		prevConnected = arg2;
		Vector3 localControllerPosition = OVRInput.GetLocalControllerPosition(activeController);
		data.AppendFormat("Position: ({0:F2}, {1:F2}, {2:F2})\n", localControllerPosition.x, localControllerPosition.y, localControllerPosition.z);
		Quaternion localControllerRotation = OVRInput.GetLocalControllerRotation(activeController);
		data.AppendFormat("Orientation: ({0:F2}, {1:F2}, {2:F2}, {3:F2})\n", localControllerRotation.x, localControllerRotation.y, localControllerRotation.z, localControllerRotation.w);
		data.AppendFormat("HandTrackingEnabled: {0}\n", OVRPlugin.GetHandTrackingEnabled());
		bool handState = OVRPlugin.GetHandState(OVRPlugin.Step.Render, OVRPlugin.Hand.HandLeft, ref hs_LH);
		data.AppendFormat("LH HS Query Res: {0}\n", handState);
		data.AppendFormat("LH HS Status: {0}\n", hs_LH.Status);
		data.AppendFormat("LH HS Pose: {0}\n", hs_LH.RootPose);
		data.AppendFormat("LH HS HandConf: {0}\n", hs_LH.HandConfidence);
		bool handState2 = OVRPlugin.GetHandState(OVRPlugin.Step.Render, OVRPlugin.Hand.HandRight, ref hs_RH);
		data.AppendFormat("RH HS Query Res: {0}\n", handState2);
		data.AppendFormat("RH HS Status: {0}\n", hs_RH.Status);
		data.AppendFormat("RH HS Pose: {0}\n", hs_RH.RootPose);
		data.AppendFormat("RH HS HandConf: {0}\n", hs_RH.HandConfidence);
		data.AppendFormat("LH Skel Query Res: {0}\n", result_skel_LH);
		data.AppendFormat("LH Skel Type: {0}\n", skel_LH.Type);
		data.AppendFormat("LH Skel NumBones: {0}\n", skel_LH.NumBones);
		data.AppendFormat("RH Skel Query Res: {0}\n", result_skel_RH);
		data.AppendFormat("RH Skel Type: {0}\n", skel_RH.Type);
		data.AppendFormat("RH Skel NumBones: {0}\n", skel_RH.NumBones);
		data.AppendFormat("LH Mesh Query Res: {0}\n", result_mesh_LH);
		data.AppendFormat("LH Mesh Type: {0}\n", mesh_LH.Type);
		data.AppendFormat("LH Mesh NumVers: {0}\n", mesh_LH.NumVertices);
		data.AppendFormat("RH Mesh Query Res: {0}\n", result_mesh_RH);
		data.AppendFormat("RH Mesh Type: {0}\n", mesh_RH.Type);
		data.AppendFormat("RH Mesh NumVers: {0}\n", mesh_RH.NumVertices);
		for (int i = 0; i < monitors.Count; i++)
		{
			monitors[i].Update();
			monitors[i].AppendToStringBuilder(ref data);
		}
		if (uiText != null)
		{
			uiText.text = data.ToString();
		}
	}
}
public class OVRMesh : MonoBehaviour
{
	public interface IOVRMeshDataProvider
	{
		MeshType GetMeshType();
	}

	public enum MeshType
	{
		None = -1,
		[InspectorName("OVR Hand (Left)")]
		HandLeft = 0,
		[InspectorName("OVR Hand (Right)")]
		HandRight = 1,
		[InspectorName("OpenXR Hand (Left)")]
		XRHandLeft = 4,
		[InspectorName("OpenXR Hand (Right)")]
		XRHandRight = 5
	}

	[SerializeField]
	private IOVRMeshDataProvider _dataProvider;

	[SerializeField]
	private MeshType _meshType = MeshType.None;

	private MeshType _loadedMeshType = MeshType.None;

	private Mesh _mesh;

	public bool IsInitialized { get; private set; }

	public Mesh Mesh => _mesh;

	internal MeshType GetMeshType()
	{
		return _meshType;
	}

	internal void SetMeshType(MeshType type)
	{
		_meshType = type;
	}

	private void Awake()
	{
		if (_dataProvider == null)
		{
			_dataProvider = GetComponent<IOVRMeshDataProvider>();
		}
		if (_dataProvider != null)
		{
			_meshType = _dataProvider.GetMeshType();
		}
		if (ShouldInitialize())
		{
			Initialize(_meshType);
		}
	}

	private bool ShouldInitialize()
	{
		if (_loadedMeshType != _meshType)
		{
			return true;
		}
		if (IsInitialized)
		{
			return false;
		}
		if (_meshType == MeshType.None)
		{
			return false;
		}
		_meshType.IsHand();
		return true;
	}

	private void Initialize(MeshType meshType)
	{
		_mesh = new Mesh();
		if (OVRPlugin.GetMesh((OVRPlugin.MeshType)meshType, out var mesh))
		{
			TransformOvrpMesh(mesh, _mesh);
			IsInitialized = true;
		}
		_loadedMeshType = meshType;
	}

	private void TransformOvrpMesh(OVRPlugin.Mesh ovrpMesh, Mesh mesh)
	{
		int numVertices = (int)ovrpMesh.NumVertices;
		int numIndices = (int)ovrpMesh.NumIndices;
		OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector3f> nativeArrayHelper = new OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector3f>(ovrpMesh.VertexPositions, numVertices);
		try
		{
			OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector3f> nativeArrayHelper2 = new OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector3f>(ovrpMesh.VertexNormals, numVertices);
			try
			{
				OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector2f> nativeArrayHelper3 = new OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector2f>(ovrpMesh.VertexUV0, numVertices);
				try
				{
					OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector4f> nativeArrayHelper4 = new OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector4f>(ovrpMesh.BlendWeights, numVertices);
					try
					{
						OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector4s> nativeArrayHelper5 = new OVRMeshJobs.NativeArrayHelper<OVRPlugin.Vector4s>(ovrpMesh.BlendIndices, numVertices);
						try
						{
							OVRMeshJobs.NativeArrayHelper<short> nativeArrayHelper6 = new OVRMeshJobs.NativeArrayHelper<short>(ovrpMesh.Indices, numIndices);
							try
							{
								using NativeArray<Vector3> vertices = new NativeArray<Vector3>(numVertices, Allocator.TempJob);
								using NativeArray<Vector3> normals = new NativeArray<Vector3>(numVertices, Allocator.TempJob);
								using NativeArray<Vector2> uV = new NativeArray<Vector2>(numVertices, Allocator.TempJob);
								using NativeArray<BoneWeight> boneWeights = new NativeArray<BoneWeight>(numVertices, Allocator.TempJob);
								using NativeArray<uint> triangles = new NativeArray<uint>(numIndices, Allocator.TempJob);
								OVRMeshJobs.TransformToUnitySpaceJob jobData = new OVRMeshJobs.TransformToUnitySpaceJob
								{
									Vertices = vertices,
									Normals = normals,
									UV = uV,
									BoneWeights = boneWeights,
									MeshVerticesPosition = nativeArrayHelper.UnityNativeArray,
									MeshNormals = nativeArrayHelper2.UnityNativeArray,
									MeshUV = nativeArrayHelper3.UnityNativeArray,
									MeshBoneWeights = nativeArrayHelper4.UnityNativeArray,
									MeshBoneIndices = nativeArrayHelper5.UnityNativeArray
								};
								OVRMeshJobs.TransformTrianglesJob jobData2 = new OVRMeshJobs.TransformTrianglesJob
								{
									Triangles = triangles,
									MeshIndices = nativeArrayHelper6.UnityNativeArray,
									NumIndices = numIndices
								};
								JobHandle job = jobData.Schedule(numVertices, 20);
								JobHandle job2 = jobData2.Schedule(numIndices, 60);
								JobHandle.CombineDependencies(job, job2).Complete();
								mesh.SetVertices(jobData.Vertices);
								mesh.SetNormals(jobData.Normals);
								mesh.SetUVs(0, jobData.UV);
								mesh.boneWeights = jobData.BoneWeights.ToArray();
								mesh.SetIndexBufferParams(numIndices, IndexFormat.UInt32);
								mesh.SetIndexBufferData(jobData2.Triangles, 0, 0, numIndices);
								mesh.SetSubMesh(0, new SubMeshDescriptor(0, numIndices));
							}
							finally
							{
								((IDisposable)nativeArrayHelper6/*cast due to constrained. prefix*/).Dispose();
							}
						}
						finally
						{
							((IDisposable)nativeArrayHelper5/*cast due to constrained. prefix*/).Dispose();
						}
					}
					finally
					{
						((IDisposable)nativeArrayHelper4/*cast due to constrained. prefix*/).Dispose();
					}
				}
				finally
				{
					((IDisposable)nativeArrayHelper3/*cast due to constrained. prefix*/).Dispose();
				}
			}
			finally
			{
				((IDisposable)nativeArrayHelper2/*cast due to constrained. prefix*/).Dispose();
			}
		}
		finally
		{
			((IDisposable)nativeArrayHelper/*cast due to constrained. prefix*/).Dispose();
		}
	}
}
public class OVRMeshJobs
{
	public struct TransformToUnitySpaceJob : IJobParallelFor
	{
		public NativeArray<Vector3> Vertices;

		public NativeArray<Vector3> Normals;

		public NativeArray<Vector2> UV;

		public NativeArray<BoneWeight> BoneWeights;

		public NativeArray<OVRPlugin.Vector3f> MeshVerticesPosition;

		public NativeArray<OVRPlugin.Vector3f> MeshNormals;

		public NativeArray<OVRPlugin.Vector2f> MeshUV;

		public NativeArray<OVRPlugin.Vector4f> MeshBoneWeights;

		public NativeArray<OVRPlugin.Vector4s> MeshBoneIndices;

		public void Execute(int index)
		{
			Vertices[index] = MeshVerticesPosition[index].FromFlippedXVector3f();
			Normals[index] = MeshNormals[index].FromFlippedXVector3f();
			UV[index] = new Vector2
			{
				x = MeshUV[index].x,
				y = 0f - MeshUV[index].y
			};
			OVRPlugin.Vector4f vector4f = MeshBoneWeights[index];
			OVRPlugin.Vector4s vector4s = MeshBoneIndices[index];
			BoneWeights[index] = new BoneWeight
			{
				boneIndex0 = vector4s.x,
				weight0 = vector4f.x,
				boneIndex1 = vector4s.y,
				weight1 = vector4f.y,
				boneIndex2 = vector4s.z,
				weight2 = vector4f.z,
				boneIndex3 = vector4s.w,
				weight3 = vector4f.w
			};
		}
	}

	public struct TransformTrianglesJob : IJobParallelFor
	{
		public NativeArray<uint> Triangles;

		[Unity.Collections.ReadOnly]
		public NativeArray<short> MeshIndices;

		public int NumIndices;

		public void Execute(int index)
		{
			Triangles[index] = (uint)MeshIndices[NumIndices - index - 1];
		}
	}

	public struct NativeArrayHelper<T> : IDisposable where T : struct
	{
		public NativeArray<T> UnityNativeArray;

		private GCHandle _handle;

		public unsafe NativeArrayHelper(T[] ovrArray, int length)
		{
			_handle = GCHandle.Alloc(ovrArray, GCHandleType.Pinned);
			IntPtr intPtr = _handle.AddrOfPinnedObject();
			UnityNativeArray = NativeArrayUnsafeUtility.ConvertExistingDataToNativeArray<T>((void*)intPtr, length, Allocator.None);
		}

		public void Dispose()
		{
			_handle.Free();
		}
	}
}
public class OVRMeshRenderer : MonoBehaviour
{
	public interface IOVRMeshRendererDataProvider
	{
		MeshRendererData GetMeshRendererData();
	}

	public struct MeshRendererData
	{
		public bool IsDataValid { get; set; }

		public bool IsDataHighConfidence { get; set; }

		public bool ShouldUseSystemGestureMaterial { get; set; }
	}

	public enum ConfidenceBehavior
	{
		None,
		ToggleRenderer
	}

	public enum SystemGestureBehavior
	{
		None,
		SwapMaterial
	}

	[SerializeField]
	private IOVRMeshRendererDataProvider _dataProvider;

	[SerializeField]
	private OVRMesh _ovrMesh;

	[SerializeField]
	private OVRSkeleton _ovrSkeleton;

	[SerializeField]
	private ConfidenceBehavior _confidenceBehavior = ConfidenceBehavior.ToggleRenderer;

	[SerializeField]
	private SystemGestureBehavior _systemGestureBehavior = SystemGestureBehavior.SwapMaterial;

	[SerializeField]
	private Material _systemGestureMaterial;

	private Material _originalMaterial;

	private SkinnedMeshRenderer _skinnedMeshRenderer;

	private static readonly Matrix4x4 _openXRFixup = Matrix4x4.Rotate(new Quaternion(0f, 1f, 0f, 0f));

	public bool IsInitialized { get; private set; }

	public bool IsDataValid { get; private set; }

	public bool IsDataHighConfidence { get; private set; }

	public bool ShouldUseSystemGestureMaterial { get; private set; }

	private void Awake()
	{
		if (_dataProvider == null)
		{
			_dataProvider = GetComponent<IOVRMeshRendererDataProvider>();
		}
		if (_ovrMesh == null)
		{
			_ovrMesh = GetComponent<OVRMesh>();
		}
		if (_ovrSkeleton == null)
		{
			_ovrSkeleton = GetComponent<OVRSkeleton>();
		}
	}

	private void Start()
	{
		if (_ovrMesh == null)
		{
			base.enabled = false;
		}
		else if (ShouldInitialize())
		{
			Initialize();
		}
	}

	private bool ShouldInitialize()
	{
		if (IsInitialized)
		{
			return false;
		}
		if (_ovrMesh == null || (_ovrMesh != null && !_ovrMesh.IsInitialized) || (_ovrSkeleton != null && !_ovrSkeleton.IsInitialized))
		{
			return false;
		}
		return true;
	}

	public void ForceRebind()
	{
		IsInitialized = false;
		Initialize();
	}

	private void Initialize()
	{
		_skinnedMeshRenderer = GetComponent<SkinnedMeshRenderer>();
		if (!_skinnedMeshRenderer)
		{
			_skinnedMeshRenderer = base.gameObject.AddComponent<SkinnedMeshRenderer>();
		}
		_skinnedMeshRenderer.sharedMesh = _ovrMesh.Mesh;
		_originalMaterial = _skinnedMeshRenderer.sharedMaterial;
		if (_ovrSkeleton != null)
		{
			OVRSkeleton.SkeletonType skeletonType = _ovrSkeleton.GetSkeletonType();
			int currentNumSkinnableBones = _ovrSkeleton.GetCurrentNumSkinnableBones();
			Matrix4x4[] array = new Matrix4x4[currentNumSkinnableBones];
			Transform[] array2 = new Transform[currentNumSkinnableBones];
			Matrix4x4 localToWorldMatrix = base.transform.localToWorldMatrix;
			for (int i = 0; i < currentNumSkinnableBones && i < _ovrSkeleton.Bones.Count; i++)
			{
				array2[i] = _ovrSkeleton.Bones[i].Transform;
				array[i] = _ovrSkeleton.BindPoses[i].Transform.worldToLocalMatrix * localToWorldMatrix;
				if (skeletonType.IsOpenXRHandSkeleton())
				{
					array[i] *= _openXRFixup;
				}
			}
			_ovrMesh.Mesh.bindposes = array;
			_skinnedMeshRenderer.bones = array2;
			_skinnedMeshRenderer.updateWhenOffscreen = true;
		}
		IsInitialized = true;
	}

	private void Update()
	{
		IsDataValid = false;
		IsDataHighConfidence = false;
		ShouldUseSystemGestureMaterial = false;
		if (!IsInitialized)
		{
			return;
		}
		bool flag = false;
		if (_dataProvider != null)
		{
			MeshRendererData meshRendererData = _dataProvider.GetMeshRendererData();
			IsDataValid = meshRendererData.IsDataValid;
			IsDataHighConfidence = meshRendererData.IsDataHighConfidence;
			ShouldUseSystemGestureMaterial = meshRendererData.ShouldUseSystemGestureMaterial;
			flag = meshRendererData.IsDataValid && meshRendererData.IsDataHighConfidence;
		}
		if (_confidenceBehavior == ConfidenceBehavior.ToggleRenderer && _skinnedMeshRenderer != null && _skinnedMeshRenderer.enabled != flag)
		{
			_skinnedMeshRenderer.enabled = flag;
		}
		if (_systemGestureBehavior == SystemGestureBehavior.SwapMaterial && _skinnedMeshRenderer != null)
		{
			if (ShouldUseSystemGestureMaterial && _systemGestureMaterial != null && _skinnedMeshRenderer.sharedMaterial != _systemGestureMaterial)
			{
				_skinnedMeshRenderer.sharedMaterial = _systemGestureMaterial;
			}
			else if (!ShouldUseSystemGestureMaterial && _originalMaterial != null && _skinnedMeshRenderer.sharedMaterial != _originalMaterial)
			{
				_skinnedMeshRenderer.sharedMaterial = _originalMaterial;
			}
		}
	}
}
