	public void WriteToConfigurationFile()
	{
		string contents = JsonUtility.ToJson(this, prettyPrint: true);
		try
		{
			string text = Path.Combine(Application.dataPath, "mrc.config");
			UnityEngine.Debug.Log("Write OVRMixedRealityCaptureSettings to " + text);
			File.WriteAllText(text, contents);
		}
		catch (Exception ex)
		{
			UnityEngine.Debug.LogWarning("Exception caught " + ex.Message);
		}
	}

	public void CombineWithConfigurationFile()
	{
		try
		{
			string text = Path.Combine(Application.dataPath, "mrc.config");
			if (File.Exists(text))
			{
				UnityEngine.Debug.Log("MixedRealityCapture configuration file found at " + text);
				string json = File.ReadAllText(text);
				UnityEngine.Debug.Log("Apply MixedRealityCapture configuration");
				JsonUtility.FromJsonOverwrite(json, this);
			}
			else
			{
				UnityEngine.Debug.Log("MixedRealityCapture configuration file doesn't exist at " + text);
			}
		}
		catch (Exception ex)
		{
			UnityEngine.Debug.LogWarning("Exception caught " + ex.Message);
		}
	}
}
public class OVRMixedRealityCaptureTest : MonoBehaviour
{
	private enum CameraMode
	{
		Normal,
		OverrideFov,
		ThirdPerson
	}

	private bool inited;

	private CameraMode currentMode;

	public Camera defaultExternalCamera;

	private OVRPlugin.Fovf defaultFov;

	private void Start()
	{
		if (!defaultExternalCamera)
		{
			UnityEngine.Debug.LogWarning("defaultExternalCamera undefined");
		}
		if (!OVRManager.instance.enableMixedReality)
		{
			OVRManager.instance.enableMixedReality = true;
		}
	}

	private void Initialize()
	{
		if (!inited && OVRPlugin.IsMixedRealityInitialized())
		{
			OVRPlugin.ResetDefaultExternalCamera();
			UnityEngine.Debug.LogFormat("GetExternalCameraCount before adding manual external camera {0}", OVRPlugin.GetExternalCameraCount());
			UpdateDefaultExternalCamera();
			UnityEngine.Debug.LogFormat("GetExternalCameraCount after adding manual external camera {0}", OVRPlugin.GetExternalCameraCount());
			OVRPlugin.GetMixedRealityCameraInfo(0, out var _, out var cameraIntrinsics);
			defaultFov = cameraIntrinsics.FOVPort;
			inited = true;
		}
	}

	private void UpdateDefaultExternalCamera()
	{
		OVRPlugin.CameraIntrinsics cameraIntrinsics = default(OVRPlugin.CameraIntrinsics);
		OVRPlugin.CameraExtrinsics cameraExtrinsics = default(OVRPlugin.CameraExtrinsics);
		cameraIntrinsics.IsValid = OVRPlugin.Bool.True;
		cameraIntrinsics.LastChangedTimeSeconds = Time.time;
		float num = defaultExternalCamera.fieldOfView * (MathF.PI / 180f);
		float num2 = Mathf.Atan(Mathf.Tan(num * 0.5f) * 1.7777778f) * 2f;
		OVRPlugin.Fovf fOVPort = default(OVRPlugin.Fovf);
		fOVPort.UpTan = (fOVPort.DownTan = Mathf.Tan(num * 0.5f));
		fOVPort.LeftTan = (fOVPort.RightTan = Mathf.Tan(num2 * 0.5f));
		cameraIntrinsics.FOVPort = fOVPort;
		cameraIntrinsics.VirtualNearPlaneDistanceMeters = defaultExternalCamera.nearClipPlane;
		cameraIntrinsics.VirtualFarPlaneDistanceMeters = defaultExternalCamera.farClipPlane;
		cameraIntrinsics.ImageSensorPixelResolution.w = 1920;
		cameraIntrinsics.ImageSensorPixelResolution.h = 1080;
		cameraExtrinsics.IsValid = OVRPlugin.Bool.True;
		cameraExtrinsics.LastChangedTimeSeconds = Time.time;
		cameraExtrinsics.CameraStatusData = OVRPlugin.CameraStatus.CameraStatus_Calibrated;
		cameraExtrinsics.AttachedToNode = OVRPlugin.Node.None;
		OVRCameraRig componentInParent = Camera.main.GetComponentInParent<OVRCameraRig>();
		if ((bool)componentInParent)
		{
			OVRPose oVRPose = componentInParent.trackingSpace.ToOVRPose();
			OVRPose oVRPose2 = defaultExternalCamera.transform.ToOVRPose();
			cameraExtrinsics.RelativePose = (oVRPose.Inverse() * oVRPose2).ToPosef();
		}
		else
		{
			cameraExtrinsics.RelativePose = OVRPlugin.Posef.identity;
		}
		if (!OVRPlugin.SetDefaultExternalCamera("UnityExternalCamera", ref cameraIntrinsics, ref cameraExtrinsics))
		{
			UnityEngine.Debug.LogError("SetDefaultExternalCamera() failed");
		}
	}

	private void Update()
	{
		if (!inited)
		{
			Initialize();
		}
		else
		{
			if (!defaultExternalCamera || !OVRPlugin.IsMixedRealityInitialized())
			{
				return;
			}
			if (OVRInput.GetDown(OVRInput.Button.One))
			{
				if (currentMode == CameraMode.ThirdPerson)
				{
					currentMode = CameraMode.Normal;
				}
				else
				{
					currentMode++;
				}
				UnityEngine.Debug.LogFormat("Camera mode change to {0}", currentMode);
			}
			if (currentMode == CameraMode.Normal)
			{
				UpdateDefaultExternalCamera();
				OVRPlugin.OverrideExternalCameraFov(0, useOverriddenFov: false, default(OVRPlugin.Fovf));
				OVRPlugin.OverrideExternalCameraStaticPose(0, useOverriddenPose: false, OVRPlugin.Posef.identity);
			}
			else if (currentMode == CameraMode.OverrideFov)
			{
				OVRPlugin.Fovf fovf = defaultFov;
				OVRPlugin.OverrideExternalCameraFov(0, useOverriddenFov: true, new OVRPlugin.Fovf
				{
					LeftTan = fovf.LeftTan * 2f,
					RightTan = fovf.RightTan * 2f,
					UpTan = fovf.UpTan * 2f,
					DownTan = fovf.DownTan * 2f
				});
				OVRPlugin.OverrideExternalCameraStaticPose(0, useOverriddenPose: false, OVRPlugin.Posef.identity);
				if (!OVRPlugin.GetUseOverriddenExternalCameraFov(0))
				{
					UnityEngine.Debug.LogWarning("FOV not overridden");
				}
			}
			else
			{
				if (currentMode != CameraMode.ThirdPerson)
				{
					return;
				}
				Camera component = GetComponent<Camera>();
				if (!(component == null))
				{
					float num = component.fieldOfView * (MathF.PI / 180f);
					float num2 = Mathf.Atan(Mathf.Tan(num * 0.5f) * component.aspect) * 2f;
					OVRPlugin.Fovf fov = default(OVRPlugin.Fovf);
					fov.UpTan = (fov.DownTan = Mathf.Tan(num * 0.5f));
					fov.LeftTan = (fov.RightTan = Mathf.Tan(num2 * 0.5f));
					OVRPlugin.OverrideExternalCameraFov(0, useOverriddenFov: true, fov);
					OVRCameraRig componentInParent = Camera.main.GetComponentInParent<OVRCameraRig>();
					if ((bool)componentInParent)
					{
						OVRPose oVRPose = componentInParent.trackingSpace.ToOVRPose();
						OVRPose oVRPose2 = base.transform.ToOVRPose();
						OVRPose oVRPose3 = oVRPose.Inverse() * oVRPose2;
						OVRPlugin.Posef poseInStageOrigin = (OVRPlugin.GetTrackingTransformRelativePose(OVRPlugin.TrackingOrigin.Stage).ToOVRPose().Inverse() * oVRPose3).ToPosef();
						OVRPlugin.OverrideExternalCameraStaticPose(0, useOverriddenPose: true, poseInStageOrigin);
					}
					else
					{
						OVRPlugin.OverrideExternalCameraStaticPose(0, useOverriddenPose: false, OVRPlugin.Posef.identity);
					}
					if (!OVRPlugin.GetUseOverriddenExternalCameraFov(0))
					{
						UnityEngine.Debug.LogWarning("FOV not overridden");
					}
					if (!OVRPlugin.GetUseOverriddenExternalCameraStaticPose(0))
					{
						UnityEngine.Debug.LogWarning("StaticPose not overridden");
					}
				}
			}
		}
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-core-overview/#scripts")]
public class OVRModeParms : MonoBehaviour
{
	public OVRInput.RawButton resetButton = OVRInput.RawButton.X;

	private void Start()
	{
		if (!OVRManager.isHmdPresent)
		{
			base.enabled = false;
		}
		else
		{
			InvokeRepeating("TestPowerStateMode", 10f, 10f);
		}
	}

	private void Update()
	{
		if (OVRInput.GetDown(resetButton))
		{
			OVRPlugin.suggestedCpuPerfLevel = OVRPlugin.ProcessorPerformanceLevel.PowerSavings;
			OVRPlugin.suggestedGpuPerfLevel = OVRPlugin.ProcessorPerformanceLevel.SustainedLow;
		}
	}

	private void TestPowerStateMode()
	{
		if (OVRPlugin.powerSaving)
		{
			UnityEngine.Debug.Log("POWER SAVE MODE ACTIVATED");
		}
	}
}
[HelpURL("https://developer.oculus.com/documentation/unity/unity-core-overview/#scriptss")]
public class OVRMonoscopic : MonoBehaviour
{
	public OVRInput.RawButton toggleButton = OVRInput.RawButton.B;

	private bool monoscopic;

	private void Update()
	{
		if (OVRInput.GetDown(toggleButton))
		{
			monoscopic = !monoscopic;
			OVRManager.instance.monoscopic = monoscopic;
		}
	}
}
internal struct OVRNativeList<T> : IDisposable, IReadOnlyList<T>, IEnumerable<T>, IEnumerable, IReadOnlyCollection<T> where T : unmanaged
{
	private NativeArray<T> _array;

	private readonly Allocator _allocator;

	public int Count { get; private set; }

	public int Capacity => _array.Length;

	public bool IsCreated => _array.IsCreated;

	public unsafe T* Data
	{
		get
		{
			if (!IsCreated)
			{
				return null;
			}
			return (T*)_array.GetUnsafePtr();
		}
	}

	public T this[int index]
	{
		get
		{
			if (index >= Count)
			{
				throw new IndexOutOfRangeException(string.Format("{0} ({1}) must be less than {2} ({3}).", "index", index, "Count", Count));
			}
			return _array[index];
		}
		set
		{
			if (index >= Count)
			{
				throw new IndexOutOfRangeException(string.Format("{0} ({1}) must be less than {2} ({3}).", "index", index, "Count", Count));
			}
			_array[index] = value;
		}
	}

	public OVRNativeList(int? initialCapacity, Allocator allocator)
	{
		_array = (initialCapacity.HasValue ? new NativeArray<T>(initialCapacity.Value, allocator) : default(NativeArray<T>));
		_allocator = allocator;
		Count = 0;
	}

	public OVRNativeList(Allocator allocator)
	{
		_array = default(NativeArray<T>);
		_allocator = allocator;
		Count = 0;
	}

	public unsafe T* PtrToElementAt(int index)
	{
		if (index < 0)
		{
			throw new ArgumentOutOfRangeException("index", index, "index must be greater than or equal to zero.");
		}
		if (index >= Count)
		{
			throw new ArgumentOutOfRangeException("index", index, string.Format("{0} must be less than {1} ({2}).", "index", "Count", Count));
		}
		return Data + index;
	}

	public NativeArray<T> AsNativeArray()
	{
		return _array.GetSubArray(0, Count);
	}

	public unsafe Span<T> AsSpan()
	{
		return new Span<T>(Data, Count);
	}

	public unsafe ReadOnlySpan<T> AsReadOnlySpan()
	{
		return new ReadOnlySpan<T>(Data, Count);
	}

	public NativeArray<T>.Enumerator GetEnumerator()
	{
		return AsNativeArray().GetEnumerator();
	}

	public void Add(T item)
	{
		EnsureCapacity(Count + 1);
		_array[Count++] = item;
	}

	public unsafe void AddRange(IEnumerable<T> collection)
	{
		OVREnumerable<T> oVREnumerable = collection.ToNonAlloc();
		if (oVREnumerable.TryGetCount(out var count))
		{
			EnsureCapacity(Count + count);
			if (collection is T[] array)
			{
				fixed (T* source = array)
				{
					UnsafeUtility.MemCpy(Data + Count, source, sizeof(T) * array.Length);
				}
				Count += count;
				return;
			}
		}
		foreach (T item in oVREnumerable)
		{
			Add(item);
		}
	}

	public void Clear()
	{
		Count = 0;
	}

	public void Dispose()
	{
		if (_array.IsCreated)
		{
			_array.Dispose();
			_array = default(NativeArray<T>);
		}
		Count = 0;
	}

	public JobHandle Dispose(JobHandle dependency)
	{
		Count = 0;
		return _array.Dispose(dependency);
	}

	public unsafe static implicit operator T*(OVRNativeList<T> list)
	{
		return list.Data;
	}

	public static implicit operator Span<T>(OVRNativeList<T> list)
	{
		return list.AsSpan();
	}

	public static implicit operator ReadOnlySpan<T>(OVRNativeList<T> list)
	{
		return list.AsReadOnlySpan();
	}

	IEnumerator<T> IEnumerable<T>.GetEnumerator()
	{
		return GetEnumerator();
	}

	IEnumerator IEnumerable.GetEnumerator()
	{
		return GetEnumerator();
	}

	private unsafe void EnsureCapacity(int capacity)
	{
		if (Capacity < capacity)
		{
			capacity = Math.Max(capacity, Math.Max(4, Capacity * 3 / 2));
			NativeArray<T> nativeArray = new NativeArray<T>(capacity, _allocator);
			if (_array.IsCreated)
			{
				UnsafeUtility.MemCpy(nativeArray.GetUnsafePtr(), _array.GetUnsafeReadOnlyPtr(), sizeof(T) * Count);
				_array.Dispose();
			}
			_array = nativeArray;
		}
	}
}
internal static class OVRNativeList
{
	public readonly struct CapacityHelper(int? count)
	{
		private readonly int? _count = count;

		public OVRNativeList<T> AllocateEmpty<T>(Allocator allocator) where T : unmanaged
		{
			return new OVRNativeList<T>(_count, allocator);
		}
	}

	public static CapacityHelper WithSuggestedCapacityFrom<T>([NoEnumeration] IEnumerable<T> collection)
	{
		return new CapacityHelper(collection.ToNonAlloc().Count);
	}

	public static CapacityHelper WithSuggestedCapacityFrom<T>([NoEnumeration] IEnumerable<T> collection, out OVREnumerable<T> nonAllocatingEnumerable)
	{
		nonAllocatingEnumerable = collection.ToNonAlloc();
		return new CapacityHelper(nonAllocatingEnumerable.Count);
	}

	public static OVRNativeList<T> ToNativeList<T>(this IEnumerable<T> collection, Allocator allocator) where T : unmanaged
	{
		OVRNativeList<T> result = new OVRNativeList<T>(allocator);
		result.AddRange(collection);
		return result;
	}
}
public class OVRNetwork
{
	[StructLayout(LayoutKind.Sequential, Pack = 1)]
	private struct FrameHeader
	{
		public uint protocolIdentifier;

		public int payloadType;

		public int payloadLength;

		public const int StructSize = 12;

		public byte[] ToBytes()
		{
			int num = Marshal.SizeOf(this);
			byte[] array = new byte[num];
			IntPtr intPtr = Marshal.AllocHGlobal(num);
			Marshal.StructureToPtr(this, intPtr, fDeleteOld: true);
			Marshal.Copy(intPtr, array, 0, num);
			Marshal.FreeHGlobal(intPtr);
			return array;
		}

		public static FrameHeader FromBytes(byte[] arr)
		{
			FrameHeader frameHeader = default(FrameHeader);
			int num = Marshal.SizeOf(frameHeader);
			IntPtr intPtr = Marshal.AllocHGlobal(num);
			Marshal.Copy(arr, 0, intPtr, num);
			frameHeader = (FrameHeader)Marshal.PtrToStructure(intPtr, frameHeader.GetType());
			Marshal.FreeHGlobal(intPtr);
			return frameHeader;
		}
	}

	public class OVRNetworkTcpServer
	{
		public TcpListener tcpListener;

		private readonly object clientsLock = new object();

		public readonly List<TcpClient> clients = new List<TcpClient>();

		public void StartListening(int listeningPort)
		{
			if (tcpListener != null)
			{
				UnityEngine.Debug.LogWarning("[OVRNetworkTcpServer] tcpListener is not null");
				return;
			}
			IPAddress any = IPAddress.Any;
			tcpListener = new TcpListener(any, listeningPort);
			try
			{
				tcpListener.Start();
				UnityEngine.Debug.LogFormat("TcpListener started. Local endpoint: {0}", tcpListener.LocalEndpoint.ToString());
			}
			catch (SocketException ex)
			{
				UnityEngine.Debug.LogWarningFormat("[OVRNetworkTcpServer] Unsable to start TcpListener. Socket exception: {0}", ex.Message);
				UnityEngine.Debug.LogWarning("It could be caused by multiple instances listening at the same port, or the port is forwarded to the Android device through ADB");
				UnityEngine.Debug.LogWarning("If the port is forwarded through ADB, use the Android Tools in Tools/Oculus/System Metrics Profiler to kill the server");
				tcpListener = null;
			}
			if (tcpListener == null)
			{
				return;
			}
			UnityEngine.Debug.LogFormat("[OVRNetworkTcpServer] Start Listening on port {0}", listeningPort);
			try
			{
				tcpListener.BeginAcceptTcpClient(DoAcceptTcpClientCallback, tcpListener);
			}
			catch (Exception ex2)
			{
				UnityEngine.Debug.LogWarningFormat("[OVRNetworkTcpServer] can't accept new client: {0}", ex2.Message);
			}
		}

		public void StopListening()
		{
			if (tcpListener == null)
			{
				UnityEngine.Debug.LogWarning("[OVRNetworkTcpServer] tcpListener is null");
				return;
			}
			lock (clientsLock)
			{
				clients.Clear();
			}
			tcpListener.Stop();
			tcpListener = null;
			UnityEngine.Debug.Log("[OVRNetworkTcpServer] Stopped listening");
		}

		private void DoAcceptTcpClientCallback(IAsyncResult ar)
		{
			TcpListener tcpListener = ar.AsyncState as TcpListener;
			try
			{
				TcpClient item = tcpListener.EndAcceptTcpClient(ar);
				lock (clientsLock)
				{
					clients.Add(item);
					UnityEngine.Debug.Log("[OVRNetworkTcpServer] client added");
				}
				try
				{
					this.tcpListener.BeginAcceptTcpClient(DoAcceptTcpClientCallback, this.tcpListener);
				}
				catch (Exception ex)
				{
					UnityEngine.Debug.LogWarningFormat("[OVRNetworkTcpServer] can't accept new client: {0}", ex.Message);
				}
			}
			catch (ObjectDisposedException)
			{
			}
			catch (Exception ex3)
			{
				UnityEngine.Debug.LogWarningFormat("[OVRNetworkTcpServer] EndAcceptTcpClient failed: {0}", ex3.Message);
			}
		}

		public bool HasConnectedClient()
		{
			lock (clientsLock)
			{
				foreach (TcpClient client in clients)
				{
					if (client.Connected)
					{
						return true;
					}
				}
			}
			return false;
		}

		public void Broadcast(int payloadType, byte[] payload)
		{
			if (payload.Length > 65524)
			{
				UnityEngine.Debug.LogWarningFormat("[OVRNetworkTcpServer] drop payload because it's too long: {0} bytes", payload.Length);
			}
			byte[] array = new FrameHeader
			{
				protocolIdentifier = 1384359787u,
				payloadType = payloadType,
				payloadLength = payload.Length
			}.ToBytes();
			byte[] array2 = new byte[array.Length + payload.Length];
			array.CopyTo(array2, 0);
			payload.CopyTo(array2, array.Length);
			lock (clientsLock)
			{
				foreach (TcpClient client in clients)
				{
					if (client.Connected)
					{
						try
						{
							client.GetStream().BeginWrite(array2, 0, array2.Length, DoWriteDataCallback, client.GetStream());
						}
						catch (SocketException ex)
						{
							UnityEngine.Debug.LogWarningFormat("[OVRNetworkTcpServer] close client because of socket error: {0}", ex.Message);
							client.GetStream().Close();
							client.Close();
						}
					}
				}
			}
		}

		private void DoWriteDataCallback(IAsyncResult ar)
		{
			(ar.AsyncState as NetworkStream).EndWrite(ar);
		}
	}

	public class OVRNetworkTcpClient
	{
		public enum ConnectionState
		{
			Disconnected,
			Connected,
			Connecting
		}

		public Action connectionStateChangedCallback;

		public Action<int, byte[], int, int> payloadReceivedCallback;

		private TcpClient tcpClient;

		private byte[][] receivedBuffers = new byte[2][]
		{
			new byte[65536],
			new byte[65536]
		};

		private int receivedBufferIndex;

		private int receivedBufferDataSize;

		private ManualResetEvent readyReceiveDataEvent = new ManualResetEvent(initialState: true);

		public ConnectionState connectionState
		{
			get
			{
				if (tcpClient == null)
				{
					return ConnectionState.Disconnected;
				}
				if (tcpClient.Connected)
				{
					return ConnectionState.Connected;
				}
				return ConnectionState.Connecting;
			}
		}

		public bool Connected => connectionState == ConnectionState.Connected;

		public void Connect(int listeningPort)
		{
			if (tcpClient == null)
			{
				receivedBufferIndex = 0;
				receivedBufferDataSize = 0;
				readyReceiveDataEvent.Set();
				string host = "127.0.0.1";
				tcpClient = new TcpClient(AddressFamily.InterNetwork);
				tcpClient.BeginConnect(host, listeningPort, ConnectCallback, tcpClient);
				if (connectionStateChangedCallback != null)
				{
					connectionStateChangedCallback();
				}
			}
			else
			{
				UnityEngine.Debug.LogWarning("[OVRNetworkTcpClient] already connected");
			}
		}

		private void ConnectCallback(IAsyncResult ar)
		{
			try
			{
				TcpClient tcpClient = ar.AsyncState as TcpClient;
				tcpClient.EndConnect(ar);
				UnityEngine.Debug.LogFormat("[OVRNetworkTcpClient] connected to {0}", tcpClient.ToString());
			}
			catch (Exception ex)
			{
				UnityEngine.Debug.LogWarningFormat("[OVRNetworkTcpClient] connect error {0}", ex.Message);
			}
			if (connectionStateChangedCallback != null)
			{
				connectionStateChangedCallback();
			}
		}

		public void Disconnect()
		{
			if (tcpClient != null)
			{
				if (!readyReceiveDataEvent.WaitOne(5))
				{
					UnityEngine.Debug.LogWarning("[OVRNetworkTcpClient] readyReceiveDataEvent not signaled. data receiving timeout?");
				}
				UnityEngine.Debug.Log("[OVRNetworkTcpClient] close tcpClient");
				try
				{
					tcpClient.GetStream().Close();
					tcpClient.Close();
				}
				catch (Exception ex)
				{
					UnityEngine.Debug.LogWarning("[OVRNetworkTcpClient] " + ex.Message);
				}
				tcpClient = null;
				if (connectionStateChangedCallback != null)
				{
					connectionStateChangedCallback();
				}
			}
			else
			{
				UnityEngine.Debug.LogWarning("[OVRNetworkTcpClient] not connected");
			}
		}

		public void Tick()
		{
			if (tcpClient != null && tcpClient.Connected && readyReceiveDataEvent.WaitOne(TimeSpan.Zero) && tcpClient.GetStream().DataAvailable)
			{
				if (receivedBufferDataSize >= 65536)
				{
					UnityEngine.Debug.LogWarning("[OVRNetworkTcpClient] receive buffer overflow. It should not happen since we have the constraint on message size");
					Disconnect();
				}
				else
				{
					readyReceiveDataEvent.Reset();
					int count = 65536 - receivedBufferDataSize;
					tcpClient.GetStream().BeginRead(receivedBuffers[receivedBufferIndex], receivedBufferDataSize, count, OnReadDataCallback, tcpClient.GetStream());
				}
			}
		}

		private void OnReadDataCallback(IAsyncResult ar)
		{
			NetworkStream networkStream = ar.AsyncState as NetworkStream;
			try
			{
				int num = networkStream.EndRead(ar);
				receivedBufferDataSize += num;
				while (receivedBufferDataSize >= 12)
				{
					FrameHeader frameHeader = FrameHeader.FromBytes(receivedBuffers[receivedBufferIndex]);
					if (frameHeader.protocolIdentifier != 1384359787)
					{
						UnityEngine.Debug.LogWarning("[OVRNetworkTcpClient] header mismatch");
						Disconnect();
						return;
					}
					if (frameHeader.payloadLength < 0 || frameHeader.payloadLength > 65524)
					{
						UnityEngine.Debug.LogWarningFormat("[OVRNetworkTcpClient] Sanity check failed. PayloadLength %d", frameHeader.payloadLength);
						Disconnect();
						return;
					}
					if (receivedBufferDataSize >= 12 + frameHeader.payloadLength)
					{
						if (payloadReceivedCallback != null)
						{
							payloadReceivedCallback(frameHeader.payloadType, receivedBuffers[receivedBufferIndex], 12, frameHeader.payloadLength);
						}
						int num2 = 1 - receivedBufferIndex;
						int num3 = receivedBufferDataSize - (12 + frameHeader.payloadLength);
						if (num3 > 0)
						{
							Array.Copy(receivedBuffers[receivedBufferIndex], 12 + frameHeader.payloadLength, receivedBuffers[num2], 0, num3);
						}
						receivedBufferIndex = num2;
						receivedBufferDataSize = num3;
					}
				}
				readyReceiveDataEvent.Set();
			}
			catch (SocketException ex)
			{
				UnityEngine.Debug.LogErrorFormat("[OVRNetworkTcpClient] OnReadDataCallback: socket error: {0}", ex.Message);
				Disconnect();
			}
		}
	}

	public const int MaxBufferLength = 65536;

	public const int MaxPayloadLength = 65524;

	public const uint FrameHeaderMagicIdentifier = 1384359787u;
}
internal static class OVRObjectPool
{
	public interface IPoolObject
	{
		void OnGet();

		void OnReturn();
	}

	private static class Storage<T> where T : class, new()
	{
		private static readonly HashSet<T> s_hashSet = new HashSet<T>();

		public static readonly Action Clear = delegate
		{
			s_hashSet.Clear();
		};

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static bool Remove(T item)
		{
			return s_hashSet.Remove(item);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static bool Add(T item)
		{
			return s_hashSet.Add(item);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static T GetOrCreate()
		{
			using HashSet<T>.Enumerator enumerator = s_hashSet.GetEnumerator();
			if (enumerator.MoveNext())
			{
				T current = enumerator.Current;
				Remove(current);
				return current;
			}
			return new T();
		}
	}

	public struct ListScope<T> : IDisposable
	{
		private List<T> _list;

		public ListScope(out List<T> list)
		{
			_list = (list = List<T>());
		}

		public ListScope(IEnumerable<T> source, out List<T> list)
		{
			_list = (list = List(source));
		}

		public void Dispose()
		{
			Return(_list);
		}
	}

	public struct TaskScope<T>(out List<OVRTask<T>> tasks, out List<T> results) : IDisposable
	{
		private ListScope<OVRTask<T>> _tasks = new ListScope<OVRTask<T>>(out tasks);

		private ListScope<T> _results = new ListScope<T>(out results);

		public void Dispose()
		{
			_tasks.Dispose();
			_results.Dispose();
		}
	}

	public readonly struct DictionaryScope<TKey, TValue>(out Dictionary<TKey, TValue> dictionary) : IDisposable
	{
		private readonly Dictionary<TKey, TValue> _dictionary = (dictionary = Dictionary<TKey, TValue>());

		public void Dispose()
		{
			Return(_dictionary);
		}
	}

	public readonly struct HashSetScope<T>(out HashSet<T> set) : IDisposable
	{
		private readonly HashSet<T> _set = (set = HashSet<T>());

		public void Dispose()
		{
			Return(_set);
		}
	}

	public readonly struct StackScope<T>(out Stack<T> stack) : IDisposable
	{
		private readonly Stack<T> _stack = (stack = Stack<T>());

		public void Dispose()
		{
			Return(_stack);
		}
	}

	public readonly struct QueueScope<T>(out Queue<T> queue) : IDisposable
	{
		private readonly Queue<T> _queue = (queue = Queue<T>());

		public void Dispose()
		{
			Return(_queue);
		}
	}

	public readonly struct ItemScope<T>(out T item) : IDisposable where T : class, new()
	{
		private readonly T _item = (item = Get<T>());

		public void Dispose()
		{
			Return(_item);
		}
	}

	public static T Get<T>() where T : class, new()
	{
		T orCreate = Storage<T>.GetOrCreate();
		if (orCreate is IList list)
		{
			list.Clear();
		}
		else if (orCreate is IDictionary dictionary)
		{
			dictionary.Clear();
		}
		(orCreate as IPoolObject)?.OnGet();
		return orCreate;
	}

	public static List<T> List<T>()
	{
		return Get<List<T>>();
	}

	public static List<T> List<T>(IEnumerable<T> source)
	{
		List<T> list = Get<List<T>>();
		foreach (T item in source.ToNonAlloc())
		{
			list.Add(item);
		}
		return list;
	}

	public static Dictionary<TKey, TValue> Dictionary<TKey, TValue>()
	{
		return Get<Dictionary<TKey, TValue>>();
	}

	public static HashSet<T> HashSet<T>()
	{
		HashSet<T> hashSet = Get<HashSet<T>>();
		hashSet.Clear();
		return hashSet;
	}

	public static Stack<T> Stack<T>()
	{
		Stack<T> stack = Get<Stack<T>>();
		stack.Clear();
		return stack;
	}

	public static Queue<T> Queue<T>()
	{
		Queue<T> queue = Get<Queue<T>>();
		queue.Clear();
		return queue;
	}

	public static void Return<T>(T obj) where T : class, new()
	{
		if (obj == null)
		{
			return;
		}
		if (!(obj is IList list))
		{
			if (!(obj is IDictionary dictionary))
			{
				if (obj is IPoolObject poolObject)
				{
					poolObject.OnReturn();
				}
			}
			else
			{
				dictionary.Clear();
			}
		}
		else
		{
			list.Clear();
		}
		Storage<T>.Add(obj);
	}

	public static void Return<T>(HashSet<T> set)
	{
		set?.Clear();
		OVRObjectPool.Return<HashSet<T>>(set);
	}

	public static void Return<T>(Stack<T> stack)
	{
		stack?.Clear();
		OVRObjectPool.Return<Stack<T>>(stack);
	}

	public static void Return<T>(Queue<T> queue)
	{
		queue?.Clear();
		OVRObjectPool.Return<Queue<T>>(queue);
	}
}
[RequireComponent(typeof(CharacterController))]
[HelpURL("https://developer.oculus.com/documentation/unity/unity-sf-distancegrab/")]
public class OVRPlayerController : MonoBehaviour
{
	public float Acceleration = 0.1f;

	public float Damping = 0.3f;

	public float BackAndSideDampen = 0.5f;

	public float JumpForce = 0.3f;

	public float RotationAmount = 1.5f;

	public float RotationRatchet = 45f;

	[Tooltip("The player will rotate in fixed steps if Snap Rotation is enabled.")]
	public bool SnapRotation = true;

	[Obsolete]
	[Tooltip("[Deprecated] When enabled, snap rotation will happen about the center of the guardian rather than the center of the player/camera viewpoint. This (legacy) option should be left off except for edge cases that require extreme behavioral backwards compatibility.")]
	public bool RotateAroundGuardianCenter;

	[Tooltip("Sets the number of discrete speeds that will be used in continuous motion. If 0, motion speed is not discretized.")]
	public int FixedSpeedSteps;

	public bool HmdResetsY = true;

	public bool HmdRotatesY = true;

	public float GravityModifier = 0.379f;

	public bool useProfileData = true;

	[NonSerialized]
	public float CameraHeight;

	[NonSerialized]
	public bool Teleported;

	public bool EnableLinearMovement = true;

	public bool EnableRotation = true;

	public bool RotationEitherThumbstick;

	protected CharacterController Controller;

	protected OVRCameraRig CameraRig;

	private float MoveScale = 1f;

	private Vector3 MoveThrottle = Vector3.zero;

	private float FallSpeed;

	private OVRPose? InitialPose;

	private float MoveScaleMultiplier = 1f;

	private float RotationScaleMultiplier = 1f;

	private bool SkipMouseRotation = true;

	private bool HaltUpdateMovement;

	private bool prevHatLeft;

	private bool prevHatRight;

	private float SimulationRate = 60f;

	private float buttonRotation;

	private bool ReadyToSnapTurn;

	private bool playerControllerEnabled;

	private InputAction moveForwardAction;

	private InputAction moveLeftAction;

	private InputAction moveRightAction;

	private InputAction moveBackAction;

	private InputAction runAction;

	public float InitialYRotation { get; private set; }

	public event Action<Transform> TransformUpdated;

	public event Action CameraUpdated;

	public event Action PreCharacterMove;

	private void Start()
	{
		Vector3 localPosition = CameraRig.transform.localPosition;
		localPosition.z = OVRManager.profile.eyeDepth;
		CameraRig.transform.localPosition = localPosition;
		moveForwardAction = new InputAction(null, InputActionType.Value, "<Keyboard>/w");
		moveForwardAction.AddBinding("<Keyboard>/upArrow");
		moveLeftAction = new InputAction(null, InputActionType.Value, "<Keyboard>/a");
		moveLeftAction.AddBinding("<Keyboard>/leftArrow");
		moveRightAction = new InputAction(null, InputActionType.Value, "<Keyboard>/d");
		moveRightAction.AddBinding("<Keyboard>/rightArrow");
		moveBackAction = new InputAction(null, InputActionType.Value, "<Keyboard>/s");
		moveBackAction.AddBinding("<Keyboard>/downArrow");
		runAction = new InputAction(null, InputActionType.Value, "<Keyboard>/leftShift");
		runAction.AddBinding("<Keyboard>/rightShift");
		moveForwardAction.Enable();
		moveLeftAction.Enable();
		moveRightAction.Enable();
		moveBackAction.Enable();
		runAction.Enable();
	}

	private void Awake()
	{
		Controller = base.gameObject.GetComponent<CharacterController>();
		if (Controller == null)
		{
			UnityEngine.Debug.LogWarning("OVRPlayerController: No CharacterController attached.");
		}
		OVRCameraRig[] componentsInChildren = base.gameObject.GetComponentsInChildren<OVRCameraRig>();
		if (componentsInChildren.Length == 0)
		{
			UnityEngine.Debug.LogWarning("OVRPlayerController: No OVRCameraRig attached.");
		}
		else if (componentsInChildren.Length > 1)
		{
			UnityEngine.Debug.LogWarning("OVRPlayerController: More then 1 OVRCameraRig attached.");
		}
		else
		{
			CameraRig = componentsInChildren[0];
		}
		InitialYRotation = base.transform.rotation.eulerAngles.y;
	}

	private void OnEnable()
	{
	}

	private void OnDisable()
	{
		if (playerControllerEnabled)
		{
			OVRManager.display.RecenteredPose -= ResetOrientation;
			if (CameraRig != null)
			{
				CameraRig.UpdatedAnchors -= UpdateTransform;
			}
			playerControllerEnabled = false;
		}
		moveForwardAction.Disable();
		moveLeftAction.Disable();
		moveRightAction.Disable();
		moveBackAction.Disable();
		runAction.Disable();
	}

	private void Update()
	{
		if (!playerControllerEnabled && OVRManager.OVRManagerinitialized)
		{
			OVRManager.display.RecenteredPose += ResetOrientation;
			if (CameraRig != null)
			{
				CameraRig.UpdatedAnchors += UpdateTransform;
			}
			playerControllerEnabled = true;
		}
	}

	protected virtual void UpdateController()
	{
		if (useProfileData)
		{
			if (!InitialPose.HasValue)
			{
				InitialPose = new OVRPose
				{
					position = CameraRig.transform.localPosition,
					orientation = CameraRig.transform.localRotation
				};
			}
			Vector3 localPosition = CameraRig.transform.localPosition;
			if (OVRManager.instance.trackingOriginType == OVRManager.TrackingOrigin.EyeLevel)
			{
				localPosition.y = OVRManager.profile.eyeHeight - 0.5f * Controller.height + Controller.center.y;
			}
			else if (OVRManager.instance.trackingOriginType == OVRManager.TrackingOrigin.FloorLevel)
			{
				localPosition.y = 0f - 0.5f * Controller.height + Controller.center.y;
			}
			CameraRig.transform.localPosition = localPosition;
		}
		else if (InitialPose.HasValue)
		{
			CameraRig.transform.localPosition = InitialPose.Value.position;
			CameraRig.transform.localRotation = InitialPose.Value.orientation;
			InitialPose = null;
		}
		CameraHeight = CameraRig.centerEyeAnchor.localPosition.y;
		if (this.CameraUpdated != null)
		{
			this.CameraUpdated();
		}
		UpdateMovement();
		Vector3 zero = Vector3.zero;
		float num = 1f + Damping * SimulationRate * Time.deltaTime;
		MoveThrottle.x /= num;
		MoveThrottle.y = ((MoveThrottle.y > 0f) ? (MoveThrottle.y / num) : MoveThrottle.y);
		MoveThrottle.z /= num;
		zero += MoveThrottle * SimulationRate * Time.deltaTime;
		if (Controller.isGrounded && FallSpeed <= 0f)
		{
			FallSpeed = Physics.gravity.y * (GravityModifier * 0.002f);
		}
		else
		{
			FallSpeed += Physics.gravity.y * (GravityModifier * 0.002f) * SimulationRate * Time.deltaTime;
		}
		zero.y += FallSpeed * SimulationRate * Time.deltaTime;
		if (Controller.isGrounded && MoveThrottle.y <= base.transform.lossyScale.y * 0.001f)
		{
			float num2 = Mathf.Max(Controller.stepOffset, new Vector3(zero.x, 0f, zero.z).magnitude);
			zero -= num2 * Vector3.up;
		}
		if (this.PreCharacterMove != null)
		{
			this.PreCharacterMove();
			Teleported = false;
		}
		Vector3 vector = Vector3.Scale(Controller.transform.localPosition + zero, new Vector3(1f, 0f, 1f));
		Controller.Move(zero);
		Vector3 vector2 = Vector3.Scale(Controller.transform.localPosition, new Vector3(1f, 0f, 1f));
		if (vector != vector2)
		{
			MoveThrottle += (vector2 - vector) / (SimulationRate * Time.deltaTime);
		}
	}

	public virtual void UpdateMovement()
	{
		if (HaltUpdateMovement)
		{
			return;
		}
		if (EnableLinearMovement)
		{
			bool flag = false;
			bool flag2 = false;
			bool flag3 = false;
			bool flag4 = false;
			flag = moveForwardAction.phase == InputActionPhase.Started;
			flag2 = moveLeftAction.phase == InputActionPhase.Started;
			flag3 = moveRightAction.phase == InputActionPhase.Started;
			flag4 = moveBackAction.phase == InputActionPhase.Started;
			bool flag5 = false;
			if (OVRInput.Get(OVRInput.Button.DpadUp))
			{
				flag = true;
				flag5 = true;
			}
			if (OVRInput.Get(OVRInput.Button.DpadDown))
			{
				flag4 = true;
				flag5 = true;
			}
			MoveScale = 1f;
			if ((flag && flag2) || (flag && flag3) || (flag4 && flag2) || (flag4 && flag3))
			{
				MoveScale = 0.70710677f;
			}
			if (!Controller.isGrounded)
			{
				MoveScale = 0f;
			}
			MoveScale *= SimulationRate * Time.deltaTime;
			float num = Acceleration * 0.1f * MoveScale * MoveScaleMultiplier;
			if (flag5 || runAction.phase == InputActionPhase.Started)
			{
				num *= 2f;
			}
			Vector3 eulerAngles = base.transform.rotation.eulerAngles;
			eulerAngles.z = (eulerAngles.x = 0f);
			Quaternion quaternion = Quaternion.Euler(eulerAngles);
			if (flag)
			{
				MoveThrottle += quaternion * (base.transform.lossyScale.z * num * Vector3.forward);
			}
			if (flag4)
			{
				MoveThrottle += quaternion * (base.transform.lossyScale.z * num * BackAndSideDampen * Vector3.back);
			}
			if (flag2)
			{
				MoveThrottle += quaternion * (base.transform.lossyScale.x * num * BackAndSideDampen * Vector3.left);
			}
			if (flag3)
			{
				MoveThrottle += quaternion * (base.transform.lossyScale.x * num * BackAndSideDampen * Vector3.right);
			}
			num = Acceleration * 0.1f * MoveScale * MoveScaleMultiplier;
			num *= 1f + OVRInput.Get(OVRInput.Axis1D.PrimaryIndexTrigger);
			Vector2 vector = OVRInput.Get(OVRInput.Axis2D.PrimaryThumbstick);
			if (FixedSpeedSteps > 0)
			{
				vector.y = Mathf.Round(vector.y * (float)FixedSpeedSteps) / (float)FixedSpeedSteps;
				vector.x = Mathf.Round(vector.x * (float)FixedSpeedSteps) / (float)FixedSpeedSteps;
			}
			if (vector.y > 0f)
			{
				MoveThrottle += quaternion * (vector.y * base.transform.lossyScale.z * num * Vector3.forward);
			}
			if (vector.y < 0f)
			{
				MoveThrottle += quaternion * (Mathf.Abs(vector.y) * base.transform.lossyScale.z * num * BackAndSideDampen * Vector3.back);
			}
			if (vector.x < 0f)
			{
				MoveThrottle += quaternion * (Mathf.Abs(vector.x) * base.transform.lossyScale.x * num * BackAndSideDampen * Vector3.left);
			}
			if (vector.x > 0f)
			{
				MoveThrottle += quaternion * (vector.x * base.transform.lossyScale.x * num * BackAndSideDampen * Vector3.right);
			}
		}
		if (!EnableRotation)
		{
			return;
		}
		Vector3 euler = (RotateAroundGuardianCenter ? base.transform.rotation.eulerAngles : Vector3.zero);
		float num2 = SimulationRate * Time.deltaTime * RotationAmount * RotationScaleMultiplier;
		bool flag6 = OVRInput.Get(OVRInput.Button.PrimaryShoulder);
		if (flag6 && !prevHatLeft)
		{
			euler.y -= RotationRatchet;
		}
		prevHatLeft = flag6;
		bool flag7 = OVRInput.Get(OVRInput.Button.SecondaryShoulder);
		if (flag7 && !prevHatRight)
		{
			euler.y += RotationRatchet;
		}
		prevHatRight = flag7;
		euler.y += buttonRotation;
		buttonRotation = 0f;
		if (!SkipMouseRotation)
		{
			euler.y += Input.GetAxis("Mouse X") * num2 * 3.25f;
		}
		if (SnapRotation)
		{
			if (OVRInput.Get(OVRInput.Button.SecondaryThumbstickLeft) || (RotationEitherThumbstick && OVRInput.Get(OVRInput.Button.PrimaryThumbstickLeft)))
			{
				if (ReadyToSnapTurn)
				{
					euler.y -= RotationRatchet;
					ReadyToSnapTurn = false;
				}
			}
			else if (OVRInput.Get(OVRInput.Button.SecondaryThumbstickRight) || (RotationEitherThumbstick && OVRInput.Get(OVRInput.Button.PrimaryThumbstickRight)))
			{
				if (ReadyToSnapTurn)
				{
					euler.y += RotationRatchet;
					ReadyToSnapTurn = false;
				}
			}
			else
			{
				ReadyToSnapTurn = true;
			}
		}
		else
		{
			Vector2 vector2 = OVRInput.Get(OVRInput.Axis2D.SecondaryThumbstick);
			if (RotationEitherThumbstick)
			{
				Vector2 vector3 = OVRInput.Get(OVRInput.Axis2D.PrimaryThumbstick);
				if (vector2.sqrMagnitude < vector3.sqrMagnitude)
				{
					vector2 = vector3;
				}
			}
			euler.y += vector2.x * num2;
		}
		if (RotateAroundGuardianCenter)
		{
			base.transform.rotation = Quaternion.Euler(euler);
		}
		else
		{
			base.transform.RotateAround(base.transform.position, Vector3.up, euler.y);
		}
	}

	public void UpdateTransform(OVRCameraRig rig)
	{
		Transform trackingSpace = CameraRig.trackingSpace;
		Transform centerEyeAnchor = CameraRig.centerEyeAnchor;
		if (HmdRotatesY && !Teleported)
		{
			Vector3 position = trackingSpace.position;
			Quaternion rotation = trackingSpace.rotation;
			base.transform.rotation = Quaternion.Euler(0f, centerEyeAnchor.rotation.eulerAngles.y, 0f);
			trackingSpace.position = position;
			trackingSpace.rotation = rotation;
		}
		UpdateController();
		if (this.TransformUpdated != null)
		{
			this.TransformUpdated(trackingSpace);
		}
	}

	public bool Jump()
	{
		if (!Controller.isGrounded)
		{
			return false;
		}
		MoveThrottle += new Vector3(0f, base.transform.lossyScale.y * JumpForce, 0f);
		return true;
	}

	public void Stop()
	{
		Controller.Move(Vector3.zero);
		MoveThrottle = Vector3.zero;
		FallSpeed = 0f;
	}

	public void GetMoveScaleMultiplier(ref float moveScaleMultiplier)
	{
		moveScaleMultiplier = MoveScaleMultiplier;
	}

	public void SetMoveScaleMultiplier(float moveScaleMultiplier)
	{
		MoveScaleMultiplier = moveScaleMultiplier;
	}

	public void GetRotationScaleMultiplier(ref float rotationScaleMultiplier)
	{
		rotationScaleMultiplier = RotationScaleMultiplier;
	}

	public void SetRotationScaleMultiplier(float rotationScaleMultiplier)
	{
		RotationScaleMultiplier = rotationScaleMultiplier;
	}

	public void GetSkipMouseRotation(ref bool skipMouseRotation)
	{
		skipMouseRotation = SkipMouseRotation;
	}

	public void SetSkipMouseRotation(bool skipMouseRotation)
	{
		SkipMouseRotation = skipMouseRotation;
	}

	public void GetHaltUpdateMovement(ref bool haltUpdateMovement)
	{
		haltUpdateMovement = HaltUpdateMovement;
	}

	public void SetHaltUpdateMovement(bool haltUpdateMovement)
	{
		HaltUpdateMovement = haltUpdateMovement;
	}

	public void ResetOrientation()
	{
		if (HmdResetsY && !HmdRotatesY)
		{
			Vector3 eulerAngles = base.transform.rotation.eulerAngles;
			eulerAngles.y = InitialYRotation;
			base.transform.rotation = Quaternion.Euler(eulerAngles);
		}
	}
}
